// Bank-backed, fact-checked, 16 items each. Consumed by expansion.js via fromBank().
module.exports = {"s.k.plants":[{"p":"🌱 What do plants need from the sky to grow?","a":"Sunlight","w":["Candy","Toys","Music"],"h":"It is bright and warm.","e":"Plants use sunlight to make their food and grow."},{"p":"💧 A plant looks thirsty. What should you give it?","a":"Water","w":["Milk","Juice","Soda"],"h":"It falls from the clouds as rain.","e":"Plants drink water to stay healthy and grow."},{"p":"🌻 Which part of a plant grows down under the ground?","a":"Roots","w":["Flower","Leaf","Stem"],"h":"You cannot see it easily.","e":"Roots grow down in the soil and drink up water."},{"p":"🍃 Which part of a plant is green and flat?","a":"Leaf","w":["Root","Seed","Flower"],"h":"It grows out from the stem.","e":"Leaves are green and help the plant catch sunlight."},{"p":"🌸 Which part of a plant is pretty and can smell nice?","a":"Flower","w":["Root","Stem","Leaf"],"h":"Bees like to visit it.","e":"Flowers help the plant make new seeds."},{"p":"🌰 What do we put in the dirt to grow a new plant?","a":"A seed","w":["A rock","A coin","A toy"],"h":"It is small.","e":"A seed grows into a new plant when it gets water and sun."},{"p":"🪴 Plants grow in the brown ground. What is it called?","a":"Soil","w":["A sand toy","Paper","Glass"],"h":"It is the dirt in a garden.","e":"Soil holds the plant and gives it water and food."},{"p":"🌿 What part holds the plant up like its body?","a":"The stem","w":["The flower","The seed","The root"],"h":"It is in the middle.","e":"The stem holds the plant up and carries water to the leaves."},{"p":"☀️ Where is the best spot to grow a little plant?","a":"By a sunny window","w":["In a dark closet","Under the bed","In the freezer"],"h":"Plants love light.","e":"Plants grow best where they can get lots of sunlight."},{"p":"🌧️ What weather gives plants a drink of water?","a":"Rain","w":["A snow storm","Strong wind","Foggy air"],"h":"It falls from clouds.","e":"Rain gives plants the water they need to grow."},{"p":"🌱 A plant is turning brown and dry. What does it need?","a":"Some water","w":["A nap","A hug","A hat"],"h":"It looks very thirsty.","e":"A dry plant needs water to feel healthy again."},{"p":"🌳 Do plants need air to live?","a":"Yes, they need air","w":["No, never","Only at night","Only toys"],"h":"We breathe air too.","e":"Plants use air to help make their food."},{"p":"🥕 Which food is a plant part that grows under the ground?","a":"A carrot","w":["An apple","A banana","A grape"],"h":"It is long and orange.","e":"A carrot is a root that grows down in the soil."},{"p":"🌼 What two things do seeds need to start growing?","a":"Water and sun","w":["Ice and dark","Toys and candy","Rocks and glass"],"h":"Two things plants love.","e":"Seeds need water and sunlight to sprout into plants."},{"p":"🍎 Where do apples grow?","a":"On a tree","w":["Under the sea","In the sky","On a car"],"h":"A tree is a big plant.","e":"Apples grow on apple trees, which are big plants."},{"p":"🌱 A tiny new plant just pushed out of the seed. What is it?","a":"A sprout","w":["A rock","A cloud","A bug"],"h":"It is a baby plant.","e":"A sprout is a young plant that just started to grow."}],"s.k.skyday":[{"p":"☀️ What do we see in the sky in the daytime?","a":"The sun","w":["The moon","The stars","A lamp"],"h":"It is bright and warm.","e":"The sun shines in the sky during the day."},{"p":"🌙 What do we often see in the sky at night?","a":"The moon","w":["The sun","A rainbow","A kite"],"h":"It comes out when it is dark.","e":"The moon comes out in the night sky."},{"p":"⭐ What are the tiny twinkly lights we see at night?","a":"Stars","w":["Bugs","Snowflakes","Balloons"],"h":"They are very far away.","e":"Stars are far-away lights we see in the night sky."},{"p":"🌞 What two things does the sun give us?","a":"Light and heat","w":["Rain and snow","Toys and candy","Music and games"],"h":"It is bright and warm.","e":"The sun gives us light to see and heat to keep us warm."},{"p":"🌆 When does the sky get dark outside?","a":"At night","w":["In the morning","At noon","At lunchtime"],"h":"It is time to sleep.","e":"The sky gets dark at night when the sun goes down."},{"p":"🌅 When does the sun come up?","a":"In the morning","w":["At night","At midnight","At bedtime"],"h":"It is when we wake up.","e":"The sun comes up in the morning to start the day."},{"p":"🌤️ Why is it warmer outside in the daytime?","a":"The sun is out","w":["The moon is out","The stars are out","It is nighttime"],"h":"Think about the bright sky.","e":"Daytime is warmer because the sun shines on us."},{"p":"🌇 Why can we not see the sun at night?","a":"Our side of Earth turns away","w":["The sun breaks apart","The sun turns green","The sun gets bigger"],"h":"Earth slowly spins.","e":"At night our side of Earth turns away, so we cannot see the sun."},{"p":"☀️ The sun moves across the sky. Where is it at lunchtime?","a":"High in the sky","w":["Under the ground","Behind you always","In the ocean"],"h":"It is the middle of the day.","e":"At midday the sun is high up in the sky."},{"p":"🌟 Why does the sun look brighter to us than a far-away star?","a":"The sun is much closer","w":["The star is closer","The moon blocks it","Stars are made of ice"],"h":"Closer things look bigger.","e":"The sun looks brightest because it is much closer to us than other stars."},{"p":"🌙 You see the moon in the sky. Is it day or night?","a":"Night","w":["Day","Morning","Noon"],"h":"The sky is dark then.","e":"We usually see the moon when it is night."},{"p":"😴 When do most people sleep?","a":"At night","w":["At noon","In the morning","At sunrise"],"h":"When the sky is dark.","e":"Most people sleep at night when it is dark outside."},{"p":"🌙 Does the moon make its own light like the sun?","a":"No, it does not","w":["Yes, it is on fire","Yes, it has a lamp","Yes, it is the sun"],"h":"The sun shines on it.","e":"The moon does not make light; sunlight bounces off it."},{"p":"☁️ What can hide the sun on a gray day?","a":"Clouds","w":["The moon at night","Green grass","A big book"],"h":"They are fluffy and white.","e":"Clouds can cover the sun and make the day look gray."},{"p":"🌅 What do we call the time when the sun comes up?","a":"Sunrise","w":["Sunset","Midnight","Bedtime"],"h":"It is early in the day.","e":"Sunrise is when the sun comes up in the morning."},{"p":"🌇 What do we call the time when the sun goes down?","a":"Sunset","w":["Sunrise","Noon","Morning"],"h":"It is the end of the day.","e":"Sunset is when the sun goes down in the evening."}],"s.1.lightsound":[{"p":"💡 Which of these makes its own light?","a":"The sun","w":["A mirror","A wall","A book"],"h":"It shines in the sky.","e":"The sun is a light source because it makes its own light."},{"p":"🔦 Which of these is a light source you turn on?","a":"A flashlight","w":["A spoon","A rock","A pillow"],"h":"You use it in the dark.","e":"A flashlight makes light so we can see in the dark."},{"p":"🌑 What do you need to be able to see things?","a":"Light","w":["Noise","Wind","Water"],"h":"It is hard to see in the dark.","e":"We need light to see the objects around us."},{"p":"🐕 What has to happen for a shadow to appear?","a":"An object blocks the light","w":["A loud sound is made","Water gets spilled","A cold wind blows"],"h":"Something gets in the way of light.","e":"A shadow forms when an object blocks the light."},{"p":"🌳 When is your shadow the longest outside?","a":"When the sun is low","w":["When the sun is high","At midnight","When it is raining"],"h":"Think early morning or evening.","e":"Shadows are longest when the sun is low in the sky."},{"p":"👂 What body part do we use to hear sounds?","a":"Our ears","w":["Our eyes","Our nose","Our hands"],"h":"There is one on each side.","e":"We hear sounds with our ears."},{"p":"🥁 What does a drum do to make a sound when you hit it?","a":"It vibrates","w":["It gets wet","It lights up","It gets cold"],"h":"It shakes very fast.","e":"A drum makes sound by vibrating, or shaking quickly."},{"p":"🔊 Sounds are made by things that do what?","a":"Vibrate","w":["Glow","Freeze","Melt"],"h":"They wiggle back and forth fast.","e":"All sounds come from something that vibrates."},{"p":"🎸 You pluck a guitar string and hear a sound. Why?","a":"The string vibrates","w":["The string gets hot","The string glows","The string melts"],"h":"Watch the string wiggle.","e":"The plucked string vibrates, and that makes the sound."},{"p":"📢 Which of these is a loud sound?","a":"A fire truck siren","w":["A soft whisper","A quiet hum","A page turning"],"h":"You might cover your ears.","e":"A siren is a loud sound, while a whisper is soft."},{"p":"🤫 Which of these is a soft, quiet sound?","a":"A whisper","w":["A thunderclap","A honking horn","A loud drum"],"h":"It is very quiet.","e":"A whisper is a soft, quiet sound."},{"p":"🪞 What does a mirror do with light?","a":"It bounces light back","w":["It eats the light","It makes new light","It hides the light"],"h":"You can see yourself in it.","e":"A mirror reflects, or bounces, light back to your eyes."},{"p":"🌙 Does the moon make its own light?","a":"No, it reflects the sun","w":["Yes, it burns","Yes, it has a lamp","Yes, it glows on its own"],"h":"Sunlight shines on it.","e":"The moon does not make light; it reflects light from the sun."},{"p":"🚪 Can light pass through a solid wooden door?","a":"No, it is blocked","w":["Yes, very easily","Only at night","Only if it is loud"],"h":"Think about a shadow.","e":"Light cannot pass through solid wood, so it makes a shadow."},{"p":"🪟 Can light pass through a clear glass window?","a":"Yes, it passes through","w":["No, it never can","Only sound can","Only at night"],"h":"You can see outside.","e":"Light passes through clear glass, so we can see through a window."},{"p":"🔔 A ringing bell goes quiet when you grab it. Why does the sound stop?","a":"It stops vibrating","w":["It gets darker","It gets warmer","It runs out of air"],"h":"Your hand stops the shaking.","e":"Holding the bell stops it from vibrating, so the sound stops."}],"s.1.livingnon":[{"p":"🐶 Which of these is a living thing?","a":"A dog","w":["A rock","A chair","A spoon"],"h":"It can eat and grow.","e":"A dog is living because it grows, eats, and breathes."},{"p":"🪨 Which of these is a nonliving thing?","a":"A rock","w":["A tree","A cat","A bird"],"h":"It cannot grow or eat.","e":"A rock is nonliving because it does not grow, eat, or breathe."},{"p":"🌷 Is a flower living or nonliving?","a":"Living","w":["Nonliving","A kind of rock","A kind of toy"],"h":"It grows and needs water.","e":"A flower is living because it grows and needs water and sunlight."},{"p":"🧸 Is a teddy bear living or nonliving?","a":"Nonliving","w":["Living","It breathes air","It eats food"],"h":"It cannot grow on its own.","e":"A teddy bear is nonliving because it does not grow, eat, or breathe."},{"p":"🍎 What do all living things need to stay alive?","a":"Food and water","w":["Toys and games","Paint and paper","Money and cars"],"h":"You need them too.","e":"Living things need food and water to survive."},{"p":"🌬️ What do animals need to breathe?","a":"Air","w":["Sand","Glass","Plastic"],"h":"We take it in with each breath.","e":"Animals need air to breathe and stay alive."},{"p":"🐣 Living things can make young. What can a hen do?","a":"Lay eggs","w":["Melt in the sun","Turn into a rock","Run out of battery"],"h":"Baby chicks come from them.","e":"A hen is living, so it can reproduce by laying eggs."},{"p":"📈 What does it mean that living things grow?","a":"They get bigger over time","w":["They stay the exact same","They turn into stone","They need new batteries"],"h":"Think of a puppy becoming a dog.","e":"Living things grow, meaning they change and get bigger over time."},{"p":"🚗 A car can move and needs gas. Is a car living?","a":"No, it is nonliving","w":["Yes, it is living","Yes, it eats gas","Yes, it grows up"],"h":"It cannot grow or make babies.","e":"A car is nonliving because it cannot grow, eat, or reproduce on its own."},{"p":"🌵 A cactus barely moves at all. Is it living?","a":"Yes, it is living","w":["No, it is a rock","No, it never grows","No, it is a toy"],"h":"It grows and needs water.","e":"A cactus is living because it grows and needs water and sunlight."},{"p":"🐠 A fish swims away when you reach for it. This shows living things can do what?","a":"Respond to the world around them","w":["Turn themselves off","Melt in the water","Freeze in place forever"],"h":"They sense and react.","e":"Living things respond to their surroundings, like swimming away from danger."},{"p":"🌳 Is a tall oak tree living or nonliving?","a":"Living","w":["Nonliving","Just a big rock","Made of plastic"],"h":"It grows leaves and needs sun.","e":"A tree is living because it grows, needs water, and makes seeds."},{"p":"💧 Is the water in a puddle living or nonliving?","a":"Nonliving","w":["Living","It breathes air","It has babies"],"h":"It cannot grow or eat.","e":"Water is nonliving because it does not grow, eat, or breathe."},{"p":"🏠 A bird builds a nest. What do living things need to stay safe?","a":"A place to live","w":["A cell phone","A television","A bicycle"],"h":"It can be called a home.","e":"Living things need a safe place, or habitat, to live."},{"p":"🐛 Which of these is a living thing?","a":"A caterpillar","w":["A pebble","A button","A crayon"],"h":"It eats leaves and grows.","e":"A caterpillar is living because it eats, grows, and changes."},{"p":"🌿 A real plant and a plastic plant look alike. Which one is living?","a":"The real plant","w":["The plastic plant","Both of them","Neither one"],"h":"One grows and needs water.","e":"The real plant is living because it grows and needs water, but the plastic one does not."}],"s.2.matter":[{"p":"🧊 What state of matter is an ice cube?","a":"A solid","w":["A liquid","A gas","Not matter"],"h":"It is hard and keeps its shape.","e":"An ice cube is a solid because it is firm and holds its own shape."},{"p":"💧 What state of matter is the water you drink?","a":"A liquid","w":["A solid","A gas","Not matter"],"h":"It pours and fills a cup.","e":"Water is a liquid because it flows and takes the shape of its container."},{"p":"🎈 What is inside a balloon after you blow it up?","a":"A gas","w":["A solid","A liquid","Nothing at all"],"h":"You cannot see it, but it fills the space.","e":"The air inside a balloon is a gas, which spreads to fill its container."},{"p":"🧱 Which of these is true about a solid?","a":"It keeps its own shape","w":["It always pours out","It floats away as a gas","It has no weight"],"h":"Think of a brick or a block.","e":"Solids keep their shape and do not flow like liquids or gases."},{"p":"🥤 Why does juice take the shape of the cup it is poured into?","a":"Because it is a liquid","w":["Because it is a solid","Because it is frozen","Because it is a gas"],"h":"Liquids flow to the bottom.","e":"Liquids take the shape of their container because they can flow."},{"p":"🔥 What happens to ice when it gets warm?","a":"It melts into water","w":["It turns into a rock","It becomes a gas at once","It stays frozen solid"],"h":"A solid changes to a liquid.","e":"When ice is heated it melts, changing from a solid to a liquid."},{"p":"❄️ What happens to water left in the freezer?","a":"It freezes into ice","w":["It boils away fast","It turns into a gas","It disappears for good"],"h":"A liquid changes to a solid.","e":"When water gets very cold it freezes and becomes solid ice."},{"p":"♨️ What do we call the gas that rises off boiling water?","a":"Steam","w":["Smoke","Melted ice","Cold liquid"],"h":"You see it above a hot pot.","e":"Boiling water turns into steam, which is water in gas form."},{"p":"📦 Which state of matter is easiest to squeeze into a smaller space?","a":"A gas","w":["A solid","A liquid","An ice cube"],"h":"Think about squishing air.","e":"A gas can be squeezed into a smaller space because its tiny bits are spread far apart."},{"p":"🧊 Ice, a puddle, and steam are all water. Which one is the solid?","a":"The ice","w":["The puddle","The steam","None of them"],"h":"Solids are hard.","e":"The ice is the solid form of water because it is hard and keeps its shape."},{"p":"🪵 Which of these is a solid?","a":"A wooden block","w":["A glass of milk","The air in a room","A puddle of rain"],"h":"It is hard and keeps its shape.","e":"A wooden block is a solid because it stays the same shape."},{"p":"🌫️ Can you usually see the air around you?","a":"No, most gases are invisible","w":["Yes, it is bright red","Yes, it looks like a rock","Yes, it is hard to touch"],"h":"You can feel wind but not see air.","e":"Most gases, like the air around us, cannot be seen."},{"p":"🍫 A chocolate bar melts in your warm hand. What did it become?","a":"A liquid","w":["A gas","A harder solid","Plain air"],"h":"It went from hard to runny.","e":"The melting chocolate changed from a solid into a liquid."},{"p":"🌧️ A wet sidewalk dries in the sun. Where did the water go?","a":"It became a gas in the air","w":["It became a solid","It sank into a rock","It vanished forever"],"h":"The sun made it evaporate.","e":"The water evaporated, changing from a liquid into a gas in the air."},{"p":"⚖️ Do solids, liquids, and gases all take up space and have weight?","a":"Yes, they are all matter","w":["No, only solids do","No, gas has none","No, only liquids do"],"h":"Matter takes up space.","e":"Solids, liquids, and gases are all matter, so they all take up space and have weight."},{"p":"🥛 Which state of matter can be poured but keeps the same amount?","a":"A liquid","w":["A solid","A gas","A rock"],"h":"Think of pouring milk.","e":"A liquid flows and can be poured while keeping the same amount."}],"s.2.lifecycle":[{"p":"🌱 What does most of a plant grow from?","a":"A seed","w":["A rock","A pile of leaves","A drop of rain"],"h":"You plant it in soil.","e":"Most plants begin their life cycle by growing from a seed."},{"p":"🐔 What does a baby chick hatch from?","a":"An egg","w":["A seed","A cocoon","A flower"],"h":"The hen lays it first.","e":"A baby chick hatches from an egg laid by a hen."},{"p":"🐸 What is a baby frog called before it grows legs?","a":"A tadpole","w":["A caterpillar","A chick","A puppy"],"h":"It swims like a little fish.","e":"A baby frog is called a tadpole and lives in the water."},{"p":"🦋 What does a caterpillar turn into?","a":"A butterfly","w":["A bird","A bee","A frog"],"h":"It grows colorful wings.","e":"A caterpillar changes into a butterfly through metamorphosis."},{"p":"🛡️ What does a caterpillar make around itself before it becomes a butterfly?","a":"A chrysalis","w":["A nest","A seashell","A spider web"],"h":"It is a hard case it rests inside.","e":"A caterpillar forms a chrysalis, where it changes into a butterfly."},{"p":"🌻 A seed grows into a sprout, and then into what?","a":"A grown plant","w":["An egg","A tadpole","A rock"],"h":"It keeps getting bigger.","e":"A seed grows into a sprout and then into a full grown plant."},{"p":"🐕 A puppy grows up to become what?","a":"A dog","w":["A cat","A bird","A fish"],"h":"It is the grown-up animal.","e":"A puppy is a baby dog that grows into an adult dog."},{"p":"🦋 What is the correct order of a butterfly's life?","a":"Egg, caterpillar, chrysalis, butterfly","w":["Butterfly, dog, egg, seed","Seed, sprout, plant, egg","Egg, tadpole, frog, fly"],"h":"It starts out very tiny.","e":"A butterfly's life cycle goes egg, caterpillar, chrysalis, then butterfly."},{"p":"🌼 What must happen to a flower so it can make new seeds?","a":"It gets pollinated","w":["It gets painted","It gets frozen","It falls asleep"],"h":"Bees help by moving pollen.","e":"Flowers make new seeds after pollen moves between them, often carried by bees."},{"p":"🐸 A tadpole grows legs and loses its tail. What is it turning into?","a":"A frog","w":["A fish","A snake","A bird"],"h":"It will soon hop on land.","e":"A tadpole grows into a frog by growing legs and losing its tail."},{"p":"🥚 Which of these animals hatches from an egg?","a":"A turtle","w":["A cow","A horse","A dog"],"h":"It buries them in the sand.","e":"Turtles hatch from eggs, while cows, horses, and dogs are born live."},{"p":"🌰 A seed needs three things to sprout. Which group helps it grow?","a":"Water, air, and warmth","w":["Candy and toys","Ice and darkness","Only rocks and sand"],"h":"Think what a plant loves.","e":"Seeds need water, air, and warmth to sprout and begin growing."},{"p":"🔁 Why do living things have life cycles?","a":"To make new living things like them","w":["To turn into rocks","To make more toys","To stop growing forever"],"h":"Baby, grown-up, then babies again.","e":"Life cycles let living things grow up and make new young of their own kind."},{"p":"🌳 What can a fully grown apple tree make that a seed cannot?","a":"Flowers and fruit with seeds","w":["Baby puppies","Chicken eggs","Plastic apples"],"h":"Grown plants can reproduce.","e":"A grown tree can make flowers and fruit that hold new seeds."},{"p":"🐛 What does a caterpillar do most of the day?","a":"Eat leaves and grow","w":["Fly around the sky","Lay lots of eggs","Swim in ponds"],"h":"It needs energy to change.","e":"A caterpillar eats lots of leaves so it can grow before making a chrysalis."},{"p":"🐱 A kitten grows up to become what?","a":"A cat","w":["A dog","A rabbit","A cow"],"h":"Same kind of animal, grown up.","e":"A kitten grows into a cat because young animals become the same kind as their parents."}],"s.3.magnets":[{"p":"🧲 What are the two ends of a magnet called?","a":"Poles","w":["Sides","Points","Edges"],"h":"Every magnet has two of these.","e":"Every magnet has two poles, a north pole and a south pole."},{"p":"You bring a north pole and a south pole together. What happens?","a":"They pull together","w":["They push apart","Nothing happens","They spin in circles"],"h":"Opposite poles like each other.","e":"Opposite poles of magnets attract and pull toward each other."},{"p":"Two north poles are pushed toward each other. What happens?","a":"They push apart","w":["They pull together","They stick tightly","They melt together"],"h":"Same poles do not like each other.","e":"Like poles repel, so two north poles push away from each other."},{"p":"Which object will a magnet attract on the playground?","a":"A steel paper clip","w":["A plastic spoon","A wooden block","A rubber eraser"],"h":"Look for something made of iron or steel.","e":"Magnets attract objects made of iron or steel, like a paper clip."},{"p":"You slide a toy car across the carpet and it slows down and stops. What force slowed it?","a":"Friction","w":["Magnetism","Gravity pulling sideways","A push from the air"],"h":"It happens when two surfaces rub together.","e":"Friction is a force between surfaces that rub together, and it slows moving objects down."},{"p":"A force is best described as a...","a":"Push or pull","w":["Kind of metal","Type of magnet","Speed of an object"],"h":"Think about what you do to open a door.","e":"A force is a push or a pull that can change how an object moves."},{"p":"A book sits still on a table and does not move. The forces on it are...","a":"Balanced","w":["Unbalanced","Only pushing down","Only pushing up"],"h":"If it is not moving, the pushes and pulls are even.","e":"When forces are balanced, they cancel out and the object stays still."},{"p":"A soccer ball is sitting still, then you kick it and it rolls away. The forces on it became...","a":"Unbalanced","w":["Balanced","Perfectly equal","Frictionless"],"h":"Something changed its motion.","e":"Unbalanced forces change an object's motion, making it start, stop, or turn."},{"p":"Which force pulls a dropped ball down to the ground?","a":"Gravity","w":["Friction","Magnetism","A gentle push"],"h":"It pulls everything toward Earth.","e":"Gravity is the force that pulls objects down toward the center of the Earth."},{"p":"Can a magnet push or pull an object without touching it?","a":"Yes, it works across a small gap","w":["No, it must always touch","Only when it is wet","Only underwater"],"h":"Think about how magnets act as they get close.","e":"Magnets can attract or repel across a small distance without touching."},{"p":"A compass needle always points north because the needle is...","a":"A magnet","w":["Made of gold","Filled with water","A tiny battery"],"h":"It lines up with Earth's magnetism.","e":"A compass needle is a magnet that lines up with Earth's magnetic field to point north."},{"p":"You want a wagon to be easier to pull. Making the wheels roll more smoothly reduces...","a":"Friction","w":["Gravity","Magnetism","Weight"],"h":"Smooth rolling means less rubbing.","e":"Smoother, rolling wheels reduce friction, so the wagon is easier to pull."},{"p":"A swing goes back and forth the same way each time. This is an example of a...","a":"Pattern of motion","w":["Balanced force","Magnetic pole","Type of friction"],"h":"It repeats the same way, so you can predict it.","e":"A swing repeats a back-and-forth pattern, so its future motion can be predicted."},{"p":"Two magnets on a table suddenly snap together when brought close. The facing poles must be...","a":"Opposite poles","w":["The same poles","Both north poles","Both south poles"],"h":"Attraction means the poles are different.","e":"Opposite poles attract, so magnets that snap together are facing with opposite poles."},{"p":"Compared to a smooth surface, a rough surface usually creates...","a":"More friction","w":["Less friction","No friction","More gravity"],"h":"Think about sliding on sandpaper versus ice.","e":"Rough surfaces create more friction than smooth surfaces, so objects slow down faster."},{"p":"A magnet is covered by a thin sheet of paper. Will it still pick up a paper clip through the paper?","a":"Yes, magnetism works through thin paper","w":["No, paper blocks all magnets","Only if the paper is wet","Only if the paper is red"],"h":"Paper is thin and is not metal.","e":"Magnetism can pass through thin materials like paper, so the magnet still attracts the clip."}],"s.3.lifecycles":[{"p":"🦋 What is the correct order of a butterfly's life cycle?","a":"Egg, caterpillar, chrysalis, butterfly","w":["Egg, butterfly, caterpillar, chrysalis","Caterpillar, egg, butterfly, chrysalis","Butterfly, egg, chrysalis, caterpillar"],"h":"It starts as a tiny egg.","e":"A butterfly begins as an egg, becomes a caterpillar, forms a chrysalis, then emerges as a butterfly."},{"p":"A trait passed from parents to their young is called...","a":"An inherited trait","w":["A learned trait","A daily habit","A free choice"],"h":"You get it from your parents.","e":"Inherited traits, like eye color, are passed from parents to their offspring."},{"p":"Speaking a language is best described as a...","a":"Learned trait","w":["Inherited trait","Trait you had at birth","Trait carried in the blood"],"h":"Someone had to teach it to you.","e":"Speaking a language is learned from others, not passed down from parents."},{"p":"What happens to all living things at the end of their life cycle?","a":"They grow old and die","w":["They turn into rocks","They live forever","They become plants"],"h":"Every life cycle has an ending.","e":"All living things are born, grow, reproduce, and eventually die, completing the life cycle."},{"p":"Puppies in one litter have different fur colors. This difference among them is called...","a":"Variation","w":["A learned trait","A life cycle","Camouflage"],"h":"Members of the same group are not exactly alike.","e":"Variation means individuals of the same kind have small differences, like fur color."},{"p":"A polar bear's thick white fur helps it survive by...","a":"Keeping it warm and hidden in snow","w":["Helping it swim faster only","Making it grow taller","Helping it fly"],"h":"Think about the cold, snowy place it lives.","e":"Thick white fur is an adaptation that keeps the bear warm and camouflaged in the snowy Arctic."},{"p":"A trait that helps an animal survive in its environment is called an...","a":"Adaptation","w":["Accident","Illness","Invention"],"h":"It gives the animal an advantage.","e":"An adaptation is a helpful trait that improves an animal's chances of surviving."},{"p":"Which animal changes form through metamorphosis?","a":"A frog","w":["A dog","A horse","A cat"],"h":"It changes greatly from a tadpole.","e":"A frog changes greatly from a tadpole into an adult, which is called metamorphosis."},{"p":"A plant grows taller when it gets plenty of sunlight and water. This shows traits can be affected by...","a":"The environment","w":["Only its parents","Its name","The time of day"],"h":"Things around the plant can change it.","e":"The environment, such as sunlight and water, can affect how living things grow."},{"p":"A cactus stores water in its thick stem. This adaptation helps it survive in a...","a":"Dry desert","w":["Cold ocean","Rainy forest","Snowy mountain"],"h":"Where is water hard to find?","e":"Storing water helps a cactus survive in a dry desert where rain is rare."},{"p":"Many plants begin their life cycle as a...","a":"Seed","w":["Flower","Fruit","Root"],"h":"You plant it in the soil.","e":"Many plants start life as a seed that sprouts and grows into a new plant."},{"p":"Two kittens have the same mother but look different. The best reason is that they...","a":"Inherited a different mix of traits","w":["Were taught to look different","Are only different ages","Ate different food"],"h":"Offspring get a mix of traits from their parents.","e":"Offspring inherit different combinations of traits from their parents, so siblings can look different."},{"p":"A baby deer can walk soon after it is born. This ability is...","a":"Inherited","w":["Learned at school","Taught by humans","Copied from birds"],"h":"It did not have to be taught.","e":"Walking soon after birth is an inherited ability that helps the deer escape danger."},{"p":"What is the stage called where a caterpillar changes inside a hard case?","a":"Chrysalis","w":["Egg","Adult","Newborn"],"h":"It forms right after the caterpillar.","e":"Inside the chrysalis, or pupa, the caterpillar transforms into a butterfly."},{"p":"Rabbits whose fur blends into their surroundings are less likely to be seen by predators. Over time this helps them...","a":"Survive and have more young","w":["Grow longer ears","Learn to hide better","Change color instantly"],"h":"Being hidden helps them live longer.","e":"Camouflage helps animals avoid predators, so they are more likely to survive and reproduce."},{"p":"A dog learns to sit when its owner trains it. This behavior is...","a":"Learned","w":["Inherited","Present at birth","Passed to its puppies"],"h":"The owner had to teach it.","e":"Sitting on command is a learned behavior, not something passed down from parents."}],"s.4.energy":[{"p":"The energy an object has because it is moving is called...","a":"Energy of motion","w":["Stored energy","Sound energy only","Light energy only"],"h":"A rolling ball has it; a still ball does not.","e":"Energy of motion, also called kinetic energy, is the energy a moving object has."},{"p":"Two balls roll down a hill. The faster ball has...","a":"More energy of motion","w":["Less energy of motion","No energy at all","More gravity"],"h":"Faster movement means more of this energy.","e":"The faster an object moves, the more energy of motion it has."},{"p":"A fast bike hits a curb and stops, and the rider flies forward. This shows a faster object has...","a":"More energy to transfer","w":["Less energy to transfer","No energy to transfer","Only more friction"],"h":"Speed changed how much energy was passed on.","e":"Faster objects carry more energy of motion, so they transfer more energy in a collision."},{"p":"A moving bowling ball hits the pins and knocks them over. Energy was...","a":"Transferred to the pins","w":["Destroyed completely","Created from nothing","Turned into a magnet"],"h":"The ball gave its motion to the pins.","e":"In a collision, energy of motion is transferred from the ball to the pins."},{"p":"A toaster changes electrical energy mostly into...","a":"Heat energy","w":["Sound energy","Magnetic energy","Motion energy"],"h":"What does a toaster do to bread?","e":"A toaster converts electrical energy into heat energy to cook the bread."},{"p":"When you turn on a flashlight, electrical energy from the battery changes into...","a":"Light energy","w":["Sound energy","Motion energy","Magnetic energy"],"h":"What does a flashlight give off?","e":"A flashlight converts electrical energy from the battery into light energy."},{"p":"Electricity flows easily through a...","a":"Metal wire","w":["Rubber band","Plastic straw","Wooden stick"],"h":"Think about what electric wires are made of.","e":"Metals are good conductors, so electricity flows easily through a metal wire."},{"p":"A material that does NOT let electricity flow through it is called an...","a":"Insulator","w":["Conductor","Magnet","Battery"],"h":"Rubber and plastic are examples.","e":"An insulator, like rubber or plastic, blocks the flow of electricity."},{"p":"Rubbing your hands together quickly makes them warm. This changes motion energy into...","a":"Heat energy","w":["Light energy","Sound energy","Electrical energy"],"h":"Rubbing creates friction.","e":"Friction from rubbing changes energy of motion into heat energy."},{"p":"Which of these describes speed?","a":"How fast an object moves","w":["How heavy an object is","How tall an object is","What color an object is"],"h":"It tells you fast or slow.","e":"Speed is a measure of how fast an object moves over a distance."},{"p":"A ball resting at the top of a ramp starts to roll down. Its stored energy changes into...","a":"Energy of motion","w":["Magnetic energy","Sound energy only","Electrical energy"],"h":"Sitting up high becomes moving.","e":"Stored energy at the top changes into energy of motion as the ball rolls down."},{"p":"You wind up a toy car and let it go. The stored energy in the spring becomes...","a":"Motion energy","w":["Light energy","Heat energy only","Magnetic energy"],"h":"What does the car do when you release it?","e":"The spring's stored energy is converted into energy of motion that moves the car."},{"p":"A heavy truck and a small car move at the same speed. Which has more energy of motion?","a":"The heavy truck","w":["The small car","They are exactly equal","Neither has any"],"h":"More mass at the same speed means more energy.","e":"At the same speed, a heavier object has more energy of motion than a lighter one."},{"p":"A guitar string that is plucked makes sound because it is...","a":"Vibrating","w":["Melting","Glowing","Freezing"],"h":"It moves quickly back and forth.","e":"A plucked string vibrates, and those vibrations create sound energy."},{"p":"Closing the switch in a circuit lets the bulb light up because it...","a":"Completes the path for electricity","w":["Blocks the electricity","Removes the battery","Cools down the wire"],"h":"Electricity needs a full loop.","e":"Closing the switch completes the circuit so electricity can flow and light the bulb."},{"p":"Two toy cars crash head-on and both stop. What happened to their energy of motion?","a":"It changed into sound, heat, and bent metal","w":["It disappeared completely","It turned into new cars","It became gravity"],"h":"Energy is not destroyed; it changes form.","e":"The energy of motion transferred into other forms like sound, heat, and crumpling metal."}],"s.4.rocks":[{"p":"The slow breaking down of rock into smaller pieces is called...","a":"Weathering","w":["Erosion","Melting","Freezing"],"h":"Wind and water wear the rock down in place.","e":"Weathering is the process that breaks rock into smaller pieces over time."},{"p":"When wind or water carries broken rock and soil away to a new place, this is called...","a":"Erosion","w":["Weathering","Evaporation","Condensation"],"h":"The pieces are moved somewhere else.","e":"Erosion is the movement of weathered rock and soil to a new location."},{"p":"A river slowly carves a deep canyon over millions of years. This is an example of...","a":"Weathering and erosion","w":["A volcano erupting","An earthquake shaking","A fossil forming"],"h":"Moving water wore the rock away.","e":"Flowing water weathers and erodes rock, slowly carving canyons over long times."},{"p":"A fossil is...","a":"Preserved evidence of a living thing from long ago","w":["A shiny brand-new rock","A special kind of soil","A frozen drop of water"],"h":"It shows what once lived.","e":"A fossil is preserved remains or traces of an organism that lived long ago."},{"p":"Scientists find a fish fossil in rock high on a mountain. This is evidence that...","a":"The area was once underwater","w":["Fish can climb mountains","The rock is made of fish","Mountains are made of water"],"h":"Where do fish normally live?","e":"A fish fossil on a mountain shows the land there was once covered by water."},{"p":"The dark, crumbly material that plants grow in is called...","a":"Soil","w":["Lava","Metal","Glass"],"h":"You dig in it in a garden.","e":"Soil is the loose material of weathered rock and decayed matter where plants grow."},{"p":"Which part of soil helps plants grow by adding nutrients?","a":"Decayed plants and animals","w":["Broken glass bits","Pieces of plastic","Tiny metal filings"],"h":"It comes from things that were once alive.","e":"Humus, made of decayed living things, adds nutrients to soil that plants need."},{"p":"Rock that forms when melted lava or magma cools and hardens is called...","a":"Igneous rock","w":["Fossil rock","Soil rock","Ice rock"],"h":"Think about volcanoes and heat.","e":"Igneous rock forms when melted rock cools and hardens."},{"p":"Rock made from layers of sand, mud, and shells pressed together is called...","a":"Sedimentary rock","w":["Igneous rock","Melted rock","Metal ore"],"h":"It forms in layers over time.","e":"Sedimentary rock forms as layers of sediment are pressed and cemented together."},{"p":"Fossils are usually found in which type of rock?","a":"Sedimentary rock","w":["Igneous rock","Cooled lava rock","Freshly melted rock"],"h":"Think about which rock forms in gentle layers.","e":"Fossils are usually found in sedimentary rock because it forms in soft layers that bury remains."},{"p":"Water freezes inside a crack in a rock, and the crack grows bigger. This is an example of...","a":"Weathering","w":["Erosion","A fossil forming","A volcano"],"h":"The rock is breaking apart, not being carried away.","e":"Freezing water expands and cracks rock, which is a form of weathering."},{"p":"A beach loses sand every year during storms as waves carry it away. The waves are causing...","a":"Erosion","w":["Weathering only","New rock to form","Fossils to grow"],"h":"The sand is being carried to a new place.","e":"Waves carrying beach sand away is an example of erosion."},{"p":"A large area of land that is high up but flat on top is called a...","a":"Plateau","w":["Valley","River","Ocean"],"h":"It is high and flat like a tabletop.","e":"A plateau is a landform that is high in elevation and flat on top."},{"p":"Why are layers of sedimentary rock like a history book?","a":"Lower layers are usually older than upper layers","w":["Upper layers are always the oldest","All the layers form at once","The layers have no order"],"h":"New layers pile on top of older ones.","e":"Sediment builds up over time, so deeper layers are usually older than the ones above."},{"p":"Plant roots grow into a sidewalk crack and slowly break the concrete. This shows living things can cause...","a":"Weathering","w":["Erosion","Fossils","Earthquakes"],"h":"The roots are breaking material apart.","e":"Growing roots can break apart rock and concrete, which is a type of weathering."},{"p":"A scientist finds fossils of tropical ferns in a place that is now cold and icy. This suggests the area's...","a":"Climate has changed over time","w":["Ferns can survive on ice","Fossils floated there","Cold weather makes ferns"],"h":"Ferns need warmth to grow.","e":"Tropical fern fossils in a cold place are evidence that the climate there used to be warmer."}],"s.5.matter":[{"p":"All matter is made of tiny pieces too small to see, called...","a":"Particles","w":["Colors","Shadows","Bubbles"],"h":"They are far too small to see with your eyes.","e":"All matter is made of extremely tiny particles that are too small to see."},{"p":"You stir sugar into water and it disappears, but the water tastes sweet. The sugar...","a":"Broke into tiny particles spread through the water","w":["Disappeared and no longer exists","Turned into water","Was completely destroyed"],"h":"You can still taste it.","e":"The sugar particles spread out among the water particles, so no matter is lost."},{"p":"A mixture where one substance dissolves completely into another is called a...","a":"Solution","w":["Solid","Fossil","Metal"],"h":"Salt water is an example.","e":"A solution is a mixture in which one substance dissolves evenly into another."},{"p":"Sand mixed into water settles to the bottom. This is a mixture but NOT a solution because the sand...","a":"Does not dissolve","w":["Turns into water","Disappears","Becomes salt"],"h":"A solution dissolves completely.","e":"Sand does not dissolve in water, so it forms a mixture but not a solution."},{"p":"You stir salt into water until it disappears. How could you get the salt back?","a":"Let the water evaporate","w":["Freeze it into ice","Pour it through a strainer","Add even more salt"],"h":"Remove the water and see what is left behind.","e":"Evaporating the water leaves the salt behind, showing the salt was there all along."},{"p":"Ripping a piece of paper into smaller pieces is a...","a":"Physical change","w":["Chemical change","New substance","Type of solution"],"h":"It is still paper afterward.","e":"Tearing paper is a physical change because it is still paper, just in smaller pieces."},{"p":"Burning wood until it becomes ash and smoke is a...","a":"Chemical change","w":["Physical change","Simple mixture","Solution"],"h":"A new substance forms that cannot easily change back.","e":"Burning wood forms new substances like ash and gas, which is a chemical change."},{"p":"Which of these is a sign that a chemical change has happened?","a":"A new color, gas, or smell appears","w":["The object only changes shape","The object only gets colder","The object is cut into smaller pieces"],"h":"A new substance is being made.","e":"A new color, gas, heat, or smell are clues that a chemical change has occurred."},{"p":"When liquid water freezes into ice, the amount of matter...","a":"Stays the same","w":["Disappears","Doubles","Is destroyed"],"h":"Nothing is added or taken away.","e":"Freezing changes the state but not the amount of matter, so matter is conserved."},{"p":"You seal fizzing tablets and water in a closed bottle and weigh it. Compared to before, the total weight...","a":"Stays the same","w":["Gets much lighter","Gets much heavier","Drops to zero"],"h":"The gas is trapped inside the bottle.","e":"In a closed container, matter is conserved, so the total weight stays the same."},{"p":"A property you can use to help identify a material is its...","a":"Hardness, color, or magnetism","w":["Name only","Price only","Age only"],"h":"Think about how it looks, feels, or behaves.","e":"Properties like hardness, color, and magnetism help identify what a material is."},{"p":"You want to separate iron filings from a pile of sand. The best tool is a...","a":"Magnet","w":["Cup of water","Freezer","Flashlight"],"h":"Iron has a special property.","e":"A magnet attracts the iron filings, separating them from the sand."},{"p":"Trail mix has raisins, nuts, and pretzels you can still see and pick out. This is a...","a":"Mixture","w":["Solution","Chemical change","Pure substance"],"h":"The parts keep their own properties.","e":"Trail mix is a mixture because its parts keep their properties and can be separated."},{"p":"Which method best separates a mixture of water and pebbles?","a":"Pour it through a filter or strainer","w":["Boil away the pebbles","Use a magnet","Freeze it solid"],"h":"One part is big enough to be caught.","e":"A filter or strainer lets the water pass through but catches the pebbles."},{"p":"Ice melting into water, and water boiling into steam, are all examples of...","a":"Physical changes","w":["Chemical changes","New substances forming","Ways to destroy matter"],"h":"It is still water the whole time.","e":"Melting and boiling change water's state but not what it is, so they are physical changes."},{"p":"Two clear liquids are mixed and suddenly turn into a warm solid. This is most likely a...","a":"Chemical change","w":["Physical change","Simple mixture","Solution"],"h":"New properties and heat appeared.","e":"A new solid and heat show that a chemical change made a new substance."}],"s.5.earthwater":[{"p":"The sun heating water until it turns into water vapor is called...","a":"Evaporation","w":["Condensation","Precipitation","Collection"],"h":"Liquid becomes an invisible gas.","e":"Evaporation is when the sun's heat turns liquid water into water vapor."},{"p":"Water vapor cooling and forming clouds is called...","a":"Condensation","w":["Evaporation","Precipitation","Runoff"],"h":"Gas turns back into tiny droplets.","e":"Condensation is when water vapor cools and turns into tiny droplets that form clouds."},{"p":"Rain, snow, sleet, and hail are all forms of...","a":"Precipitation","w":["Evaporation","Condensation","Collection"],"h":"It falls from the clouds.","e":"Precipitation is water that falls from clouds as rain, snow, sleet, or hail."},{"p":"Dew appears on the grass on a cool morning even though it did not rain. This water came from...","a":"Water vapor condensing from the air","w":["Rain that fell overnight","The grass making its own water","Underground rivers"],"h":"The air holds invisible water.","e":"On cool mornings, water vapor in the air condenses into dew on the grass."},{"p":"Most of Earth's water is found in the...","a":"Oceans as salt water","w":["Rivers as fresh water","Clouds as vapor","Underground as ice"],"h":"Think about what covers most of Earth.","e":"Most of Earth's water is salty ocean water covering much of the planet."},{"p":"Why can't people drink most of the water on Earth?","a":"Most of it is salty ocean water","w":["Most of it is frozen air","Most of it is up in clouds","Most of it is underground oil"],"h":"Ocean water tastes salty.","e":"Most of Earth's water is salty ocean water, which people cannot safely drink."},{"p":"Only a small part of Earth's fresh water is easy for us to use because much of it is...","a":"Frozen in glaciers and ice caps","w":["Floating in the clouds","Mixed into the oceans","Turned into solid rock"],"h":"Think about the cold poles.","e":"Much of Earth's fresh water is locked in glaciers and ice caps, so little is easy to use."},{"p":"The day-to-day condition of the air, like today's temperature and rain, is called...","a":"Weather","w":["Climate","A season","The water cycle"],"h":"It can change from hour to hour.","e":"Weather is the condition of the air in one place at one time."},{"p":"The typical pattern of weather in a place measured over many years is its...","a":"Climate","w":["Weather","Forecast","Storm"],"h":"It is the long-term average.","e":"Climate is the average weather pattern of a place measured over many years."},{"p":"A desert that is hot and dry almost every year is being described by its...","a":"Climate","w":["Today's weather","A single storm","Wind speed"],"h":"This is a long-term pattern, not one day.","e":"A pattern seen over many years, like a hot dry desert, describes climate."},{"p":"Rain falls on a mountain and flows downhill across the land in streams. This is called...","a":"Runoff","w":["Evaporation","Condensation","Water vapor"],"h":"The water runs across the surface.","e":"Runoff is water that flows over the land, often into rivers, lakes, and oceans."},{"p":"What provides the energy that powers the water cycle?","a":"Energy from the sun","w":["Energy from the moon","Energy from wind only","Energy from the soil"],"h":"Something has to warm the water.","e":"The sun's energy drives the water cycle by heating and evaporating water."},{"p":"A forecaster sees warm, moist air rising quickly into the sky. This most likely leads to...","a":"Clouds and possible storms","w":["Clear skies forever","Colder oceans","Less rain everywhere"],"h":"Rising moist air cools and forms clouds.","e":"Warm, moist air that rises and cools forms clouds and can bring storms."},{"p":"After it rains, a puddle slowly shrinks and disappears on a sunny day. Where did the water go?","a":"It evaporated into the air","w":["It sank and turned to rock","It froze into vapor","It vanished completely"],"h":"The sun warmed the puddle.","e":"The sun's heat evaporated the puddle, turning the water into invisible vapor."},{"p":"Which is a good way to conserve fresh water at home?","a":"Turn off the tap while brushing your teeth","w":["Let the faucet run all day","Pour clean water down the drain","Use extra water to wash the sidewalk"],"h":"Use only the water you need.","e":"Turning off the tap when it is not needed saves fresh water, an important resource."},{"p":"In winter, water vapor high in a cloud freezes into crystals and falls. This form of precipitation is...","a":"Snow","w":["Dew","Fog","Runoff"],"h":"Frozen precipitation is soft and white.","e":"When water freezes into ice crystals in clouds and falls, it comes down as snow."}],"s.6.weather":[{"p":"What is the main difference between weather and climate?","a":"Weather is short-term conditions; climate is the long-term average","w":["Weather is the long-term average; climate is short-term conditions","Weather and climate mean exactly the same thing","Weather happens in space; climate happens on Earth"],"h":"Think about time scales: days versus many years.","e":"Weather describes day-to-day conditions, while climate is the average of weather over many years."},{"p":"Which gas makes up most of Earth's atmosphere?","a":"Nitrogen","w":["Oxygen","Carbon dioxide","Water vapor"],"h":"It makes up about 78% of the air.","e":"Nitrogen makes up roughly 78% of Earth's atmosphere, far more than oxygen."},{"p":"In the water cycle, what process turns liquid water into water vapor?","a":"Evaporation","w":["Condensation","Precipitation","Collection"],"h":"It requires heat energy from the Sun.","e":"Evaporation occurs when heat energy changes liquid water into invisible water vapor."},{"p":"What is condensation?","a":"Water vapor cooling and changing into tiny liquid droplets","w":["Liquid water heating and turning into vapor","Water falling from clouds as rain","Snow melting back into liquid water"],"h":"It is how clouds and dew form.","e":"Condensation happens when water vapor cools and turns back into liquid droplets, forming clouds."},{"p":"A cold air mass moves in and pushes under a warm air mass. What is this called?","a":"A cold front","w":["A warm front","A stationary front","A sea breeze"],"h":"Name it for the moving air mass that wedges underneath.","e":"A cold front forms when a cold air mass pushes under warmer air, often bringing storms."},{"p":"Warm fronts most often bring what kind of weather?","a":"Light, steady rain over a long period","w":["Sudden thunderstorms and strong gusty winds","Clear, dry, sunny skies for days","Heavy blizzard snow and freezing winds"],"h":"Warm air rises gently over cold air.","e":"Warm fronts bring gradual, steady precipitation as warm air slowly slides over cooler air."},{"p":"Why is it usually cooler at the top of a tall mountain than at its base?","a":"Air gets thinner and temperature drops as altitude increases","w":["The mountain top is much closer to the cold Sun","Snow at the top freezes all the surrounding air","Wind at the top removes all of the heat"],"h":"Think about how air changes as you go higher.","e":"As altitude increases the air becomes thinner and holds less heat, so temperature drops."},{"p":"Two cities share the same latitude, but one is on the coast and one is far inland. Which likely has milder, less extreme temperatures?","a":"The coastal city, because water heats and cools slowly","w":["The inland city, because land holds heat longer","Both cities have exactly identical temperatures","The coastal city, because oceans have no effect"],"h":"Water changes temperature more slowly than land.","e":"Large bodies of water heat and cool slowly, keeping nearby coastal areas milder year-round."},{"p":"What is the main source of energy that drives the water cycle and most weather?","a":"Energy from the Sun","w":["Heat from the Earth's core","The gravity of the Moon","Heat from underwater volcanoes"],"h":"It is the same thing that lights the daytime sky.","e":"The Sun's energy powers evaporation and heating that drive Earth's water cycle and weather."},{"p":"A weather report describes a 'north wind.' Where is the wind coming from?","a":"From the north","w":["From the south","Toward the north","From the west"],"h":"Winds are named for the direction they blow FROM.","e":"Winds are named for their origin, so a north wind blows from the north toward the south."},{"p":"What does humidity measure?","a":"The amount of water vapor in the air","w":["The temperature of the air","The speed of the wind","The amount of rain that has fallen"],"h":"It is about moisture in the air, not heat.","e":"Humidity measures how much water vapor is present in the air."},{"p":"How can ocean currents affect the climate of nearby land?","a":"Warm currents can carry heat and warm nearby coasts","w":["Currents cool every coastline they flow past","Currents have no effect on land temperatures","Currents only change tides, never climate"],"h":"Moving water can move heat too.","e":"Ocean currents transport heat, so warm currents can raise temperatures along nearby coasts."},{"p":"Which instrument measures air pressure?","a":"A barometer","w":["A thermometer","An anemometer","A hygrometer"],"h":"Its name hints at 'pressure.'","e":"A barometer measures atmospheric pressure, which helps forecasters predict weather changes."},{"p":"A barometer reading is dropping quickly. What weather is most likely on the way?","a":"Stormy or rainy weather","w":["Clear, calm, sunny weather","Only a rise in temperature","No change in the weather at all"],"h":"Falling pressure often means a storm system.","e":"Falling air pressure usually signals an approaching low-pressure system with clouds and storms."},{"p":"Why does the equator stay warmer than the poles?","a":"Sunlight strikes the equator more directly, concentrating energy","w":["The equator is much closer to the Sun","The poles are always in Earth's shadow","The equator has almost no atmosphere"],"h":"Think about the angle of the Sun's rays.","e":"Direct sunlight at the equator concentrates energy over a smaller area, keeping it warmer."},{"p":"Which of these is a factor that affects a region's climate?","a":"Latitude, or distance from the equator","w":["The day of the week","The current phase of the Moon","The color of the local soil"],"h":"Think about what determines how much direct sun a place gets.","e":"Latitude strongly affects climate because it determines how directly sunlight reaches a region."}],"s.6.energymachines":[{"p":"Which of these is a simple machine?","a":"An inclined plane","w":["A bicycle","A car engine","A laptop computer"],"h":"Simple machines have few or no moving parts.","e":"An inclined plane is one of the six simple machines; a bicycle is a compound machine made of several."},{"p":"A ramp used to roll heavy boxes up to a truck is an example of which simple machine?","a":"An inclined plane","w":["A lever","A pulley","A wheel and axle"],"h":"It is a flat, slanted surface.","e":"A ramp is an inclined plane, which reduces the force needed to raise an object."},{"p":"What does a simple machine do?","a":"It makes work easier by changing the size or direction of a force","w":["It creates brand-new energy out of nothing","It removes the need to do any work at all","It makes heavy objects actually weigh less"],"h":"Machines change how force is applied, not the total work.","e":"Simple machines make tasks easier by changing the amount or direction of the force you apply."},{"p":"A seesaw on a playground is an example of which simple machine?","a":"A lever","w":["A wedge","A screw","A pulley"],"h":"It balances on a pivot point.","e":"A seesaw is a lever that pivots on a fixed point called a fulcrum."},{"p":"In science, work is done whenever...","a":"A force moves an object over a distance","w":["You think very hard about a difficult problem","You hold a heavy box perfectly still","An object simply rests on a shelf"],"h":"Something must actually move.","e":"Scientific work happens only when a force causes an object to move some distance."},{"p":"You push hard on a brick wall for five minutes, but it does not move. How much work did you do on the wall?","a":"No work, because the wall did not move","w":["A lot of work, because you pushed hard","Some work, because you got tired","Work equal to your own weight"],"h":"Work requires movement, not effort.","e":"Since the wall did not move any distance, no scientific work was done on it despite the effort."},{"p":"What is potential energy?","a":"Stored energy due to an object's position or condition","w":["The energy of an object in motion","Energy that has already been used up","Energy that only machines can make"],"h":"Think of energy waiting to be released.","e":"Potential energy is stored energy, such as the energy in a ball held high above the ground."},{"p":"What is kinetic energy?","a":"The energy of a moving object","w":["Stored energy of a raised object","Energy that is waiting to be released","Chemical energy stored in food"],"h":"'Kinetic' relates to motion.","e":"Kinetic energy is the energy an object has because it is moving."},{"p":"A ball is held at the top of a hill and then released. As it rolls down, what happens to its energy?","a":"Potential energy changes into kinetic energy","w":["Kinetic energy changes into potential energy","Its energy is destroyed as it rolls","New energy is created by the hill"],"h":"It starts stored and ends up moving.","e":"As the ball rolls downhill, stored potential energy is converted into kinetic energy of motion."},{"p":"What does the mechanical advantage of a machine tell you?","a":"How much the machine multiplies your input force","w":["How fast the machine can move objects","How much energy the machine creates","How much the machine itself weighs"],"h":"It compares output force to input force.","e":"Mechanical advantage tells you how many times a machine multiplies the force you put in."},{"p":"Why does a longer ramp make it easier to lift a load to the same height?","a":"You use less force but push over a longer distance","w":["The load actually becomes lighter on it","A longer ramp creates extra free energy","Gravity turns off on a longer ramp"],"h":"Less force is traded for more distance.","e":"A longer inclined plane spreads the work over a greater distance, so less force is needed."},{"p":"A knife blade used to slice food is an example of which simple machine?","a":"A wedge","w":["A screw","A lever","A pulley"],"h":"It has a thin, slanted edge that splits things.","e":"A knife is a wedge, which uses a sharp edge to push objects apart."},{"p":"A flagpole with a rope looped over the top uses which simple machine to raise the flag?","a":"A pulley","w":["A wedge","An inclined plane","A screw"],"h":"It changes the direction of your pull.","e":"A pulley uses a wheel and rope to change the direction of force, letting you pull down to lift up."},{"p":"Energy cannot be created or destroyed. So where does a moving car's kinetic energy mostly go when it brakes to a stop?","a":"It is transformed mostly into heat energy","w":["It disappears completely and is gone","It is destroyed by the car's brakes","It changes back into gasoline"],"h":"Feel how hot brakes get.","e":"Braking converts the car's kinetic energy into heat through friction, conserving total energy."},{"p":"A truck and a bicycle move at the same speed. Which has more kinetic energy?","a":"The truck, because it has much more mass","w":["The bicycle, because it is smaller","They are equal because their speeds match","Neither one has any kinetic energy"],"h":"Kinetic energy depends on both mass and speed.","e":"With equal speeds, the object with more mass, the truck, has more kinetic energy."},{"p":"A screw is basically which simple machine wrapped around a cylinder?","a":"An inclined plane","w":["A lever","A pulley","A wheel and axle"],"h":"Look at the slanted ridges spiraling up it.","e":"A screw is an inclined plane wrapped around a central cylinder, forming its spiral threads."}],"s.7.bodysystems":[{"p":"What is the main job of the circulatory system?","a":"To transport blood, oxygen, and nutrients through the body","w":["To break down food into usable nutrients","To exchange oxygen and carbon dioxide with air","To send electrical signals to the muscles"],"h":"Think about what the heart moves around.","e":"The circulatory system moves blood, delivering oxygen and nutrients and carrying away wastes."},{"p":"Which organ pumps blood throughout the body?","a":"The heart","w":["The lungs","The liver","The brain"],"h":"It beats about 60-100 times a minute.","e":"The heart is a muscular pump that pushes blood through blood vessels to the whole body."},{"p":"Where does most nutrient absorption happen in the digestive system?","a":"The small intestine","w":["The stomach","The large intestine","The esophagus"],"h":"It is long and lined with tiny villi.","e":"The small intestine absorbs most nutrients into the blood through its finger-like villi."},{"p":"What is the main job of the respiratory system?","a":"To bring in oxygen and remove carbon dioxide","w":["To pump blood around the whole body","To digest food into usable nutrients","To support the body with a frame of bones"],"h":"It works every time you breathe.","e":"The respiratory system takes in oxygen and releases carbon dioxide during breathing."},{"p":"Which system uses the brain and electrical signals to control the body?","a":"The nervous system","w":["The circulatory system","The digestive system","The skeletal system"],"h":"It includes the brain, spinal cord, and nerves.","e":"The nervous system sends electrical signals through nerves to sense and control the body."},{"p":"You touch a hot stove and instantly pull your hand away. Which system detected the danger and signaled your muscles?","a":"The nervous system","w":["The digestive system","The respiratory system","The circulatory system"],"h":"Which system carries fast electrical signals?","e":"The nervous system sensed the heat and quickly signaled muscles to move your hand away."},{"p":"What two gases do the lungs exchange with the blood?","a":"Oxygen and carbon dioxide","w":["Nutrients and water","Blood and plasma","Sugar and salt"],"h":"One is breathed in, one is breathed out.","e":"In the lungs, oxygen enters the blood and carbon dioxide leaves it to be exhaled."},{"p":"What is one important job of the skeletal system?","a":"To support the body and protect internal organs","w":["To digest food into usable energy","To pump blood toward the lungs","To filter liquid wastes from blood"],"h":"Think about your rib cage and skull.","e":"The skeletal system provides structure and shields organs like the brain, heart, and lungs."},{"p":"How do the respiratory and circulatory systems work together?","a":"The lungs add oxygen to blood, which the heart pumps to the body","w":["The lungs pump blood while the heart breathes air","They work completely separately from each other","The heart digests the oxygen for the lungs"],"h":"One collects oxygen, the other delivers it.","e":"The lungs load oxygen into the blood, and the heart then pumps that blood throughout the body."},{"p":"What is homeostasis?","a":"Keeping a stable internal environment in the body","w":["Growing new body cells very rapidly","Breaking food down to release energy","Fighting off every kind of disease"],"h":"'Homeo' means same, 'stasis' means steady.","e":"Homeostasis is the body's process of maintaining steady internal conditions like temperature."},{"p":"When you get too hot, you sweat to cool down. This is an example of...","a":"Homeostasis","w":["Digestion","Respiration","Circulation"],"h":"The body is keeping a steady temperature.","e":"Sweating cools the body to maintain a stable internal temperature, which is homeostasis."},{"p":"Which system transports oxygen and nutrients to muscle cells all over the body?","a":"The circulatory system","w":["The skeletal system","The nervous system","The respiratory system"],"h":"It carries materials through blood vessels.","e":"The circulatory system delivers oxygen and nutrients to cells throughout the body via blood."},{"p":"How do muscles usually cause bones to move?","a":"They pull on bones by contracting","w":["They push bones apart by expanding","They dissolve slightly to shift bones","They pump blood to bend the bones"],"h":"Muscles can only shorten and pull.","e":"Muscles move bones by contracting and pulling on them, since muscles can pull but not push."},{"p":"What are the tiny air sacs in the lungs where gas exchange takes place?","a":"Alveoli","w":["Villi","Neurons","Tendons"],"h":"They look like clusters of tiny balloons.","e":"Alveoli are tiny air sacs in the lungs where oxygen and carbon dioxide are exchanged with blood."},{"p":"Why must the digestive system break food into very small molecules?","a":"So nutrients can be absorbed into the blood","w":["So food can be stored inside the bones","So the body can breathe the food out","So the brain can send signals faster"],"h":"Only small pieces can pass into the bloodstream.","e":"Food must be broken into small molecules so nutrients can be absorbed into the blood and used by cells."},{"p":"The nervous system signals the diaphragm to contract. Which body process does this cause?","a":"Breathing air into the lungs","w":["Digesting food in the stomach","Pumping blood to the body","Growing longer bones"],"h":"The diaphragm is the main breathing muscle.","e":"When the diaphragm contracts, it expands the chest and pulls air into the lungs, causing inhalation."}],"s.7.ecology":[{"p":"What is a producer in an ecosystem?","a":"An organism that makes its own food, such as a plant","w":["An animal that hunts and eats other animals","An organism that breaks down dead matter","An animal that eats only plants for food"],"h":"Think about what uses sunlight to make food.","e":"Producers, like plants, make their own food through photosynthesis using sunlight."},{"p":"What is a consumer?","a":"An organism that eats other organisms for energy","w":["An organism that makes its own food","An organism that only decomposes waste","An organism that makes oxygen from sunlight"],"h":"It cannot make its own food.","e":"Consumers get energy by eating other organisms because they cannot make their own food."},{"p":"What do decomposers do in an ecosystem?","a":"Break down dead organisms and return nutrients to the soil","w":["Make their own food from sunlight","Hunt and eat living prey animals","Produce oxygen for other animals"],"h":"Think of mushrooms and bacteria.","e":"Decomposers break down dead matter, recycling nutrients back into the soil for producers."},{"p":"Where does the energy in almost every food web originally come from?","a":"The Sun","w":["The soil","Decomposers","The water cycle"],"h":"Producers capture it first.","e":"Nearly all food-web energy starts as sunlight, which producers capture through photosynthesis."},{"p":"In the food chain grass → grasshopper → frog → snake, what is the grasshopper?","a":"A primary consumer","w":["A producer","A decomposer","A top predator"],"h":"It eats the producer directly.","e":"The grasshopper eats grass, making it a primary consumer, the first consumer level."},{"p":"In an energy pyramid, why is there less energy available at each higher level?","a":"Most energy is lost as heat at each level","w":["Higher-level animals simply need less energy","Energy is destroyed whenever predators eat","Producers store all the energy at the top"],"h":"Energy is used up for life activities.","e":"Only about 10% of energy passes to the next level; the rest is lost as heat and life processes."},{"p":"A relationship in which both organisms benefit is called...","a":"Mutualism","w":["Parasitism","Commensalism","Predation"],"h":"Both partners come out ahead.","e":"In mutualism, both organisms benefit, like a bee getting nectar while pollinating a flower."},{"p":"In a parasitic relationship, what happens?","a":"One organism benefits while the other is harmed","w":["Both organisms benefit equally","One benefits and the other is unaffected","Both organisms are equally harmed"],"h":"Think of a tick on a dog.","e":"In parasitism, the parasite benefits while the host organism is harmed."},{"p":"A bird builds a nest in a tree. The bird is helped and the tree is unaffected. What relationship is this?","a":"Commensalism","w":["Mutualism","Parasitism","Competition"],"h":"One gains, the other neither gains nor loses.","e":"Commensalism is when one organism benefits and the other is neither helped nor harmed."},{"p":"What is carrying capacity?","a":"The largest population an environment can support","w":["The number of predators living in an area","The combined weight of all the plants","The speed at which a population grows"],"h":"Think about limits on resources.","e":"Carrying capacity is the maximum population size an environment can support with its resources."},{"p":"If the number of rabbits in a field suddenly increases, what will most likely happen to the fox population that eats them?","a":"The fox population will likely increase","w":["The fox population will immediately die off","The foxes will change into producers","The foxes will stop eating rabbits"],"h":"More food usually means more predators.","e":"More prey means more food for foxes, so the predator population tends to grow in response."},{"p":"Why does removing all the wolves from an area often cause the deer population to grow too large?","a":"Fewer predators means fewer deer are eaten","w":["Wolves were producers the deer needed","Deer only reproduce once wolves leave","Deer become decomposers without wolves"],"h":"Wolves are the deer's main predator.","e":"Without wolves preying on them, more deer survive and reproduce, so the population grows unchecked."},{"p":"What is one role of plants in the carbon cycle?","a":"They take in carbon dioxide during photosynthesis","w":["They release only carbon dioxide, never oxygen","They remove all nitrogen from the soil","They break down and decompose dead animals"],"h":"Think about what plants use to make food.","e":"During photosynthesis, plants absorb carbon dioxide from the air, moving carbon through the cycle."},{"p":"In a food web diagram, what does each arrow represent?","a":"The flow of energy from one organism to another","w":["The direction that animals travel","The flow of water in the ecosystem","The movement of oxygen only"],"h":"Arrows point from food toward the eater.","e":"Each arrow in a food web shows the direction energy flows, from the food to the organism that eats it."},{"p":"An organism that eats both plants and animals is called...","a":"An omnivore","w":["A herbivore","A carnivore","A decomposer"],"h":"'Omni' means all.","e":"An omnivore eats both plants and animals, like a bear or a human."},{"p":"Two species of birds eat the exact same seeds in the same area. What are they most likely doing?","a":"Competing for the same resource","w":["Practicing mutualism together","Acting as decomposers","Forming a food chain"],"h":"They both need a limited resource.","e":"When organisms need the same limited resource, they compete, which is competition."}],"s.8.reactions":[{"p":"In a chemical reaction, the starting substances are called...","a":"Reactants","w":["Products","Solutions","Mixtures"],"h":"They are present before the reaction begins.","e":"Reactants are the substances that you start with and that get changed during a reaction."},{"p":"The new substances formed during a chemical reaction are called...","a":"Products","w":["Reactants","Elements","Catalysts"],"h":"They appear on the right side of an equation.","e":"Products are the new substances created when reactants combine and change in a reaction."},{"p":"What does the law of conservation of mass state about a chemical reaction?","a":"Mass is neither created nor destroyed","w":["Mass always increases during a reaction","Mass always decreases during a reaction","Mass is turned directly into energy"],"h":"Atoms are only rearranged, not lost.","e":"In a chemical reaction, matter is rearranged, so the total mass stays the same."},{"p":"You seal 10 g of reactants in a jar and they react completely. What is the mass of the products?","a":"10 g","w":["More than 10 g","Less than 10 g","0 g"],"h":"No atoms can enter or leave a sealed jar.","e":"Because mass is conserved, the sealed products must still total 10 g, the same as the reactants."},{"p":"Which of these is a sign that a chemical reaction has likely occurred?","a":"A color change or gas bubbles forming","w":["An ice cube melting into water","Liquid water boiling into steam","Sugar dissolving evenly in tea"],"h":"Physical changes do not make new substances.","e":"Color changes and gas production suggest new substances formed, a sign of a chemical reaction."},{"p":"An exothermic reaction...","a":"Releases energy, often as heat","w":["Absorbs energy from its surroundings","Destroys energy completely","Creates brand-new atoms"],"h":"'Exo' means out or exit.","e":"Exothermic reactions release energy to their surroundings, usually making them feel warmer."},{"p":"An endothermic reaction...","a":"Absorbs energy from its surroundings","w":["Releases heat to its surroundings","Gives off only bright light","Produces no energy change at all"],"h":"'Endo' means into.","e":"Endothermic reactions absorb energy, often making the surroundings feel cooler."},{"p":"A cold pack becomes cold when you activate it. What kind of reaction is happening?","a":"Endothermic, because it absorbs heat","w":["Exothermic, because it releases heat","No reaction is happening at all","Only a physical change is occurring"],"h":"The pack takes heat from its surroundings.","e":"The cold pack feels cold because an endothermic reaction absorbs heat from its surroundings."},{"p":"On the pH scale, a value below 7 means a substance is...","a":"Acidic","w":["Basic","Neutral","A salt"],"h":"Lemon juice and vinegar fall here.","e":"Substances with a pH below 7 are acids, such as vinegar and lemon juice."},{"p":"A substance with a pH of exactly 7 is considered...","a":"Neutral","w":["Strongly acidic","Strongly basic","Impossible to make"],"h":"Pure water is the classic example.","e":"A pH of 7 is neutral, neither acidic nor basic, like pure water."},{"p":"Lemon juice has a pH of about 2. This tells you it is...","a":"A strong acid","w":["A strong base","A neutral liquid","Ordinary salt water"],"h":"The lower the pH, the stronger the acid.","e":"A pH of 2 is well below 7, showing that lemon juice is a strong acid."},{"p":"Why must a chemical equation be balanced?","a":"To show the same number of each atom on both sides","w":["To make the reaction happen much faster","So that new mass can be created","To keep the products heavier than reactants"],"h":"It reflects conservation of mass.","e":"Balancing shows equal atoms of each element on both sides, matching the conservation of mass."},{"p":"In the reaction 2H₂ + O₂ → 2H₂O, what does the 2 in front of H₂O mean?","a":"Two molecules of water are formed","w":["Two atoms of oxygen are formed","The water weighs exactly 2 grams","Two separate reactions take place"],"h":"The big number in front is a coefficient.","e":"The coefficient 2 means two molecules of water are produced in the reaction."},{"p":"When wood burns, the ash left behind weighs far less than the original wood. Where did the missing mass go?","a":"It escaped as gases and smoke","w":["The mass was destroyed by the fire","It turned completely into pure energy","The mass simply vanished into nothing"],"h":"Mass cannot be destroyed, only moved.","e":"Burning releases gases like carbon dioxide and water vapor, carrying away mass that seemed to disappear."},{"p":"Mixing baking soda and vinegar creates lots of bubbles. What do the bubbles show?","a":"A gas was produced in a chemical reaction","w":["The liquid is simply boiling","Only a physical change is happening","The mixture is beginning to freeze"],"h":"New gas means a new substance formed.","e":"The bubbles are carbon dioxide gas, a new substance produced by a chemical reaction."},{"p":"A substance that speeds up a chemical reaction without being used up is called...","a":"A catalyst","w":["A reactant","A product","A solvent"],"h":"It helps the reaction but remains unchanged.","e":"A catalyst speeds up a reaction without being consumed, so it can be used again and again."}],"s.8.waves":[{"p":"What is the wavelength of a wave?","a":"The distance between two matching points on a wave","w":["The height of the wave from its rest position","The number of waves that pass each second","The speed at which the wave travels"],"h":"Measure from one crest to the next crest.","e":"Wavelength is the distance between two identical points, such as from one crest to the next."},{"p":"What does the amplitude of a wave measure?","a":"The height of a wave from rest, related to its energy","w":["The distance between two wave crests","How many waves pass a point each second","How fast the wave is traveling"],"h":"Taller waves carry more energy.","e":"Amplitude is the height of a wave from its rest position and indicates how much energy it carries."},{"p":"What is the frequency of a wave?","a":"The number of waves that pass a point each second","w":["The distance between two crests","The height of the wave from rest","The speed of light in a vacuum"],"h":"It is measured in waves per second (hertz).","e":"Frequency is how many wave cycles pass a fixed point each second, measured in hertz."},{"p":"A wave has a large amplitude. What does this tell you about its energy?","a":"It carries more energy","w":["It carries less energy","It carries no energy at all","Amplitude is unrelated to energy"],"h":"Bigger waves hit harder.","e":"A larger amplitude means the wave carries more energy."},{"p":"In a transverse wave, the particles move...","a":"Perpendicular, at right angles, to the wave's direction","w":["In the same direction as the wave travels","In small circles around the source","They do not move at all"],"h":"Picture shaking a rope up and down.","e":"In a transverse wave, particles vibrate at right angles to the direction the wave travels."},{"p":"In a longitudinal wave, the particles move...","a":"Back and forth, parallel to the wave's direction","w":["At right angles to the wave's direction","In a fixed circular path","Straight up and down only"],"h":"Think of a stretched spring pushed and pulled.","e":"In a longitudinal wave, particles move back and forth in the same direction the wave travels."},{"p":"Sound travels by compressing and spreading apart the particles in a medium. What type of wave is sound?","a":"A longitudinal wave","w":["A transverse wave","An electromagnetic wave","A wave that needs no medium"],"h":"Particles move parallel to the wave.","e":"Sound is a longitudinal wave because particles vibrate back and forth along its direction of travel."},{"p":"Sound is produced by...","a":"Vibrations traveling through a medium","w":["Light bouncing off nearby objects","Heat rising from a warm surface","Magnets pushing on the air"],"h":"Feel your throat when you hum.","e":"Sound is created by vibrations that travel as waves through a medium like air, water, or solids."},{"p":"Why can't sound travel through the vacuum of outer space?","a":"There are no particles to carry the vibrations","w":["Space is far too cold for any sound","Sound simply moves too fast in space","There is too much light in space"],"h":"Sound needs a medium to travel.","e":"Sound needs particles to pass vibrations along, and a vacuum has none, so sound cannot travel."},{"p":"When light bounces off a surface such as a mirror, this is called...","a":"Reflection","w":["Refraction","Absorption","Diffraction"],"h":"You see your image bounce back.","e":"Reflection occurs when light bounces off a surface, such as a mirror, back toward your eyes."},{"p":"When light bends as it passes from air into water, this is called...","a":"Refraction","w":["Reflection","Absorption","Vibration"],"h":"The light changes direction as it enters.","e":"Refraction is the bending of light as it passes from one material into another, like air into water."},{"p":"A straw in a glass of water appears bent at the water's surface. What causes this?","a":"Refraction of light","w":["Reflection of light","The straw actually bending","Sound waves in the water"],"h":"Light bends as it leaves the water.","e":"The straw looks bent because light refracts, changing direction as it moves between water and air."},{"p":"Which of these is part of the electromagnetic spectrum?","a":"Visible light","w":["Sound waves","Water waves","Seismic waves"],"h":"EM waves can travel through empty space.","e":"Visible light is part of the electromagnetic spectrum, unlike sound, which needs a medium."},{"p":"Radio waves and visible light are both electromagnetic waves. How do they differ?","a":"They have different wavelengths and frequencies","w":["Radio waves are actually made of sound","Only visible light can travel through space","They travel at very different speeds in a vacuum"],"h":"All EM waves travel at the same speed in a vacuum.","e":"Radio waves and light differ in wavelength and frequency, though both travel at light speed in a vacuum."},{"p":"A sound wave with a higher frequency produces a sound that is...","a":"Higher in pitch","w":["Lower in pitch","Louder in volume","Quieter in volume"],"h":"Frequency controls pitch, not loudness.","e":"Higher-frequency sound waves are heard as higher-pitched sounds."},{"p":"Two sound waves have the same pitch, but one is louder. What is different about the louder wave?","a":"It has a greater amplitude","w":["It has a higher frequency","It has a longer wavelength","It travels much faster"],"h":"Loudness depends on amplitude.","e":"Louder sounds have greater amplitude, while pitch stays tied to frequency."}],"sp.k.saludos":[{"p":"How do you say 'Hello' in Spanish?","a":"Hola","w":["Adiós","Gracias","Buenas noches"],"h":"Starts with a silent H.","e":"'Hola' is the most common greeting, meaning 'hello'."},{"p":"How do you say 'Goodbye' in Spanish?","a":"Adiós","w":["Hola","Buenos días","Por favor"],"h":"You say it when you leave.","e":"'Adiós' means 'goodbye'."},{"p":"What does 'Gracias' mean in English?","a":"Thank you","w":["Please","Hello","You're welcome"],"h":"You say it when someone helps you.","e":"'Gracias' means 'thank you'."},{"p":"What does 'Por favor' mean in English?","a":"Please","w":["Thank you","Goodbye","Good morning"],"h":"You add it to be polite when asking.","e":"'Por favor' means 'please'."},{"p":"How do you say 'Good morning' in Spanish?","a":"Buenos días","w":["Buenas noches","Buenas tardes","Hasta luego"],"h":"You say it early in the day.","e":"'Buenos días' means 'good morning'."},{"p":"How do you say 'Good night' in Spanish?","a":"Buenas noches","w":["Buenos días","Buenas tardes","Muchas gracias"],"h":"You say it before going to sleep.","e":"'Buenas noches' means 'good night'."},{"p":"What does 'De nada' mean in English?","a":"You're welcome","w":["Please","Thank you","See you later"],"h":"You reply with it after someone thanks you.","e":"'De nada' is the polite reply to 'gracias'."},{"p":"How do you say 'Good afternoon' in Spanish?","a":"Buenas tardes","w":["Buenos días","Buenas noches","De nada"],"h":"You say it after noon.","e":"'Buenas tardes' means 'good afternoon'."},{"p":"Someone says 'Gracias.' What is a polite reply?","a":"De nada","w":["Por favor","Hola","Adiós"],"h":"It means 'you're welcome'.","e":"You answer 'gracias' with 'de nada'."},{"p":"What does 'Hola' mean in English?","a":"Hello","w":["Goodbye","Please","Thank you"],"h":"It's how you greet a friend.","e":"'Hola' means 'hello'."},{"p":"How do you ask 'How are you?' (informal) in Spanish?","a":"¿Cómo estás?","w":["¿Cómo te llamas?","¿Dónde estás?","¿Qué color?"],"h":"It uses the word 'cómo'.","e":"'¿Cómo estás?' asks how someone is feeling."},{"p":"What does '¿Cómo te llamas?' mean in English?","a":"What is your name?","w":["How are you?","Where are you?","How old are you?"],"h":"It asks about your name.","e":"'¿Cómo te llamas?' means 'what is your name?'."},{"p":"How do you say 'See you later' in Spanish?","a":"Hasta luego","w":["Buenas noches","Muchas gracias","Por favor"],"h":"You say it when leaving for a while.","e":"'Hasta luego' means 'see you later'."},{"p":"Fill in: 'Muchas ___' means 'thank you very much.'","a":"gracias","w":["favor","noches","hola"],"h":"The word means 'thanks'.","e":"'Muchas gracias' means 'thank you very much'."},{"p":"You meet your teacher in the morning. What do you say?","a":"Buenos días","w":["Buenas noches","Adiós","De nada"],"h":"It's a morning greeting.","e":"In the morning we greet with 'buenos días'."},{"p":"What does 'Adiós' mean in English?","a":"Goodbye","w":["Hello","Please","Good morning"],"h":"You say it when you leave.","e":"'Adiós' means 'goodbye'."}],"sp.k.colores":[{"p":"How do you say 'red' in Spanish?","a":"rojo","w":["azul","verde","negro"],"h":"It's the color of an apple.","e":"'Rojo' means 'red'."},{"p":"How do you say 'blue' in Spanish?","a":"azul","w":["rojo","amarillo","verde"],"h":"It's the color of the sky.","e":"'Azul' means 'blue'."},{"p":"How do you say 'green' in Spanish?","a":"verde","w":["azul","rojo","rosa"],"h":"It's the color of grass.","e":"'Verde' means 'green'."},{"p":"How do you say 'yellow' in Spanish?","a":"amarillo","w":["azul","verde","morado"],"h":"It's the color of the sun.","e":"'Amarillo' means 'yellow'."},{"p":"What does 'negro' mean in English?","a":"black","w":["white","brown","blue"],"h":"It's the color of night.","e":"'Negro' means 'black'."},{"p":"What does 'blanco' mean in English?","a":"white","w":["black","yellow","green"],"h":"It's the color of snow.","e":"'Blanco' means 'white'."},{"p":"How do you say the color 'orange' in Spanish?","a":"naranja","w":["morado","rosa","marrón"],"h":"Same word as the fruit.","e":"'Naranja' is both the fruit and the color orange."},{"p":"What does 'rosa' mean in English?","a":"pink","w":["red","purple","orange"],"h":"It's a light red color.","e":"'Rosa' means 'pink'."},{"p":"How do you say 'purple' in Spanish?","a":"morado","w":["rosa","naranja","marrón"],"h":"A mix of red and blue.","e":"'Morado' means 'purple'."},{"p":"What does 'marrón' mean in English?","a":"brown","w":["black","gray","green"],"h":"It's the color of chocolate.","e":"'Marrón' means 'brown'."},{"p":"What does 'rojo' mean in English?","a":"red","w":["blue","green","yellow"],"h":"The color of a strawberry.","e":"'Rojo' means 'red'."},{"p":"Fill in: 'la manzana ___' (the red apple).","a":"roja","w":["rojo","rojos","rojas"],"h":"'Manzana' is feminine and singular.","e":"Colors ending in -o change to -a for feminine nouns: 'roja'."},{"p":"Fill in: 'el gato ___' (the black cat).","a":"negro","w":["negra","negros","negras"],"h":"'Gato' is masculine and singular.","e":"With a masculine noun the color keeps -o: 'negro'."},{"p":"What color do you get by mixing 'azul' and 'amarillo'?","a":"verde","w":["morado","naranja","rojo"],"h":"It's the color of leaves.","e":"Azul (blue) and amarillo (yellow) make verde (green)."},{"p":"How do you say 'gray' in Spanish?","a":"gris","w":["verde","azul","rosa"],"h":"It's the color of a cloud.","e":"'Gris' means 'gray'."},{"p":"Fill in: 'las flores ___' (the yellow flowers).","a":"amarillas","w":["amarillo","amarilla","amarillos"],"h":"'Flores' is feminine and plural.","e":"For feminine plural nouns the color becomes 'amarillas'."}],"sp.4.comida":[{"p":"What does 'el pan' mean in English?","a":"bread","w":["cheese","milk","meat"],"h":"You use it to make a sandwich.","e":"'El pan' means 'bread'."},{"p":"How do you say 'apple' in Spanish?","a":"la manzana","w":["la naranja","el plátano","la pera"],"h":"A round fruit, often red or green.","e":"'La manzana' means 'apple'."},{"p":"What does 'la leche' mean in English?","a":"milk","w":["water","juice","cheese"],"h":"It comes from cows.","e":"'La leche' means 'milk'."},{"p":"How do you say 'water' in Spanish?","a":"el agua","w":["la leche","el jugo","el vino"],"h":"You drink it when thirsty.","e":"'El agua' means 'water'."},{"p":"What meal is 'el desayuno'?","a":"breakfast","w":["lunch","dinner","snack"],"h":"You eat it in the morning.","e":"'El desayuno' is the morning meal, breakfast."},{"p":"What meal is 'la cena'?","a":"dinner","w":["breakfast","lunch","dessert"],"h":"You eat it at night.","e":"'La cena' is the evening meal, dinner."},{"p":"What does 'el almuerzo' mean in English?","a":"lunch","w":["breakfast","dinner","dessert"],"h":"You eat it in the middle of the day.","e":"'El almuerzo' is the midday meal, lunch."},{"p":"Fill in: 'Me ___ el helado' (I like ice cream).","a":"gusta","w":["gustan","gusto","gustar"],"h":"'El helado' is singular.","e":"With a singular thing we use 'gusta': 'me gusta el helado'."},{"p":"How do you say 'I would like a water, please' when ordering?","a":"Quiero un agua, por favor","w":["Tengo un agua, por favor","Como un agua, por favor","Soy un agua, por favor"],"h":"Use the verb 'querer' (to want).","e":"'Quiero...' means 'I would like...' when ordering."},{"p":"What does 'el queso' mean in English?","a":"cheese","w":["bread","egg","chicken"],"h":"It's made from milk.","e":"'El queso' means 'cheese'."},{"p":"How do you say 'chicken' in Spanish?","a":"el pollo","w":["el pescado","la carne","el huevo"],"h":"A bird you can eat.","e":"'El pollo' means 'chicken'."},{"p":"What does 'la fruta' mean in English?","a":"fruit","w":["vegetable","meat","dessert"],"h":"Apples and bananas are examples.","e":"'La fruta' means 'fruit'."},{"p":"Fill in: 'Me ___ las verduras' (I like vegetables).","a":"gustan","w":["gusta","gusto","gustar"],"h":"'Las verduras' is plural.","e":"With plural things we use 'gustan': 'me gustan las verduras'."},{"p":"How do you say the fruit 'orange' in Spanish?","a":"la naranja","w":["la manzana","el limón","la fresa"],"h":"A round orange-colored citrus fruit.","e":"'La naranja' means the fruit 'orange'."},{"p":"What does 'el huevo' mean in English?","a":"egg","w":["ham","fish","rice"],"h":"A hen lays it.","e":"'El huevo' means 'egg'."},{"p":"A waiter asks '¿Qué desea?' What is he asking?","a":"What would you like?","w":["Where are you?","How much is it?","What is your name?"],"h":"You hear it in a restaurant when ordering.","e":"'¿Qué desea?' means 'what would you like?'."}],"sp.4.numeros":[{"p":"How do you write '5' in Spanish?","a":"cinco","w":["cuatro","seis","siete"],"h":"One more than four.","e":"'Cinco' is the number 5."},{"p":"What number is 'diez'?","a":"10","w":["9","11","12"],"h":"The first two-digit number.","e":"'Diez' is 10."},{"p":"How do you say '15' in Spanish?","a":"quince","w":["catorce","dieciséis","cincuenta"],"h":"Halfway to thirty.","e":"'Quince' is 15."},{"p":"What number is 'veinte'?","a":"20","w":["12","30","21"],"h":"Two tens.","e":"'Veinte' is 20."},{"p":"How do you say '30' in Spanish?","a":"treinta","w":["trece","cuarenta","tres"],"h":"Three tens.","e":"'Treinta' is 30."},{"p":"How do you write '11' in Spanish?","a":"once","w":["onze","diez","doce"],"h":"One more than ten.","e":"'Once' is 11."},{"p":"What number is 'cincuenta'?","a":"50","w":["15","40","60"],"h":"Half of one hundred.","e":"'Cincuenta' is 50."},{"p":"How do you say '100' in Spanish?","a":"cien","w":["ciento","mil","noventa"],"h":"Ten tens.","e":"'Cien' is exactly 100."},{"p":"How do you say '21' in Spanish?","a":"veintiuno","w":["veinte y uno","dieciuno","veintidós"],"h":"Twenty plus one, written as one word.","e":"'Veintiuno' is 21, written as a single word."},{"p":"What number is 'setenta'?","a":"70","w":["17","60","80"],"h":"Seven tens.","e":"'Setenta' is 70."},{"p":"How do you write '12' in Spanish?","a":"doce","w":["diez","once","dos"],"h":"One more than eleven.","e":"'Doce' is 12."},{"p":"What number is 'cuarenta'?","a":"40","w":["14","4","50"],"h":"Four tens.","e":"'Cuarenta' is 40."},{"p":"How do you say '16' in Spanish?","a":"dieciséis","w":["diez y seis","quince","diecisiete"],"h":"Ten plus six, one word with an accent.","e":"'Dieciséis' is 16."},{"p":"What is 'treinta y cinco' as a number?","a":"35","w":["25","53","305"],"h":"Thirty plus five.","e":"'Treinta y cinco' is 35."},{"p":"How do you say '90' in Spanish?","a":"noventa","w":["nueve","ochenta","novecientos"],"h":"Nine tens.","e":"'Noventa' is 90."},{"p":"What number is 'sesenta y ocho'?","a":"68","w":["78","86","618"],"h":"Sixty plus eight.","e":"'Sesenta y ocho' is 68."}],"sp.5.gustar":[{"p":"Fill in: 'Me ___ la música' (I like music).","a":"gusta","w":["gustan","gusto","gustas"],"h":"'La música' is singular.","e":"Use 'gusta' with a singular noun."},{"p":"Fill in: 'Me ___ los perros' (I like dogs).","a":"gustan","w":["gusta","gusto","gustas"],"h":"'Los perros' is plural.","e":"Use 'gustan' with a plural noun."},{"p":"How do you say 'You like the book' (informal) in Spanish?","a":"Te gusta el libro","w":["Te gustan el libro","Me gusta el libro","Te gusto el libro"],"h":"The informal 'to you' pronoun is 'te'.","e":"'Te gusta' means 'you like' with a singular thing."},{"p":"What does 'Le gusta el chocolate' mean?","a":"He/She likes chocolate","w":["I like chocolate","You like chocolate","They like chocolate"],"h":"'Le' means 'to him/her'.","e":"'Le gusta' means 'he/she likes'."},{"p":"Fill in: 'Me ___ los tacos' (I love tacos).","a":"encantan","w":["encanta","encanto","gustan"],"h":"'Los tacos' is plural; use 'encantar' for 'love'.","e":"'Encantar' works like 'gustar', so plural nouns take 'encantan'."},{"p":"Fill in: 'Nos ___ el helado' (We like ice cream).","a":"gusta","w":["gustan","gustamos","gustas"],"h":"'We' uses 'nos'; 'el helado' is singular.","e":"'Nos gusta' means 'we like' with a singular thing."},{"p":"How do you say 'I like to read' in Spanish?","a":"Me gusta leer","w":["Me gustan leer","Me gusta leo","Yo gusta leer"],"h":"With a verb, always use 'gusta'.","e":"When followed by a verb, 'gustar' stays singular: 'me gusta leer'."},{"p":"Fill in: 'Te ___ las manzanas' (You like apples).","a":"gustan","w":["gusta","gustas","gusto"],"h":"'Las manzanas' is plural.","e":"Use 'gustan' because 'las manzanas' is plural."},{"p":"What does 'Me encanta bailar' mean?","a":"I love to dance","w":["I like to dance a little","I hate to dance","You love to dance"],"h":"'Encantar' is stronger than 'gustar'.","e":"'Me encanta bailar' means 'I love to dance'."},{"p":"How do you say 'She likes flowers' in Spanish?","a":"Le gustan las flores","w":["Le gusta las flores","Les gustan las flores","Le gustan la flor"],"h":"'Le' for her; 'las flores' is plural.","e":"'Le gustan las flores' uses plural 'gustan' for plural flowers."},{"p":"Fill in: 'A ellos les ___ el fútbol' (They like soccer).","a":"gusta","w":["gustan","gustamos","gusto"],"h":"'El fútbol' is singular.","e":"'El fútbol' is singular, so use 'gusta'."},{"p":"Which pronoun means 'to me' with gustar?","a":"me","w":["te","le","nos"],"h":"It's the first person singular.","e":"'Me' is the indirect pronoun for 'I like' (me gusta)."},{"p":"How do you say 'We love the beach' in Spanish?","a":"Nos encanta la playa","w":["Nos encantan la playa","Nos gustamos la playa","Me encanta la playa"],"h":"'We' uses 'nos'; 'la playa' is singular.","e":"'Nos encanta la playa' means 'we love the beach'."},{"p":"Fill in: 'No me ___ las arañas' (I don't like spiders).","a":"gustan","w":["gusta","gusto","gustas"],"h":"'Las arañas' is plural.","e":"Even in the negative, plural nouns take 'gustan'."},{"p":"What does '¿Te gusta el español?' mean?","a":"Do you like Spanish?","w":["Do you speak Spanish?","Are you Spanish?","Do you love Spanish?"],"h":"It's a yes/no question about liking.","e":"'¿Te gusta el español?' asks 'do you like Spanish?'."},{"p":"Complete to say 'Yes, I like it': 'Sí, ___ gusta.'","a":"me","w":["te","le","nos"],"h":"You are talking about yourself.","e":"To say 'I like it' you use 'me gusta'."}],"sp.5.tiempo":[{"p":"How do you say 'It is sunny' in Spanish?","a":"Hace sol","w":["Hace frío","Hace viento","Está sol"],"h":"Uses 'hace' plus a noun.","e":"'Hace sol' means 'it is sunny'."},{"p":"What does 'Hace frío' mean?","a":"It is cold","w":["It is hot","It is windy","It is sunny"],"h":"Think of winter weather.","e":"'Hace frío' means 'it is cold'."},{"p":"How do you say 'It is hot' in Spanish?","a":"Hace calor","w":["Hace frío","Hace sol","Está caliente"],"h":"Summer weather, uses 'hace'.","e":"'Hace calor' means 'it is hot'."},{"p":"What does 'Llueve' mean?","a":"It is raining","w":["It is snowing","It is windy","It is cloudy"],"h":"Bring an umbrella.","e":"'Llueve' means 'it rains / it is raining'."},{"p":"How do you say 'It is snowing' in Spanish?","a":"Nieva","w":["Llueve","Hace sol","Truena"],"h":"White and cold, in winter.","e":"'Nieva' means 'it is snowing'."},{"p":"What season is 'el verano'?","a":"summer","w":["winter","spring","fall"],"h":"The hottest season.","e":"'El verano' is summer."},{"p":"What season is 'el invierno'?","a":"winter","w":["summer","spring","autumn"],"h":"The coldest season.","e":"'El invierno' is winter."},{"p":"How do you say 'spring' in Spanish?","a":"la primavera","w":["el otoño","el verano","el invierno"],"h":"Flowers bloom in this season.","e":"'La primavera' is spring."},{"p":"What season is 'el otoño'?","a":"fall/autumn","w":["spring","summer","winter"],"h":"Leaves change color.","e":"'El otoño' is autumn/fall."},{"p":"How do you say 'It is windy' in Spanish?","a":"Hace viento","w":["Hace calor","Llueve","Hace fresco"],"h":"Uses 'hace' plus the word for wind.","e":"'Hace viento' means 'it is windy'."},{"p":"What does '¿Qué tiempo hace?' mean?","a":"What is the weather like?","w":["What time is it?","What season is it?","How are you?"],"h":"It asks about weather, not the clock.","e":"'¿Qué tiempo hace?' asks about the weather."},{"p":"Fill in: 'En ___ hace mucho frío y nieva.'","a":"invierno","w":["verano","primavera","otoño"],"h":"The cold, snowy season.","e":"In 'invierno' (winter) it is cold and snows."},{"p":"What does 'Está nublado' mean?","a":"It is cloudy","w":["It is sunny","It is raining","It is clear"],"h":"The sky is gray, no sun.","e":"'Está nublado' means 'it is cloudy'."},{"p":"How do you say 'It is cool' in Spanish?","a":"Hace fresco","w":["Hace calor","Hace frío","Hace sol"],"h":"Between warm and cold.","e":"'Hace fresco' means 'it is cool'."},{"p":"Fill in: 'En ___ hace calor y vamos a la playa.'","a":"verano","w":["invierno","otoño","primavera"],"h":"The hot season for the beach.","e":"In 'verano' (summer) it is hot."},{"p":"How do you say 'summer' in Spanish?","a":"el verano","w":["el invierno","la primavera","el otoño"],"h":"The warmest season.","e":"'El verano' means 'summer'."}],"sp.7.objetos":[{"p":"Replace the object: '¿Ves la película?' → 'Sí, ___ veo.'","a":"la","w":["lo","le","las"],"h":"'La película' is feminine singular.","e":"The direct object 'la película' is replaced by 'la'."},{"p":"Replace the object: '¿Compras el libro?' → 'Sí, ___ compro.'","a":"lo","w":["la","le","los"],"h":"'El libro' is masculine singular.","e":"'El libro' is replaced by the masculine direct object 'lo'."},{"p":"Replace the object: '¿Tienes los boletos?' → 'Sí, ___ tengo.'","a":"los","w":["las","les","lo"],"h":"'Los boletos' is masculine plural.","e":"'Los boletos' becomes the direct object 'los'."},{"p":"Fill in the indirect pronoun: '___ doy el regalo a ti' (I give the gift to you).","a":"Te","w":["Me","Le","Nos"],"h":"'To you' (informal) is 'te'.","e":"The indirect object 'to you' is 'te'."},{"p":"What does 'Lo veo' mean?","a":"I see it/him","w":["I see her","I see them","He sees me"],"h":"'Lo' is masculine singular.","e":"'Lo veo' means 'I see it' or 'I see him'."},{"p":"Fill in the indirect pronoun: '___ escribo una carta a mi madre' (I write a letter to my mother).","a":"Le","w":["La","Les","Me"],"h":"'To her' (one person) uses 'le'.","e":"The indirect object 'to my mother' is 'le'."},{"p":"Place the pronoun correctly: 'las' + 'Quiero comer' (I want to eat them).","a":"Las quiero comer","w":["Quiero las comer","Quiero comer las","Las las quiero comer"],"h":"It goes before the conjugated verb.","e":"The pronoun goes before the conjugated verb: 'las quiero comer' (or 'quiero comerlas')."},{"p":"Attach the pronoun to the infinitive: 'Voy a comprar (el)' → 'Voy a ___.'","a":"comprarlo","w":["lo comprar","comprar lo","comprarle"],"h":"Attach 'lo' to the end of the infinitive.","e":"With an infinitive, the pronoun attaches to the end: 'comprarlo'."},{"p":"Replace the direct object: 'Doy el libro a Juan' → 'Se ___ doy.'","a":"lo","w":["le","la","los"],"h":"'El libro' is masculine singular; 'le' has become 'se'.","e":"'A Juan' becomes 'se' and 'el libro' becomes 'lo': 'se lo doy'."},{"p":"Fill in the indirect pronoun: '___ dan un premio a nosotros' (They give a prize to us).","a":"Nos","w":["Les","Me","Te"],"h":"'To us' is 'nos'.","e":"The indirect object 'to us' is 'nos'."},{"p":"What does 'Te llamo mañana' mean?","a":"I'll call you tomorrow","w":["You call me tomorrow","I'll call him tomorrow","We'll call you tomorrow"],"h":"'Te' is the object, 'llamo' is 'I call'.","e":"'Te llamo mañana' means 'I'll call you tomorrow'."},{"p":"Replace the object: '¿Conoces a María?' → 'Sí, ___ conozco.'","a":"la","w":["lo","le","las"],"h":"María is feminine singular.","e":"'A María' is replaced by the direct object 'la'."},{"p":"Fill in the indirect pronoun: '___ compro flores a ellas' (I buy flowers for them).","a":"Les","w":["Le","Las","Nos"],"h":"'To them' (plural) uses 'les'.","e":"The indirect object 'to them' is 'les'."},{"p":"Attach the pronoun in this command: 'Compra (lo)' (Buy it!).","a":"Cómpralo","w":["Lo compra","Compra lo","Lo cómpralo"],"h":"In affirmative commands it attaches to the end.","e":"In an affirmative command the pronoun attaches: 'cómpralo'."},{"p":"Replace the object: '¿Escuchas la canción?' → 'No, no ___ escucho.'","a":"la","w":["lo","le","las"],"h":"'La canción' is feminine singular; the pronoun goes before the verb.","e":"In the negative, 'la' still goes before the verb: 'no la escucho'."},{"p":"What does 'Nos ayudan' mean?","a":"They help us","w":["We help them","They help me","We help you"],"h":"'Nos' means 'us'.","e":"'Nos ayudan' means 'they help us'."}],"sp.7.comparativos":[{"p":"Fill in: 'Ana es ___ alta ___ Luis' (Ana is taller than Luis).","a":"más... que","w":["menos... que","tan... como","más... como"],"h":"Use 'more... than'.","e":"'Más... que' means 'more... than'."},{"p":"Fill in: 'Este coche es ___ caro ___ el otro' (less expensive than).","a":"menos... que","w":["más... que","tan... como","menos... como"],"h":"Use 'less... than'.","e":"'Menos... que' means 'less... than'."},{"p":"Fill in: 'Ella es ___ inteligente ___ su hermano' (as intelligent as).","a":"tan... como","w":["más... que","tan... que","menos... como"],"h":"Equality: 'as... as'.","e":"'Tan... como' expresses equality, 'as... as'."},{"p":"How do you say 'better' in Spanish (irregular comparative)?","a":"mejor","w":["más bueno","más mejor","peor"],"h":"The irregular form of 'bueno'.","e":"'Mejor' means 'better' and replaces 'más bueno'."},{"p":"How do you say 'worse' in Spanish (irregular comparative)?","a":"peor","w":["más malo","mejor","más peor"],"h":"The irregular form of 'malo'.","e":"'Peor' means 'worse' and replaces 'más malo'."},{"p":"Fill in: 'María es la ___ alta de la clase' (the tallest).","a":"más","w":["menos","tan","mejor"],"h":"Superlative: 'the most'.","e":"'La más alta' means 'the tallest' (superlative)."},{"p":"What does 'Es el mejor jugador del equipo' mean?","a":"He is the best player on the team","w":["He is a better player than the team","He is the worst player on the team","He is as good as the team"],"h":"'El mejor' is a superlative.","e":"'El mejor jugador' means 'the best player'."},{"p":"Fill in: 'Tengo ___ libros ___ tú' (more books than you).","a":"más... que","w":["tan... como","menos... que","más... como"],"h":"Use 'more... than'.","e":"'Más... que' means 'more... than'."},{"p":"Choose the correct form: 'Mi nota es ___ que la tuya' (better).","a":"mejor","w":["más buena","más mejor","tan buena"],"h":"Use the irregular comparative.","e":"'Mejor que' means 'better than'."},{"p":"Fill in: 'Hoy hace ___ calor ___ ayer' (more heat than yesterday).","a":"más... que","w":["tan... como","menos... como","más... como"],"h":"Use 'more... than'.","e":"'Más calor que' means 'more heat than'."},{"p":"How do you say 'the most expensive' for a feminine noun in Spanish?","a":"la más cara","w":["la más caro","el más caro","la menos cara"],"h":"Superlative with feminine agreement.","e":"'La más cara' means 'the most expensive' for a feminine noun."},{"p":"What does 'Pedro corre tan rápido como Juan' mean?","a":"Pedro runs as fast as Juan","w":["Pedro runs faster than Juan","Pedro runs slower than Juan","Pedro runs the fastest"],"h":"'Tan... como' shows equality.","e":"'Tan rápido como' means 'as fast as'."},{"p":"Fill in: 'Este examen es ___ difícil ___ el anterior' (as difficult as).","a":"tan... como","w":["más... que","menos... que","tan... que"],"h":"Equality of difficulty.","e":"'Tan... como' means 'as... as'."},{"p":"How do you say 'younger' about a person in Spanish (irregular)?","a":"menor","w":["más menor","más joven que","peor"],"h":"The irregular comparative of age.","e":"'Menor' means 'younger' (irregular comparative of age)."},{"p":"Fill in: 'Es el estudiante ___ trabajador de todos' (the most hard-working).","a":"más","w":["menos","tan","mejor"],"h":"Superlative 'the most'.","e":"'El más trabajador' means 'the most hard-working'."},{"p":"What does 'Ella es mayor que su hermano' mean?","a":"She is older than her brother","w":["She is younger than her brother","She is taller than her brother","She is the oldest"],"h":"'Mayor' is the irregular comparative for age.","e":"'Mayor que' means 'older than'."}],"e.4.context":[{"p":"Read the sentence: \"The arid desert had no water for miles, so the plants were dry and brittle.\" What does the word \"arid\" mean?","a":"dry","w":["wet","cold","green"],"h":"Look at the clues \"no water\" and \"dry.\"","e":"Nearby words like \"no water\" and \"dry\" are context clues that show arid means dry."},{"p":"In the word \"untie,\" the prefix \"un-\" means:","a":"not or the opposite of","w":["again","before","very"],"h":"un- reverses or undoes the action.","e":"The prefix un- means \"not\" or \"the opposite of,\" so untie means to reverse tying."},{"p":"What does the word \"reread\" mean?","a":"to read again","w":["to read before","to not read","to read quickly"],"h":"The prefix re- means again.","e":"The prefix re- means \"again,\" so reread means to read something again."},{"p":"Read the sentence: \"Please preheat the oven before you bake.\" What does the prefix \"pre-\" mean?","a":"before","w":["after","again","not"],"h":"pre- points to a time earlier than something.","e":"The prefix pre- means \"before,\" so preheat means to heat beforehand."},{"p":"What does the word \"disagree\" mean?","a":"to not agree","w":["to agree again","to agree fully","to agree before"],"h":"dis- means not or the opposite.","e":"The prefix dis- means \"not\" or \"opposite of,\" so disagree means to not agree."},{"p":"What does the word \"joyful\" mean?","a":"full of joy","w":["without joy","a little joy","joy again"],"h":"The suffix -ful means full of.","e":"The suffix -ful means \"full of,\" so joyful means full of joy."},{"p":"What does the word \"fearless\" mean?","a":"without fear","w":["full of fear","a little fear","fear again"],"h":"The suffix -less means without.","e":"The suffix -less means \"without,\" so fearless means without fear."},{"p":"In the sentence \"She spoke softly,\" the suffix \"-ly\" in \"softly\" shows the word tells:","a":"how something is done","w":["when it happened","where it happened","who did it"],"h":"-ly often makes a word that tells how.","e":"The suffix -ly often turns a word into one that tells how an action is done."},{"p":"The word \"action\" comes from the base word \"act.\" The suffix \"-tion\" turns the word into:","a":"a noun (a thing or idea)","w":["an action word","a describing word","a question"],"h":"-tion names a thing or idea.","e":"The suffix -tion changes a verb into a noun that names a thing or idea."},{"p":"What is the base word in \"replaying\"?","a":"play","w":["replay","playing","re"],"h":"Remove the prefix and the ending.","e":"Removing the prefix re- and the ending -ing leaves the base word play."},{"p":"Read the sentence: \"Trevor was so famished after the long hike that he ate three sandwiches.\" What does \"famished\" mean?","a":"very hungry","w":["very tired","very happy","very full"],"h":"He ate three sandwiches right away.","e":"The clue that he ate three sandwiches shows famished means very hungry."},{"p":"Read the sentence: \"Unlike his cheerful sister, Max was quite glum.\" What does \"glum\" mean?","a":"gloomy or sad","w":["cheerful","funny","loud"],"h":"The word \"unlike\" signals an opposite.","e":"The word \"unlike\" signals that glum is the opposite of cheerful, meaning sad."},{"p":"What does the word \"misspell\" mean?","a":"to spell wrongly","w":["to spell again","to spell before","to not spell"],"h":"The prefix mis- means wrongly.","e":"The prefix mis- means \"wrongly,\" so misspell means to spell incorrectly."},{"p":"In the sentence \"A teacher is a person who teaches,\" the suffix \"-er\" means:","a":"a person who does something","w":["more than","without","before"],"h":"-er can name the one who does an action.","e":"The suffix -er can mean \"a person who,\" so a teacher is one who teaches."},{"p":"Read the sentence: \"The bridge was so fragile that engineers worried it might collapse.\" What does \"fragile\" mean?","a":"easily broken","w":["very strong","very wide","brand new"],"h":"They worried it might collapse.","e":"The worry that it might collapse shows fragile means easily broken."},{"p":"The word \"unhelpful\" is made of un- + help + -ful. What does it mean?","a":"not full of help","w":["full of help","help again","a person who helps"],"h":"Combine \"not\" with \"full of help.\"","e":"Combining un- (not) with helpful (full of help) makes unhelpful mean not full of help."}],"e.4.mainidea":[{"p":"Read: \"Bees are important. They help flowers grow by carrying pollen. They also make honey that people eat.\" What is the main idea?","a":"Bees are important","w":["Bees make honey","Bees carry pollen","People eat honey"],"h":"Which sentence covers the whole paragraph?","e":"The main idea is the big point that all of the details support, that bees are important."},{"p":"In that same paragraph, \"They make honey that people eat\" is an example of a:","a":"supporting detail","w":["main idea","title","summary"],"h":"It gives one specific piece of information.","e":"A supporting detail gives specific information that backs up the main idea."},{"p":"Read: \"First, gather your materials. Next, cut the paper. Then, glue the pieces. Finally, let it dry.\" What text structure is this?","a":"sequence","w":["compare and contrast","cause and effect","problem and solution"],"h":"Notice words like first, next, then, finally.","e":"Words like first, next, and finally signal a sequence structure that lists steps in order."},{"p":"Read: \"Because it rained all day, the soccer game was canceled.\" What is the effect?","a":"the soccer game was canceled","w":["it rained all day","the players were sad","the field was muddy"],"h":"The effect is what happened as a result.","e":"The effect is the result, so the canceled game is the effect of the rain."},{"p":"In the sentence \"Because it rained all day, the soccer game was canceled,\" what is the cause?","a":"it rained all day","w":["the game was canceled","the players went home","the sun came out"],"h":"The cause is the reason something happened.","e":"The cause is the reason something happens, which here is the rain."},{"p":"Read: \"Cats and dogs are both popular pets, but cats are more independent while dogs need more attention.\" What text structure is this?","a":"compare and contrast","w":["sequence","problem and solution","cause and effect"],"h":"It shows how two things are alike and different.","e":"Compare and contrast shows how two things are similar and different, like cats and dogs."},{"p":"Read: \"The library was too noisy, so the librarian created a quiet room for reading.\" What text structure is this?","a":"problem and solution","w":["sequence","compare and contrast","description"],"h":"There is a trouble and a way to fix it.","e":"Problem and solution presents a difficulty and a way to fix it, like the noisy library."},{"p":"Which is the BEST summary of: \"The class planted seeds, watered them daily, and watched them grow into tall sunflowers\"?","a":"The class grew sunflowers by planting and caring for seeds","w":["The class watered seeds every day","Sunflowers are very tall","The class enjoyed plants"],"h":"A summary briefly covers the whole thing.","e":"A good summary briefly retells the most important ideas of the whole text."},{"p":"Read: \"Sea turtles face many dangers. Plastic trash can trap them. Losing beaches means fewer nesting spots. Some are caught in fishing nets.\" What is the main idea?","a":"Sea turtles face many dangers","w":["Plastic traps turtles","Turtles nest on beaches","Fishing nets are large"],"h":"What do ALL the details prove together?","e":"The main idea is the general point that all of the listed dangers support."},{"p":"Which words best signal a cause-and-effect text structure?","a":"because, so, therefore","w":["first, next, last","same, different, alike","problem, fix, solve"],"h":"Think about reason and result.","e":"Words like because, so, and therefore signal a cause-and-effect structure."},{"p":"A paragraph is all about \"recycling.\" The word \"recycling\" is the:","a":"topic","w":["main idea","detail","summary"],"h":"The topic is the subject in a word or phrase.","e":"The topic is what a text is about in a word or phrase, while the main idea is the full point."},{"p":"In a set of directions, which word usually signals the LAST step?","a":"finally","w":["first","next","before"],"h":"Which word ends a sequence?","e":"The word finally usually signals the last step in a sequence."},{"p":"Which word signals a contrast, showing a difference between two things?","a":"however","w":["because","first","then"],"h":"Contrast words point out differences.","e":"Signal words like however, but, and unlike point out differences in a compare-and-contrast text."},{"p":"A paragraph's main idea is \"Exercise keeps your body healthy.\" Which detail does NOT belong?","a":"My cousin's cat is named Whiskers","w":["Running makes your heart strong","Stretching keeps muscles loose","Walking helps you stay fit"],"h":"Which sentence is off-topic?","e":"A supporting detail must connect to the main idea, and the cat's name does not."},{"p":"An author wants to explain how a butterfly changes from egg to adult in order. Which text structure fits best?","a":"sequence","w":["compare and contrast","problem and solution","persuasion"],"h":"Think about steps in order over time.","e":"Explaining stages in order over time fits a sequence structure."},{"p":"Which sentence would make the BEST main-idea sentence for a paragraph about how volcanoes form?","a":"Volcanoes form when melted rock rises to Earth's surface","w":["Lava is very hot","Some volcanoes are on islands","Ash can fill the sky"],"h":"Which sentence is broad enough to cover the topic?","e":"The best main-idea sentence is broad enough to introduce the whole paragraph, not just one detail."}],"e.6.authorpov":[{"p":"Read: \"You should recycle because it saves our planet for future generations.\" What is the author's main purpose?","a":"to persuade","w":["to inform","to entertain","to describe"],"h":"Is the author trying to change your mind?","e":"When an author tries to convince you to do or believe something, the purpose is to persuade."},{"p":"Read: \"The human heart beats about 100,000 times each day.\" What is the author's purpose?","a":"to inform","w":["to persuade","to entertain","to warn"],"h":"Facts that teach the reader.","e":"Text that gives facts to teach the reader has the purpose to inform."},{"p":"Read: \"The purple dragon sneezed and accidentally set his own tail on fire.\" What is the author's purpose?","a":"to entertain","w":["to inform","to persuade","to instruct"],"h":"Is it a fun, imaginative story?","e":"A funny or imaginative story is written to entertain the reader."},{"p":"Read: \"I could not believe what I saw when I opened the door.\" What point of view is this?","a":"first person","w":["second person","third-person limited","third-person omniscient"],"h":"Look for the pronouns I and me.","e":"First-person point of view uses pronouns like I and me to tell the story."},{"p":"Read: \"She opened the door and gasped at what she found.\" What point of view is this?","a":"third person","w":["first person","second person","none of these"],"h":"Look for she, he, or they.","e":"Third-person point of view uses pronouns like she, he, and they."},{"p":"Read: \"You walk into the room and feel the cold air on your skin.\" What point of view is this?","a":"second person","w":["first person","third person","omniscient"],"h":"The narrator speaks directly to \"you.\"","e":"Second-person point of view speaks directly to the reader using you."},{"p":"A narrator who knows the thoughts and feelings of EVERY character is using:","a":"third-person omniscient","w":["third-person limited","first person","second person"],"h":"Omniscient means all-knowing.","e":"A third-person omniscient narrator knows the thoughts and feelings of all characters."},{"p":"Which sentence shows the author's bias rather than a fact?","a":"Soccer is clearly the best sport ever invented","w":["Soccer is played with a round ball","A soccer match has two halves","Field players cannot use their hands"],"h":"Which one is an opinion stated as truth?","e":"Bias shows when an author states an opinion as if it were fact, like calling soccer the best sport."},{"p":"An article lists the steps to plant a garden and states which plants are poisonous. Its main purpose is to:","a":"inform","w":["entertain","persuade","amuse"],"h":"It gives facts and directions.","e":"Giving directions and facts serves the purpose to inform."},{"p":"A story is told by a nervous new student on the first day of school. Because it is first person, the reader mainly learns:","a":"that one student's thoughts and feelings","w":["every student's thoughts","the teacher's secret plans","future events not yet known"],"h":"First person limits us to one mind.","e":"A first-person narrator limits the reader to that single character's thoughts and feelings."},{"p":"Read: \"Everyone knows our town needs a new park.\" This persuades readers by:","a":"suggesting everybody already agrees","w":["giving exact statistics","telling a joke","describing a peaceful scene"],"h":"\"Everyone knows\" pressures you to agree.","e":"Claiming \"everyone knows\" pressures readers to agree by suggesting they would be alone if they didn't."},{"p":"Which sentence is an opinion?","a":"Winter is the most beautiful season","w":["Winter has fewer daylight hours","Snow is frozen water","Some animals hibernate in winter"],"h":"Which one cannot be proven true?","e":"An opinion states a personal belief that cannot be proven, like which season is most beautiful."},{"p":"Read: \"The greedy company raised prices again.\" The word \"greedy\" shows the author is:","a":"expressing a negative opinion","w":["stating a neutral fact","describing an exact price","giving a statistic"],"h":"Is the word \"greedy\" neutral?","e":"A loaded word like greedy reveals the author's negative opinion rather than a neutral fact."},{"p":"An author wants readers to donate to an animal shelter. The BEST purpose to choose is to:","a":"persuade","w":["entertain","inform only","confuse"],"h":"The author wants readers to take action.","e":"Because the author wants readers to act, the purpose is to persuade."},{"p":"A story is narrated by a character who often lies to others. Readers should be careful because the narrator may be:","a":"unreliable","w":["omniscient","second person","completely factual"],"h":"Can we fully trust this narrator?","e":"A narrator who lies may be unreliable, so readers should question what he reports."},{"p":"One author writes a scary campfire tale about wolves; another writes an encyclopedia entry about wolves. Their differing purposes are best described as:","a":"entertain versus inform","w":["persuade versus entertain","inform versus persuade","describe versus persuade"],"h":"Story versus facts.","e":"A scary tale aims to entertain while an encyclopedia entry aims to inform, showing purpose can differ on the same topic."}],"e.6.evidence":[{"p":"Claim: \"Maria is a hard worker.\" Which quote best supports this claim?","a":"\"Maria stayed after class every day to finish her project.\"","w":["\"Maria has brown hair.\"","\"Maria likes pizza.\"","\"Maria has a younger brother.\""],"h":"Which quote shows effort?","e":"The best evidence directly shows the claim is true, here that Maria works hard by staying late."},{"p":"Which statement is evidence rather than an opinion?","a":"The thermometer read 95 degrees at noon","w":["It was a miserably hot day","Summer is the worst season","Nobody enjoys the heat"],"h":"Which statement can be checked or measured?","e":"Evidence can be checked or measured, while opinions express feelings."},{"p":"Claim: \"Exercise improves memory.\" Which detail is relevant support?","a":"Students who ran before tests remembered more words","w":["Running shoes come in many colors","The gym opens at six o'clock","Some people dislike jogging"],"h":"Which detail links exercise to memory?","e":"Relevant evidence connects directly to the claim, here linking exercise to memory."},{"p":"Claim: \"The new library helps students.\" Which detail is IRRELEVANT?","a":"The library building is painted blue","w":["It offers free tutoring","Students can borrow laptops","It stays open late for studying"],"h":"Which detail does not show help?","e":"Irrelevant details do not support the claim, and the paint color says nothing about helping students."},{"p":"\"Textual evidence\" means:","a":"details or quotations taken from the text","w":["your own personal guesses","a retelling of the whole book","the author's biography"],"h":"Evidence comes from the words on the page.","e":"Textual evidence is specific information or quotations drawn from the text itself."},{"p":"Claim: \"The storm was dangerous.\" Which quote gives the strongest support?","a":"\"Winds tore roofs off houses and flooded the streets.\"","w":["\"The sky looked gray.\"","\"People stayed inside.\"","\"It rained in the morning.\""],"h":"Which quote shows real danger?","e":"The strongest evidence shows clear danger, like winds tearing off roofs."},{"p":"Claim: \"Dogs can be trained easily.\" Which quote does NOT support it?","a":"\"Cats often ignore their owners' commands.\"","w":["\"Most dogs learn to sit in a week.\"","\"Trainers say dogs love to please.\"","\"Puppies quickly learn their names.\""],"h":"Is this quote even about dogs?","e":"A quote about cats does not support a claim about dogs."},{"p":"Putting a text's idea into your own words is called:","a":"paraphrasing","w":["quoting","copying the whole book","plagiarizing"],"h":"Your words, but the same idea.","e":"Paraphrasing restates a text's idea in your own words rather than copying it exactly."},{"p":"Which phrase best introduces a quotation in an essay?","a":"According to the text,","w":["In my opinion,","I just think that","Everybody always says"],"h":"Which phrase points back to the source?","e":"Phrases like \"according to the text\" signal that the evidence comes from the source."},{"p":"A student claims \"The town needs a stoplight\" but only says \"My friend agrees.\" This support is weak because it:","a":"is an opinion, not factual evidence","w":["is far too long","uses a direct quotation","names the town"],"h":"Does a friend's agreement prove the need?","e":"A friend's agreement is opinion, not the factual evidence needed to prove a claim."},{"p":"Claim: \"The author admires the ocean.\" Which quote is the best evidence?","a":"\"She wrote that the waves filled her with wonder and peace.\"","w":["\"She lives near a lake.\"","\"The book has ten chapters.\"","\"She once got seasick.\""],"h":"Which quote shows admiration?","e":"Evidence should match the claim, and wonder and peace show admiration."},{"p":"In \"Recess helps students focus; a study found grades rose after schools added recess,\" the EVIDENCE is:","a":"the study finding that grades rose after adding recess","w":["\"Recess helps students focus\"","\"students need recess\"","\"recess is fun\""],"h":"Which part proves the other part?","e":"The study finding is the evidence that supports the claim that recess helps focus."},{"p":"Claim: \"Sharks are misunderstood.\" Which quote is the stronger support?","a":"\"Records show shark attacks are extremely rare.\"","w":["\"Sharks have many sharp teeth.\"","\"Sharks live in the ocean.\"","\"Movies show scary sharks.\""],"h":"Which quote challenges the fear of sharks?","e":"The rarity of attacks is strong evidence that sharks are misunderstood."},{"p":"A complete text-evidence answer includes the evidence AND:","a":"reasoning that explains how the evidence proves the claim","w":["only the page number","a much longer quote","a different topic"],"h":"Evidence alone is not enough.","e":"Strong answers pair evidence with reasoning that explains how it supports the claim."},{"p":"Choosing only the quotes that agree with you and ignoring the rest is a problem because it:","a":"gives an unfair, incomplete picture","w":["makes the essay shorter","uses too many facts","is always required"],"h":"Is it fair to hide the other quotes?","e":"Using only agreeable quotes and ignoring others gives readers an unfair, incomplete picture."},{"p":"Which sentence cites evidence most precisely?","a":"On page 12, the narrator says she \"hadn't eaten in two days.\"","w":["Somewhere the book talks about hunger.","The character seems hungry to me.","I feel like the character is hungry."],"h":"Which names where it is and quotes exactly?","e":"Precise citation names the location and quotes the text exactly, as on page 12."}],"e.9.roots":[{"p":"The root \"bio\" (as in biology) means:","a":"life","w":["earth","self","book"],"h":"Think of biology, the study of living things.","e":"The Greek root bio means life, as in biology, the study of living things."},{"p":"The words \"geography\" and \"geology\" share the root \"geo,\" which means:","a":"earth","w":["life","star","water"],"h":"Think of the ground beneath you.","e":"The root geo means earth, as seen in geography and geology."},{"p":"The root \"tele\" (as in telescope, telephone) means:","a":"far or distant","w":["sound","sight","near"],"h":"A telescope sees things far away.","e":"The Greek root tele means far or distant, as in telescope."},{"p":"A word with the root \"port\" (as in transport, portable) relates to:","a":"carrying","w":["writing","seeing","hearing"],"h":"To transport is to move something.","e":"The Latin root port means to carry, as in portable and transport."},{"p":"The root \"dict\" (as in dictate, predict) means:","a":"to say or speak","w":["to write","to see","to build"],"h":"To dictate is to speak words aloud.","e":"The Latin root dict means to say or speak, as in dictate and predict."},{"p":"The words \"scribe\" and \"manuscript\" share a root that means:","a":"to write","w":["to read","to speak","to carry"],"h":"A scribe copies written text.","e":"The root scrib or script means to write, as in manuscript."},{"p":"The root \"aud\" (as in audible, audience) relates to:","a":"hearing","w":["seeing","speaking","moving"],"h":"An audience listens.","e":"The Latin root aud means to hear, as in audible and audience."},{"p":"The root \"spect\" (as in inspect, spectator) means:","a":"to look or watch","w":["to hear","to build","to carry"],"h":"A spectator watches an event.","e":"The Latin root spect means to look or watch, as in inspect and spectator."},{"p":"The root \"struct\" (as in construct, structure) means:","a":"to build","w":["to break","to see","to write"],"h":"Construction crews build things.","e":"The Latin root struct means to build, as in construct and structure."},{"p":"The root \"phon\" (as in telephone, symphony) relates to:","a":"sound","w":["light","distance","life"],"h":"A phone carries sound.","e":"The Greek root phon means sound, as in telephone and symphony."},{"p":"Using its roots, the word \"telephone\" combines \"tele\" and \"phon\" to literally mean:","a":"distant sound","w":["distant sight","life sound","earth writing"],"h":"Combine far with sound.","e":"Combining tele (far) and phon (sound) gives the literal meaning distant sound."},{"p":"A \"biography\" combines \"bio\" (life) with \"graph\" (writing). It literally means:","a":"writing about a life","w":["study of the earth","a distant picture","a spoken word"],"h":"Combine life with writing.","e":"Biography combines bio (life) and graph (writing) to mean writing about a life."},{"p":"Based on its root, a \"dictionary\" is a book that mainly deals with:","a":"words and what they mean or say","w":["maps of the earth","pictures of stars","sounds of music"],"h":"The root dict means say or speak.","e":"Because dict means to say or speak, a dictionary deals with words and their meanings."},{"p":"A \"circumspect\" person (circum = around, spect = look) is one who:","a":"looks around carefully before acting","w":["builds structures quickly","speaks very loudly","travels very far away"],"h":"Combine around with look.","e":"Circumspect combines around and look, describing someone who looks around carefully, meaning cautious."},{"p":"To \"deport\" someone (de = away, port = carry) means to:","a":"carry or send them away","w":["write about them","listen to them","build something for them"],"h":"Combine away with carry.","e":"Deport combines de (away) and port (carry), meaning to carry someone away from a country."},{"p":"Which word does NOT share the \"sound\" root \"phon\"?","a":"portable","w":["symphony","phonics","megaphone"],"h":"Which word's root means carry, not sound?","e":"Portable uses port (carry), not phon (sound), so it does not belong with the sound words."}],"e.9.claims":[{"p":"In an argument, a \"claim\" is:","a":"the main point the writer wants readers to accept","w":["a random fact","a question","the title of the piece"],"h":"What is the writer arguing for?","e":"A claim is the central position or point an argument tries to prove."},{"p":"A \"counterclaim\" is:","a":"an opposing view the writer addresses","w":["the writer's own evidence","a summary of the essay","a dictionary definition"],"h":"It argues against the writer's claim.","e":"A counterclaim presents the opposing side that the writer then responds to."},{"p":"In an argument, evidence is used to:","a":"support the claim with facts or examples","w":["state a personal opinion","introduce the topic","confuse the reader"],"h":"What backs up the main point?","e":"Evidence supports a claim using facts, data, or examples."},{"p":"In an argument, \"reasoning\" does what?","a":"explains how the evidence supports the claim","w":["lists additional claims","provides the title","states only a fact"],"h":"It connects evidence to the claim.","e":"Reasoning is the explanation that links evidence to the claim."},{"p":"\"Don't listen to her plan; she's a terrible dresser.\" This is which fallacy?","a":"ad hominem","w":["false dilemma","straw man","hasty generalization"],"h":"Is the attack on the plan or the person?","e":"Ad hominem attacks the person instead of addressing their actual argument."},{"p":"A speaker twists an opponent's view into a weaker version, then attacks that version. This is:","a":"a straw man fallacy","w":["ad hominem","false dilemma","circular reasoning"],"h":"They attack a fake version of the argument.","e":"A straw man fallacy misrepresents an opponent's position to make it easier to attack."},{"p":"\"Either we ban all cars or the planet is doomed.\" This is which fallacy?","a":"false dilemma","w":["ad hominem","straw man","appeal to authority"],"h":"Are there really only two choices?","e":"A false dilemma wrongly presents only two options when more exist."},{"p":"Which is the STRONGEST support for the claim \"Our school should start later\"?","a":"A sleep study showing teens learn better after more rest","w":["My cousin hates mornings","A teacher looked tired today","I dislike waking up early"],"h":"Which support is credible and relevant?","e":"A relevant, credible study is stronger evidence than personal preferences."},{"p":"Which of these is a debatable claim rather than a verifiable fact?","a":"The school day should be shortened","w":["The school day is seven hours long","Classes begin at 8 a.m.","There are 30 desks in the room"],"h":"Which one could reasonably be argued?","e":"A claim is debatable and calls for support, unlike a verifiable fact."},{"p":"In an essay arguing FOR uniforms, which sentence is the counterclaim?","a":"Some argue that uniforms limit students' self-expression","w":["Uniforms reduce distractions","Uniforms save families money","Uniforms create a sense of unity"],"h":"Which sentence states the opposing side?","e":"The counterclaim voices the opposing view, that uniforms limit self-expression."},{"p":"\"This book is the best because it is better than all the others.\" This reasoning is flawed because it:","a":"restates the claim instead of proving it","w":["attacks a person","offers only two choices","cites a real study"],"h":"Does the reason add any actual proof?","e":"Circular reasoning simply restates the claim as its own support without real proof."},{"p":"\"I met two rude tourists, so all tourists are rude.\" This is which fallacy?","a":"hasty generalization","w":["false dilemma","ad hominem","straw man"],"h":"A big conclusion from too few cases.","e":"A hasty generalization draws a broad conclusion from too little evidence."},{"p":"Claim: \"Video games cause violence.\" Evidence: \"Violent crime and game sales both rose.\" The weakness is that:","a":"correlation does not prove causation","w":["the evidence is a direct quote","there is no claim at all","it relies on statistics"],"h":"Does rising together prove one caused the other?","e":"Two things rising together is correlation, which does not prove that one caused the other."},{"p":"\"A famous actor says this medicine works, so it must.\" The problem is that the source is:","a":"not an expert on the topic","w":["too scientific","a licensed doctor","irrelevant to being famous"],"h":"Is a movie actor a medical expert?","e":"Citing a celebrity who lacks relevant expertise is a misuse of authority."},{"p":"After a counterclaim that \"uniforms are expensive,\" the best rebuttal offers:","a":"evidence that uniforms cost less than a regular wardrobe over time","w":["an insult about people who disagree","a claim with no support","a new, unrelated topic"],"h":"Answer the objection with evidence.","e":"A strong rebuttal answers the counterclaim with relevant evidence and reasoning."},{"p":"Which argument is the most logically sound?","a":"Recycling reduces landfill waste; data show towns with programs cut waste by 30%, so our town should recycle","w":["Only fools would oppose recycling","We must recycle or the earth will end","My neighbor recycles, so it must be pointless"],"h":"Which uses relevant evidence and valid reasoning?","e":"A sound argument links a clear claim to relevant evidence and valid reasoning without fallacies."}],"e.11.themesym":[{"p":"Which of the following is a THEME rather than a topic?","a":"True courage means acting despite fear","w":["Courage","War","Friendship"],"h":"A theme is a full statement, not one word.","e":"A theme is a complete insight about life, while a topic is just a subject word."},{"p":"A literary theme is best described as:","a":"a central message or insight about life","w":["the sequence of plot events","the physical setting","the identity of the narrator"],"h":"What does the work reveal about life?","e":"Theme is the underlying message or insight a work conveys about life or human nature."},{"p":"A symbol is:","a":"an object that stands for a larger idea","w":["a description of the weather","the main character","a chapter title"],"h":"It represents something beyond itself.","e":"A symbol is a concrete object or image that represents a larger, abstract idea."},{"p":"In literature, a dove most commonly symbolizes:","a":"peace","w":["greed","war","time"],"h":"Think of a familiar image of calm.","e":"A dove is a widely recognized symbol of peace."},{"p":"In literature, light and darkness most often symbolize:","a":"knowledge and ignorance, or good and evil","w":["summer and winter","wealth and poverty","youth and old age"],"h":"Think good versus evil.","e":"Light and darkness commonly symbolize knowledge versus ignorance or good versus evil."},{"p":"A motif is:","a":"a recurring image or idea that helps develop the theme","w":["a single symbol used only once","the story's climax","the author's name"],"h":"The key word is recurring.","e":"A motif is a recurring element throughout a work that helps build its theme."},{"p":"A novel's TOPIC is \"ambition.\" Which of these could be its THEME?","a":"Unchecked ambition can destroy those who pursue it","w":["Ambition","The main character is ambitious","The story is set in a castle"],"h":"Turn the topic into a statement about life.","e":"A theme states an insight, such as how unchecked ambition can destroy a person."},{"p":"In a story, a garden the family stops tending wilts as their relationships fall apart. The garden most likely symbolizes:","a":"the family's neglected relationships","w":["the weather that season","the cost of vegetables","the town's history"],"h":"What fades alongside the garden?","e":"The neglected, wilting garden symbolizes the family's decaying relationships, developing a theme about neglect."},{"p":"A writer sets a character's death in winter and a rebirth in spring. This uses the seasons to symbolize:","a":"the cycle of death and renewal","w":["the price of food","a character's wealth","the town's location"],"h":"What do winter and spring represent?","e":"Winter and spring are often used to symbolize the cycle of death and renewal."},{"p":"Unlike a simple moral such as \"Always tell the truth,\" a theme in complex literature is usually:","a":"a nuanced insight open to interpretation","w":["a single blunt command","a plot summary","a description of setting"],"h":"Is it a strict rule or a deeper insight?","e":"A theme offers a nuanced, interpretable insight rather than a blunt rule."},{"p":"A fearful character avoids a red door for the whole story, then finally opens it at the end. The red door most likely symbolizes:","a":"the danger or passion the character has long avoided","w":["the color of the house","the season of the year","the character's wealth"],"h":"What does finally opening it represent?","e":"The red door can symbolize the danger or passion the character finally chooses to confront."},{"p":"The key difference between a motif and a symbol is that a motif:","a":"recurs throughout the work, while a symbol may appear only once","w":["is always a person","never relates to theme","is the same thing as the plot"],"h":"Focus on repetition.","e":"A motif is defined by its repetition across a work, whereas a symbol may appear a single time."},{"p":"A character gains great wealth but loses every friend and dies alone. This best supports the theme that:","a":"material success cannot replace human connection","w":["money is easy to earn","friends are unnecessary","wealth guarantees happiness"],"h":"What does the ending reveal?","e":"The lonely ending supports a theme that material success cannot replace human connection."},{"p":"A caged bird that keeps singing appears whenever an oppressed character dreams of freedom. The caged bird symbolizes:","a":"the longing for freedom despite confinement","w":["a pet the family owns","the character's job","the passage of time"],"h":"Cage, plus song, plus dreams of freedom.","e":"The singing caged bird symbolizes the enduring longing for freedom despite confinement."},{"p":"Which statement is a universal theme that could apply across many cultures and eras?","a":"Love can inspire great sacrifice","w":["The knight rode a brown horse","The story happens in 1850","The village had a single well"],"h":"Which speaks to broad human experience?","e":"A universal theme expresses an insight about human experience that transcends a single time or place."},{"p":"Throughout a novel, broken clocks appear in nearly every scene. This motif most likely develops a theme about:","a":"time, mortality, or lives frozen in the past","w":["the price of watches","the town's economy","a character's hobby"],"h":"What idea do repeated clocks evoke?","e":"A recurring motif of broken clocks develops a theme about time, mortality, or being stuck in the past."}],"e.12.syntax":[{"p":"Parallelism is:","a":"using the same grammatical form for related ideas","w":["repeating the first word of clauses","placing opposite ideas together","asking a question with no answer"],"h":"Think matching grammatical structure.","e":"Parallelism uses matching grammatical structures for related ideas, as in \"of the people, by the people, for the people.\""},{"p":"Anaphora is:","a":"repeating a word or phrase at the start of successive clauses","w":["reversing normal word order","using a parallel list of items","placing opposites side by side"],"h":"Think \"I have a dream... I have a dream.\"","e":"Anaphora repeats the same word or phrase at the beginning of successive clauses for emphasis."},{"p":"Antithesis places:","a":"contrasting ideas together in balanced structure","w":["the same idea stated twice","a question before its answer","a simple list of three items"],"h":"Opposites set in balance.","e":"Antithesis sets contrasting ideas in parallel structure, as in \"ask not what your country can do for you.\""},{"p":"Juxtaposition is:","a":"placing two things side by side to highlight their contrast","w":["repeating a phrase for rhythm","using very long sentences","matching grammatical forms"],"h":"Side by side for effect.","e":"Juxtaposition positions two elements near each other to emphasize their differences."},{"p":"Placing a very short sentence right after several long ones tends to:","a":"create emphasis or a sense of abruptness","w":["slow the pace gently","confuse the verb tense","remove all tone"],"h":"What happens when the rhythm suddenly stops?","e":"A short sentence among longer ones creates emphasis and a sense of abruptness."},{"p":"\"We will fight in the fields. We will fight in the streets. We will fight in the hills.\" This device is:","a":"anaphora","w":["antithesis","juxtaposition","understatement"],"h":"Notice the repeated opening words.","e":"Repeating \"We will fight\" at the start of each clause is anaphora."},{"p":"\"It was the best of times, it was the worst of times.\" This device is:","a":"antithesis","w":["anaphora","parallelism only","hyperbole"],"h":"Balanced opposites: best and worst.","e":"Pairing best and worst in balanced clauses is antithesis."},{"p":"\"She likes hiking, swimming, and biking.\" This sentence uses:","a":"parallelism","w":["antithesis","anaphora","a sentence fragment"],"h":"Notice the matching -ing forms.","e":"The matching -ing forms make this a parallel structure."},{"p":"Which sentence contains FAULTY parallelism?","a":"He likes to run, swimming, and to bike","w":["He likes running, swimming, and biking","He likes to run, swim, and bike","She reads, writes, and edits"],"h":"Which one mixes verb forms?","e":"Mixing \"to run,\" \"swimming,\" and \"to bike\" breaks parallel form, creating faulty parallelism."},{"p":"A passage built from long, flowing, comma-rich sentences most likely creates a tone that is:","a":"reflective and leisurely","w":["tense and clipped","angry and abrupt","simple and childish"],"h":"What mood do long, winding sentences suggest?","e":"Long, flowing sentences tend to create a reflective, leisurely tone."},{"p":"\"He ran. He stopped. He listened.\" The clipped, short syntax mainly conveys:","a":"tension and urgency","w":["calm reflection","playful humor","formal distance"],"h":"What do abrupt sentences suggest?","e":"Short, clipped sentences build tension and a sense of urgency."},{"p":"A \"periodic sentence\" delays its main idea until the end. Its main effect is to:","a":"build suspense before the key point","w":["state the main point first","shorten the sentence","remove all clauses"],"h":"What does saving the main idea for last do?","e":"A periodic sentence withholds the main clause until the end, building suspense."},{"p":"A \"loose\" (cumulative) sentence states its main idea first, then adds detail. Compared with a periodic sentence, it feels more:","a":"relaxed and conversational","w":["suspenseful and formal","abrupt and tense","broken and incomplete"],"h":"Main idea first, details trailing after.","e":"A loose sentence leads with the main idea, giving a relaxed, conversational effect."},{"p":"A writer describes a lavish feast in one paragraph and a starving crowd outside in the next. This juxtaposition emphasizes:","a":"the contrast between wealth and poverty","w":["the taste of the food","the time of day","the narrator's age"],"h":"What do the paired images stress?","e":"Placing feast beside famine juxtaposes wealth and poverty to stress their contrast."},{"p":"Ending a persuasive speech with \"How long must we wait for justice?\" primarily works to:","a":"provoke the audience to reflect and feel urgency","w":["request a factual answer","introduce a brand-new topic","soften the argument"],"h":"Is the speaker really seeking an answer?","e":"A rhetorical question prompts reflection and urgency rather than seeking a literal answer."},{"p":"\"We build to endure, not to impress; we labor for tomorrow, not for applause.\" This sentence relies mainly on:","a":"parallelism and antithesis","w":["anaphora and hyperbole","understatement and pun","fragment and slang"],"h":"Balanced structure that sets up contrasts.","e":"The balanced clauses set up contrasts, combining parallelism with antithesis."}],"s.9.cells":[{"p":"Which organelle contains the cell's DNA and directs its activities?","a":"Nucleus","w":["Mitochondria","Ribosome","Vacuole"],"h":"Think of the cell's control center.","e":"The nucleus stores genetic information and controls the cell's activities."},{"p":"Which organelle produces most of the cell's ATP energy?","a":"Mitochondria","w":["Nucleus","Ribosome","Chloroplast"],"h":"Nicknamed the powerhouse.","e":"Mitochondria release energy from food as ATP through cellular respiration."},{"p":"Where in the cell are proteins assembled?","a":"Ribosomes","w":["Nucleus","Vacuole","Cell membrane"],"h":"These tiny structures build proteins.","e":"Ribosomes link amino acids together to build proteins."},{"p":"Which structure controls what enters and leaves the cell?","a":"Cell membrane","w":["Cell wall","Nucleus","Cytoplasm"],"h":"It surrounds every cell.","e":"The cell membrane is selectively permeable, regulating what passes in and out."},{"p":"Which rigid, cellulose structure surrounds plant cells for support?","a":"Cell wall","w":["Cell membrane","Vacuole","Chloroplast"],"h":"It gives plants their firm shape.","e":"The cell wall is a rigid layer of cellulose that supports and protects plant cells."},{"p":"Which organelle captures light energy to make food in plants?","a":"Chloroplast","w":["Mitochondria","Nucleus","Ribosome"],"h":"It holds a green pigment.","e":"Chloroplasts use chlorophyll to capture light energy for photosynthesis."},{"p":"What is the jelly-like fluid that fills the cell and holds organelles?","a":"Cytoplasm","w":["Cell membrane","Vacuole","Nucleus"],"h":"Organelles float in it.","e":"Cytoplasm is the gel-like fluid where organelles are suspended and reactions occur."},{"p":"Which organelle stores water, nutrients, and waste and is largest in plant cells?","a":"Vacuole","w":["Nucleus","Chloroplast","Ribosome"],"h":"A storage sac.","e":"The vacuole stores water and materials and is very large in plant cells."},{"p":"Which type of cell lacks a membrane-bound nucleus?","a":"Prokaryotic cells","w":["Eukaryotic cells","Plant cells","Animal cells"],"h":"Bacteria are examples.","e":"Prokaryotic cells have no nucleus; their DNA floats freely in the cytoplasm."},{"p":"Which structure is found in plant cells but NOT animal cells?","a":"Cell wall","w":["Nucleus","Mitochondria","Ribosome"],"h":"Animals lack this rigid layer.","e":"Plant cells have a cell wall, while animal cells do not."},{"p":"A cell with no nucleus and no mitochondria is most likely which kind?","a":"Bacterial (prokaryotic) cell","w":["Plant cell","Animal cell","Fungal cell"],"h":"Only one lacks a nucleus.","e":"Bacteria are prokaryotes, lacking a nucleus and membrane-bound organelles."},{"p":"What key feature makes eukaryotic cells different from prokaryotic cells?","a":"A membrane-bound nucleus","w":["A cell membrane","Cytoplasm","DNA"],"h":"All cells share the other three.","e":"Eukaryotic cells have a membrane-bound nucleus, which prokaryotes lack."},{"p":"A student sees a cell with a cell wall and chloroplasts. What is it?","a":"Plant cell","w":["Animal cell","Bacterial cell","Human cell"],"h":"Chloroplasts point to one type.","e":"Only plant cells have both a cell wall and chloroplasts."},{"p":"Why do animal cells NOT contain chloroplasts?","a":"They do not make their own food from light","w":["They are too small to hold them","They use a cell wall instead","They store food in the nucleus"],"h":"Think about how animals get energy.","e":"Animals get food by eating, so they have no chloroplasts for photosynthesis."},{"p":"A muscle cell needs lots of energy. Which organelle would be very numerous?","a":"Mitochondria","w":["Chloroplasts","Cell walls","Vacuoles"],"h":"Which organelle makes energy?","e":"Cells that need much energy contain many mitochondria to produce ATP."},{"p":"Which organelle holds the chlorophyll used to trap sunlight?","a":"Chloroplast","w":["Mitochondria","Vacuole","Ribosome"],"h":"It is green.","e":"Chloroplasts contain chlorophyll, the pigment that absorbs light energy."}],"s.9.photresp":[{"p":"Which gas do plants take in for photosynthesis?","a":"Carbon dioxide","w":["Oxygen","Nitrogen","Hydrogen"],"h":"It's the gas we breathe out.","e":"Plants absorb carbon dioxide from the air to use in photosynthesis."},{"p":"Which gas is released by plants during photosynthesis?","a":"Oxygen","w":["Carbon dioxide","Nitrogen","Hydrogen"],"h":"We breathe it in.","e":"Photosynthesis releases oxygen as a byproduct of making glucose."},{"p":"What sugar is produced by photosynthesis?","a":"Glucose","w":["Starch","Lactose","Sucrose"],"h":"A simple sugar the cell can use.","e":"Photosynthesis produces glucose, which cells use for energy."},{"p":"In which organelle does photosynthesis take place?","a":"Chloroplast","w":["Mitochondria","Nucleus","Ribosome"],"h":"It contains chlorophyll.","e":"Photosynthesis occurs in the chloroplasts of plant cells."},{"p":"Which green pigment absorbs light energy for photosynthesis?","a":"Chlorophyll","w":["Chloroplast","Glucose","Cytoplasm"],"h":"Don't confuse it with its organelle.","e":"Chlorophyll is the pigment inside chloroplasts that absorbs light energy."},{"p":"Besides carbon dioxide and light, what raw material does photosynthesis need?","a":"Water","w":["Oxygen","Glucose","Nitrogen"],"h":"Roots absorb it from soil.","e":"Photosynthesis combines carbon dioxide and water using light energy."},{"p":"Cellular respiration breaks down glucose to release what usable energy?","a":"ATP","w":["DNA","Chlorophyll","Sunlight"],"h":"The cell's energy currency.","e":"Cellular respiration transfers energy from glucose into ATP molecules."},{"p":"In which organelle does cellular respiration mainly occur?","a":"Mitochondria","w":["Chloroplast","Nucleus","Ribosome"],"h":"The powerhouse organelle.","e":"Most cellular respiration takes place in the mitochondria."},{"p":"Which gas is required for cellular respiration?","a":"Oxygen","w":["Carbon dioxide","Nitrogen","Hydrogen"],"h":"We breathe it in to use it.","e":"Cellular respiration uses oxygen to break down glucose for energy."},{"p":"Which gas is released as a waste product of cellular respiration?","a":"Carbon dioxide","w":["Oxygen","Nitrogen","Hydrogen"],"h":"We breathe it out.","e":"Cellular respiration produces carbon dioxide and water as wastes."},{"p":"The products of photosynthesis are the reactants of which process?","a":"Cellular respiration","w":["Digestion","Evaporation","Condensation"],"h":"Glucose and oxygen are used here.","e":"Photosynthesis makes glucose and oxygen, which respiration then uses."},{"p":"Which equation correctly represents photosynthesis?","a":"Carbon dioxide + water → glucose + oxygen","w":["Glucose + oxygen → carbon dioxide + water","Water + oxygen → glucose + carbon dioxide","Glucose + carbon dioxide → oxygen + water"],"h":"It builds sugar from air and water.","e":"Photosynthesis turns carbon dioxide and water into glucose and oxygen."},{"p":"Which organisms carry out cellular respiration?","a":"Both plants and animals","w":["Only animals","Only plants","Only fungi"],"h":"All living cells need ATP.","e":"Both plants and animals use respiration to release energy from glucose."},{"p":"During daylight, does a plant carry out only photosynthesis?","a":"No, it does both photosynthesis and respiration","w":["Yes, only photosynthesis","No, only respiration","Yes, only at night"],"h":"Plant cells still need ATP all the time.","e":"Plants photosynthesize in light but also respire continuously for energy."},{"p":"Why is chlorophyll essential to a plant?","a":"It absorbs the light energy used to make food","w":["It stores glucose for later use","It releases carbon dioxide gas","It builds the plant's cell wall"],"h":"Think about capturing sunlight.","e":"Chlorophyll captures light energy that powers the making of glucose."},{"p":"How do photosynthesis and respiration cycle together?","a":"One process's products are the other's reactants","w":["Both processes release only oxygen","Both processes use only sunlight","Both occur only in mitochondria"],"h":"Their inputs and outputs swap.","e":"The oxygen and glucose from photosynthesis fuel respiration, whose wastes feed photosynthesis."}],"s.10.atoms":[{"p":"What is the electric charge of a proton?","a":"Positive","w":["Negative","Neutral","It varies"],"h":"Opposite of an electron.","e":"Protons carry a positive electric charge."},{"p":"What is the electric charge of an electron?","a":"Negative","w":["Positive","Neutral","It varies"],"h":"Opposite of a proton.","e":"Electrons carry a negative electric charge."},{"p":"What is the electric charge of a neutron?","a":"Neutral (no charge)","w":["Positive","Negative","It varies"],"h":"The name is a clue.","e":"Neutrons have no electric charge; they are neutral."},{"p":"Where are protons and neutrons located in an atom?","a":"In the nucleus","w":["In the electron cloud","Orbiting the nucleus","Outside the atom"],"h":"The dense center.","e":"Protons and neutrons are packed together in the atom's nucleus."},{"p":"Where are electrons found in an atom?","a":"Orbiting the nucleus in the electron cloud","w":["Inside the nucleus","Packed with the neutrons","Bonded to the protons"],"h":"They move around the center.","e":"Electrons occupy the space around the nucleus in energy levels."},{"p":"What does an element's atomic number tell you?","a":"The number of protons","w":["The number of neutrons","The number of protons plus neutrons","The total mass of the atom"],"h":"It defines the element.","e":"The atomic number equals the number of protons in an atom."},{"p":"What does the mass number of an atom equal?","a":"Protons plus neutrons","w":["Protons plus electrons","Protons only","Neutrons only"],"h":"Add the two heavy particles.","e":"Mass number is the sum of protons and neutrons in the nucleus."},{"p":"Atoms of the same element with different numbers of neutrons are called what?","a":"Isotopes","w":["Ions","Molecules","Compounds"],"h":"Same protons, different mass.","e":"Isotopes are atoms of one element that differ in neutron count."},{"p":"An atom that has gained or lost electrons and now has a charge is called what?","a":"Ion","w":["Isotope","Molecule","Element"],"h":"Charged particle.","e":"An ion forms when an atom gains or loses electrons, giving it a charge."},{"p":"Electrons in the outermost energy level of an atom are called what?","a":"Valence electrons","w":["Core electrons","Neutrons","Protons"],"h":"They control bonding.","e":"Valence electrons are the outer electrons that determine chemical behavior."},{"p":"The horizontal rows of the periodic table are called what?","a":"Periods","w":["Groups","Families","Columns"],"h":"Rows go across.","e":"Horizontal rows on the periodic table are called periods."},{"p":"The vertical columns of the periodic table are groups, also called what?","a":"Families","w":["Periods","Rows","Isotopes"],"h":"Members share properties.","e":"Vertical columns are groups or families with similar properties."},{"p":"Elements that are shiny, conduct electricity, and are malleable are classified as what?","a":"Metals","w":["Nonmetals","Metalloids","Noble gases"],"h":"Think of copper or iron.","e":"Metals are shiny, conductive, and malleable, and sit left of the table."},{"p":"An element with properties of both metals and nonmetals is called what?","a":"Metalloid","w":["Metal","Nonmetal","Noble gas"],"h":"In between the two categories.","e":"Metalloids share properties of both metals and nonmetals."},{"p":"A neutral atom has 6 protons. How many electrons does it have?","a":"6","w":["0","12","3"],"h":"Neutral means charges balance.","e":"A neutral atom has equal numbers of protons and electrons."},{"p":"An atom has atomic number 11 and mass number 23. How many neutrons does it have?","a":"12","w":["11","23","34"],"h":"Mass number minus atomic number.","e":"Neutrons = mass number (23) minus protons (11), which equals 12."}],"s.10.bonding":[{"p":"What type of bond forms when electrons are transferred from one atom to another?","a":"Ionic bond","w":["Covalent bond","Metallic bond","Hydrogen bond"],"h":"One atom gives, one takes.","e":"Ionic bonds form when electrons transfer, creating oppositely charged ions."},{"p":"What type of bond forms when atoms share electrons?","a":"Covalent bond","w":["Ionic bond","Metallic bond","Nuclear bond"],"h":"Sharing, not transferring.","e":"Covalent bonds form when atoms share pairs of electrons."},{"p":"Why do atoms form chemical bonds?","a":"To become more stable with a full outer shell","w":["To gain more neutrons","To become radioactive","To lose their nucleus"],"h":"Think about a full valence shell.","e":"Atoms bond to fill their outer electron shells and gain stability."},{"p":"The tendency of atoms to seek eight valence electrons is called what?","a":"The octet rule","w":["The proton rule","The isotope rule","The mass rule"],"h":"'Oct' means eight.","e":"The octet rule states atoms are stable with eight valence electrons."},{"p":"A positively charged ion is called what?","a":"Cation","w":["Anion","Isotope","Molecule"],"h":"It has lost electrons.","e":"A cation is a positively charged ion formed by losing electrons."},{"p":"A negatively charged ion is called what?","a":"Anion","w":["Cation","Isotope","Neutron"],"h":"It has gained electrons.","e":"An anion is a negatively charged ion formed by gaining electrons."},{"p":"Table salt (NaCl) is held together by which type of bond?","a":"Ionic bond","w":["Covalent bond","Metallic bond","Hydrogen bond"],"h":"A metal joins a nonmetal.","e":"NaCl is ionic, formed by electron transfer between sodium and chlorine."},{"p":"Water (H2O) is held together by which type of bond?","a":"Covalent bond","w":["Ionic bond","Metallic bond","Nuclear bond"],"h":"Nonmetals sharing electrons.","e":"Water molecules are held together by covalent bonds that share electrons."},{"p":"Two or more different elements chemically bonded together form a what?","a":"Compound","w":["Mixture","Element","Isotope"],"h":"Chemically joined, not just mixed.","e":"A compound is two or more different elements chemically bonded together."},{"p":"A neutral group of atoms joined by covalent bonds is called a what?","a":"Molecule","w":["Ion","Isotope","Crystal"],"h":"Think of H2O or O2.","e":"A molecule is a neutral group of atoms held together by covalent bonds."},{"p":"When a metal bonds with a nonmetal, they usually form which type of bond?","a":"Ionic bond","w":["Covalent bond","Metallic bond","Hydrogen bond"],"h":"Metals give up electrons easily.","e":"Metal-plus-nonmetal pairs usually transfer electrons to form ionic bonds."},{"p":"When two nonmetals bond, they usually form which type of bond?","a":"Covalent bond","w":["Ionic bond","Metallic bond","Magnetic bond"],"h":"Neither atom gives up electrons easily.","e":"Two nonmetals share electrons, forming covalent bonds."},{"p":"An atom that loses an electron becomes what?","a":"A positive ion (cation)","w":["A negative ion (anion)","A neutron","An isotope"],"h":"Fewer electrons than protons.","e":"Losing an electron leaves more protons than electrons, making a positive ion."},{"p":"In a water molecule, unequal sharing of electrons makes the molecule what?","a":"Polar","w":["Nonpolar","Ionic","Neutral in charge everywhere"],"h":"It has slightly charged ends.","e":"Water is polar because electrons are shared unequally, creating charged ends."},{"p":"Carbon dioxide (CO2) is made of nonmetals sharing electrons, so its bonds are what?","a":"Covalent","w":["Ionic","Metallic","Magnetic"],"h":"Nonmetals share electrons.","e":"CO2 forms covalent bonds because its nonmetal atoms share electrons."},{"p":"Sodium (Na) loses one electron during bonding. What does it become?","a":"A cation (Na+)","w":["An anion (Na-)","A neutral atom","An isotope"],"h":"Losing an electron adds positive charge.","e":"Losing one electron turns sodium into a positively charged cation, Na+."}],"s.11.motion":[{"p":"What quantity is speed in a specific direction?","a":"Velocity","w":["Acceleration","Distance","Friction"],"h":"It includes direction.","e":"Velocity is speed with a direction, making it a vector quantity."},{"p":"What is the rate of change of velocity called?","a":"Acceleration","w":["Speed","Momentum","Displacement"],"h":"It measures how fast velocity changes.","e":"Acceleration is the rate at which an object's velocity changes over time."},{"p":"Which quantity measures straight-line distance and direction from start to finish?","a":"Displacement","w":["Distance","Speed","Time"],"h":"It is a vector from start to end.","e":"Displacement is the straight-line vector from the starting point to the ending point."},{"p":"A runner completes one full lap on a 400 m track. What is the displacement?","a":"0 m","w":["400 m","200 m","800 m"],"h":"Start and finish are the same point.","e":"Because the runner ends where they started, displacement is zero even though distance is 400 m."},{"p":"Which law states an object stays at rest or in motion unless acted on by a force?","a":"Newton's first law","w":["Newton's second law","Newton's third law","The law of gravity"],"h":"It is about inertia.","e":"Newton's first law, the law of inertia, says motion stays constant unless a net force acts."},{"p":"What is an object's resistance to changes in its motion called?","a":"Inertia","w":["Friction","Momentum","Gravity"],"h":"Related to Newton's first law.","e":"Inertia is the tendency of an object to resist changes in its state of motion."},{"p":"Which equation represents Newton's second law?","a":"F = m × a","w":["F = m ÷ a","F = a ÷ m","F = m × v"],"h":"Force, mass, and acceleration.","e":"Newton's second law states that force equals mass times acceleration."},{"p":"What force accelerates a 2 kg object at 3 m/s squared?","a":"6 N","w":["1.5 N","5 N","0.67 N"],"h":"Multiply mass by acceleration.","e":"Force equals mass times acceleration, so 2 kg × 3 m/s squared = 6 N."},{"p":"For every action there is an equal and opposite what?","a":"Reaction","w":["Acceleration","Velocity","Friction"],"h":"Newton's third law wording.","e":"Newton's third law states every action force has an equal and opposite reaction force."},{"p":"On Earth, what is the approximate acceleration due to gravity?","a":"9.8 m/s squared","w":["3.7 m/s squared","1.6 m/s squared","98 m/s squared"],"h":"Near 10 m/s squared downward.","e":"Objects in free fall near Earth's surface accelerate downward at about 9.8 m/s squared."},{"p":"In a vacuum, a feather and a hammer dropped together will land...","a":"At the same time","w":["Hammer first","Feather first","Neither falls"],"h":"There is no air resistance.","e":"Without air resistance, all objects fall with the same acceleration regardless of mass."},{"p":"What is the net force on an object when forces are balanced?","a":"Zero","w":["Positive","Negative","Doubled"],"h":"They cancel out.","e":"Balanced forces cancel, producing a net force of zero and no change in motion."},{"p":"Unbalanced forces acting on an object cause it to...","a":"Accelerate","w":["Stay still","Move at constant speed","Disappear"],"h":"Net force is not zero.","e":"Unbalanced forces produce a net force, causing the object to accelerate."},{"p":"What force opposes motion between two surfaces in contact?","a":"Friction","w":["Gravity","Tension","Magnetism"],"h":"It resists sliding.","e":"Friction is the force that resists motion between two surfaces touching each other."},{"p":"Which surface generally produces the most friction?","a":"Rough sandpaper","w":["Smooth ice","Polished glass","Oiled metal"],"h":"Rougher means more friction.","e":"Rough surfaces like sandpaper create more friction than smooth or slippery surfaces."},{"p":"What is the measure of the amount of matter in an object?","a":"Mass","w":["Weight","Force","Volume"],"h":"Measured in kilograms.","e":"Mass is the amount of matter in an object and is measured in kilograms."}],"s.11.circuits":[{"p":"What is the flow of electric charge through a conductor called?","a":"Current","w":["Voltage","Resistance","Insulation"],"h":"Measured in amperes.","e":"Electric current is the flow of electric charge, measured in amperes."},{"p":"What is the unit of electric current?","a":"Ampere","w":["Volt","Ohm","Watt"],"h":"Often shortened to amp.","e":"Current is measured in amperes, often called amps."},{"p":"What pushes electric charge through a circuit?","a":"Voltage","w":["Resistance","Friction","Insulation"],"h":"Measured in volts.","e":"Voltage is the electrical push, or potential difference, that drives current through a circuit."},{"p":"What is the unit of voltage?","a":"Volt","w":["Ampere","Ohm","Watt"],"h":"Named after Volta.","e":"Voltage is measured in volts."},{"p":"What opposes the flow of current in a circuit?","a":"Resistance","w":["Voltage","Current","Charge"],"h":"Measured in ohms.","e":"Resistance opposes the flow of electric current and is measured in ohms."},{"p":"What is the unit of resistance?","a":"Ohm","w":["Volt","Ampere","Watt"],"h":"Its symbol is the omega sign.","e":"Resistance is measured in ohms."},{"p":"Which equation represents Ohm's law?","a":"V = I × R","w":["V = I ÷ R","V = R ÷ I","V = I + R"],"h":"Voltage, current, resistance.","e":"Ohm's law states voltage equals current times resistance."},{"p":"A 2 A current flows through a 5 ohm resistor. What is the voltage?","a":"10 V","w":["2.5 V","7 V","0.4 V"],"h":"Multiply current by resistance.","e":"Using V = I × R, 2 A × 5 ohms = 10 V."},{"p":"What current flows when 12 V is applied across a 4 ohm resistor?","a":"3 A","w":["48 A","8 A","0.33 A"],"h":"I = V ÷ R.","e":"Using Ohm's law, I = V ÷ R = 12 V ÷ 4 ohms = 3 A."},{"p":"In which circuit do all components share a single path for current?","a":"Series circuit","w":["Parallel circuit","Open circuit","Short circuit"],"h":"One loop, one path.","e":"In a series circuit, current has only one path through all components."},{"p":"In a series string of bulbs, what happens if one bulb burns out?","a":"All bulbs go out","w":["Only that bulb goes out","Bulbs get brighter","Nothing changes"],"h":"One path is broken.","e":"In a series circuit, a single break stops current everywhere, so all bulbs go out."},{"p":"In which circuit does each component have its own path for current?","a":"Parallel circuit","w":["Series circuit","Open circuit","Broken circuit"],"h":"Multiple branches.","e":"In a parallel circuit, each component is on its own branch with a separate current path."},{"p":"Which material lets electric current flow easily?","a":"Copper","w":["Rubber","Glass","Plastic"],"h":"A common metal wire.","e":"Copper is a good conductor, allowing electric current to flow easily."},{"p":"Which material blocks the flow of electric current?","a":"Rubber","w":["Copper","Silver","Aluminum"],"h":"Used to coat wires.","e":"Rubber is an insulator that resists the flow of electric current."},{"p":"What must a circuit be for current to flow?","a":"A closed loop","w":["An open loop","A broken wire","A single wire end"],"h":"The path must be unbroken.","e":"Current only flows when a circuit forms a complete, closed loop."},{"p":"Which action is safest around electricity?","a":"Keep water away from outlets","w":["Touch wires with wet hands","Overload a single socket","Poke outlets with metal"],"h":"Water conducts electricity.","e":"Keeping water away from outlets prevents dangerous shocks because water conducts electricity."}],"s.12.environment":[{"p":"What term describes the variety of living things in an ecosystem?","a":"Biodiversity","w":["Population","Habitat","Pollution"],"h":"Bio means life; diversity means variety.","e":"Biodiversity is the variety of different species living in an ecosystem."},{"p":"What do we call a community of living things interacting with their environment?","a":"An ecosystem","w":["A population","A single species","An atom"],"h":"Includes living and nonliving parts.","e":"An ecosystem is all the living organisms and nonliving factors interacting in an area."},{"p":"Which process removes carbon dioxide from the air?","a":"Photosynthesis","w":["Respiration","Combustion","Decomposition"],"h":"Plants do this.","e":"Photosynthesis removes carbon dioxide from the air as plants make food."},{"p":"Which process releases the most carbon dioxide into the atmosphere?","a":"Burning fossil fuels","w":["Photosynthesis","Growing new trees","Making oxygen"],"h":"Think cars and factories.","e":"Burning fossil fuels releases stored carbon as carbon dioxide into the atmosphere."},{"p":"Which of these is a renewable energy source?","a":"Solar power","w":["Coal","Oil","Natural gas"],"h":"It comes from the sun.","e":"Solar power is renewable because sunlight is naturally replenished."},{"p":"Which of these is a nonrenewable energy source?","a":"Coal","w":["Wind","Solar","Hydropower"],"h":"It takes millions of years to form.","e":"Coal is nonrenewable because it forms over millions of years and cannot be quickly replaced."},{"p":"Which energy source uses moving air to generate electricity?","a":"Wind power","w":["Nuclear power","Coal power","Oil power"],"h":"Turbines spin in the breeze.","e":"Wind power uses turbines turned by moving air to generate electricity."},{"p":"Which gas is a major greenhouse gas released by burning fuels?","a":"Carbon dioxide","w":["Oxygen","Nitrogen","Helium"],"h":"Plants absorb it; cars emit it.","e":"Carbon dioxide is a major greenhouse gas that traps heat in the atmosphere."},{"p":"What do greenhouse gases do to Earth's heat?","a":"Trap it in the atmosphere","w":["Reflect it into space","Destroy it completely","Cool the planet"],"h":"Like a blanket.","e":"Greenhouse gases trap heat in the atmosphere, warming the planet."},{"p":"The long-term rise in Earth's average temperature is called...","a":"Global warming","w":["Ozone depletion","Acid rain","Erosion"],"h":"Linked to greenhouse gases.","e":"Global warming is the long-term increase in Earth's average temperature."},{"p":"What is the large-scale clearing of forests called?","a":"Deforestation","w":["Reforestation","Pollination","Irrigation"],"h":"Removing trees.","e":"Deforestation is the clearing of forests, which reduces habitat and carbon storage."},{"p":"What term describes harmful substances released into the environment?","a":"Pollution","w":["Conservation","Recycling","Photosynthesis"],"h":"Dirties air, water, or land.","e":"Pollution is the release of harmful substances that damage the environment."},{"p":"What is the careful protection and wise use of natural resources called?","a":"Conservation","w":["Deforestation","Extraction","Consumption"],"h":"Protecting resources.","e":"Conservation is the responsible protection and management of natural resources."},{"p":"Using resources so future generations still have them is called...","a":"Sustainability","w":["Depletion","Extinction","Pollution"],"h":"Meeting needs without using everything up.","e":"Sustainability means using resources in a way that does not exhaust them for the future."},{"p":"Which action best reduces waste sent to landfills?","a":"Recycling materials","w":["Burning more coal","Cutting more forests","Using more plastic"],"h":"Reuse instead of throw away.","e":"Recycling reuses materials, reducing the amount of waste sent to landfills."},{"p":"The permanent loss of an entire species is called...","a":"Extinction","w":["Migration","Hibernation","Adaptation"],"h":"Gone for good.","e":"Extinction is the permanent disappearance of an entire species."}],"s.12.labskills":[{"p":"What usually begins the scientific method?","a":"Asking a question","w":["Writing a conclusion","Publishing results","Making a graph"],"h":"It comes from an observation.","e":"The scientific method typically begins by observing something and asking a question."},{"p":"What is a testable, proposed explanation for an observation?","a":"A hypothesis","w":["A conclusion","A theory","A law"],"h":"An educated, testable guess.","e":"A hypothesis is a testable proposed explanation that an experiment can support or reject."},{"p":"What is the variable the experimenter deliberately changes?","a":"Independent variable","w":["Dependent variable","Controlled variable","Control group"],"h":"The cause you set.","e":"The independent variable is the factor the experimenter changes on purpose."},{"p":"What is the variable that is measured as a result of the experiment?","a":"Dependent variable","w":["Independent variable","Controlled variable","Constant factor"],"h":"The effect you measure.","e":"The dependent variable is the outcome measured in response to the independent variable."},{"p":"What do we call factors kept the same throughout an experiment?","a":"Controlled variables","w":["Independent variables","Dependent variables","Random variables"],"h":"Held constant for fairness.","e":"Controlled variables are factors kept constant so they do not affect the results."},{"p":"Which group does not receive the experimental treatment?","a":"The control group","w":["The experimental group","The variable group","The sample group"],"h":"Used for comparison.","e":"The control group receives no treatment and serves as a baseline for comparison."},{"p":"Accuracy describes how close a measurement is to what?","a":"The true value","w":["Other measurements","The average","Zero"],"h":"Close to the real answer.","e":"Accuracy is how close a measured value is to the true or accepted value."},{"p":"Precision describes how close repeated measurements are to...","a":"Each other","w":["The true value","The origin","The correct answer"],"h":"Consistency of results.","e":"Precision is how close repeated measurements are to one another."},{"p":"What is the SI base unit of length?","a":"Meter","w":["Foot","Mile","Liter"],"h":"Metric length unit.","e":"The meter is the SI base unit for measuring length."},{"p":"What is the SI base unit of mass?","a":"Kilogram","w":["Pound","Gram","Newton"],"h":"Metric mass unit.","e":"The kilogram is the SI base unit for measuring mass."},{"p":"What is the SI base unit of time?","a":"Second","w":["Minute","Hour","Day"],"h":"The smallest here.","e":"The second is the SI base unit for measuring time."},{"p":"What should a valid conclusion be based on?","a":"The collected data","w":["A personal opinion","The hypothesis alone","A lucky guess"],"h":"Evidence from the experiment.","e":"A conclusion should be based on the evidence and data gathered in the experiment."},{"p":"Which tool best shows how one variable changes with another?","a":"A graph","w":["A hypothesis","A ruler","A beaker"],"h":"Visualizes trends.","e":"A graph visually displays the relationship between variables in data."},{"p":"What should you wear to protect your eyes in the lab?","a":"Safety goggles","w":["Sunglasses","A cloth hat","Foam earmuffs"],"h":"Protects from splashes.","e":"Safety goggles protect your eyes from chemical splashes and flying particles."},{"p":"What should you do first if you spill a chemical?","a":"Tell your teacher","w":["Ignore the spill","Taste the liquid","Hide the mess"],"h":"Report to an adult.","e":"Always notify your teacher immediately so a chemical spill is handled safely."},{"p":"Why do scientists repeat experiments many times?","a":"To make results more reliable","w":["To waste materials","To change the answer","To skip the data"],"h":"More trials, stronger evidence.","e":"Repeating experiments improves reliability by reducing the effect of random error."}],"s.2.forces":[{"p":"What is a push or a pull?","a":"A force","w":["A color","A sound","A smell"],"h":"It can move things.","e":"A push or a pull is a force that can move an object."},{"p":"Which one is a push?","a":"Closing a door","w":["Eating lunch","Singing a song","Reading a book"],"h":"You push it shut.","e":"Closing a door is a push because you press it away from you."},{"p":"Which one is a pull?","a":"Opening a drawer","w":["Kicking a ball","Clapping hands","Blinking eyes"],"h":"You pull it to you.","e":"Opening a drawer is a pull because you bring it toward you."},{"p":"A force can make a still ball do what?","a":"Start moving","w":["Turn blue","Fall asleep","Get louder"],"h":"It begins to move.","e":"A push or pull can make a still object start moving."},{"p":"What can make a rolling ball stop?","a":"A force","w":["A song","A color","A smell"],"h":"A push or pull stops it.","e":"A force from a hand or the ground can make a moving ball stop."},{"p":"A hard push makes a ball go...","a":"Faster","w":["Slower","Quieter","Colder"],"h":"More push, more speed.","e":"A stronger push makes an object move faster."},{"p":"A gentle push makes a ball go...","a":"Slower","w":["Faster","Louder","Higher"],"h":"Less push, less speed.","e":"A gentle push makes an object move more slowly than a hard push."},{"p":"What force slows things down as they rub?","a":"Friction","w":["Sunlight","Music","Color"],"h":"It happens when things rub.","e":"Friction is a force that slows objects down when surfaces rub together."},{"p":"A ball rolls slower on grass than on a smooth floor because of...","a":"More friction","w":["More light","More sound","Less color"],"h":"Grass is rough.","e":"Rough grass has more friction, so it slows the ball more than a smooth floor."},{"p":"To change where a ball goes, you can...","a":"Push it a new way","w":["Look at it","Talk to it","Name it"],"h":"A push can turn it.","e":"Pushing an object in a new direction changes the way it moves."},{"p":"Kicking a soccer ball is a...","a":"Push","w":["Pull","Color","Sound"],"h":"Your foot pushes it.","e":"Kicking a ball is a push from your foot that makes it move."},{"p":"A dog tugging on a leash is a...","a":"Pull","w":["Push","Smell","Song"],"h":"It pulls toward the dog.","e":"A dog tugging a leash uses a pull force."},{"p":"Which needs a bigger push to move?","a":"A heavy box","w":["An empty cup","A soft feather","A thin paper"],"h":"Heavy things are harder.","e":"Heavier objects need a bigger push to start moving."},{"p":"A swing moving back and forth was first given a...","a":"Push","w":["Nap","Snack","Story"],"h":"Someone pushed it.","e":"A swing moves because someone gave it a push force."},{"p":"Rubbing your hands together makes them warm because of...","a":"Friction","w":["Rain","Music","Light"],"h":"Rubbing makes heat.","e":"Friction between your rubbing hands makes them feel warm."},{"p":"Can you see a force like a push?","a":"No, but you see what it does","w":["Yes, it is green","Yes, it is round","No, it is a sound"],"h":"You see things move.","e":"You cannot see a force, but you can see how it makes objects move."}],"sp.8.futuro":[{"p":"Yo ___ a estudiar esta noche.","a":"voy","w":["vas","va","vamos"],"h":"Conjuga 'ir' para 'yo'.","e":"The near future uses ir + a + infinitive; 'yo' takes 'voy'."},{"p":"Nosotros ___ a viajar a México.","a":"vamos","w":["van","voy","vas"],"h":"Forma de 'nosotros'.","e":"For 'nosotros', ir is conjugated as 'vamos' before a + infinitive."},{"p":"Ella ___ a comer pizza.","a":"va","w":["vas","voy","van"],"h":"Tercera persona singular.","e":"'Ella' uses the third-person singular 'va' in ir + a + infinitive."},{"p":"Tú ___ a jugar al fútbol.","a":"vas","w":["va","voy","van"],"h":"Forma de 'tú'.","e":"'Tú' takes 'vas' when forming plans with ir + a + infinitive."},{"p":"Ellos ___ a bailar en la fiesta.","a":"van","w":["va","vamos","voy"],"h":"Tercera persona plural.","e":"'Ellos' uses 'van' in the ir + a + infinitive structure."},{"p":"Traduce: 'I am going to study.'","a":"Voy a estudiar","w":["Voy estudiar","Voy a estudio","Yo estudio"],"h":"No olvides la 'a'.","e":"Ir + a + infinitive requires the linking word 'a' plus the unconjugated verb."},{"p":"Traduce: 'We are going to travel.'","a":"Vamos a viajar","w":["Vamos viajar","Van a viajar","Vamos a viajo"],"h":"'Nosotros' + a + infinitivo.","e":"'We' is 'vamos', followed by 'a' and the infinitive 'viajar'."},{"p":"¿Cuál es correcta?","a":"Voy a comer","w":["Voy comer","Voy a como","Yo va a comer"],"h":"Busca 'a' + infinitivo.","e":"The correct pattern is conjugated ir + a + infinitive, giving 'Voy a comer'."},{"p":"¿Qué ___ a hacer tú mañana?","a":"vas","w":["va","van","voy"],"h":"Sujeto: 'tú'.","e":"With 'tú', ir becomes 'vas' in future plans."},{"p":"Mis amigos ___ a ver una película.","a":"van","w":["va","vamos","vas"],"h":"Sujeto plural.","e":"'Mis amigos' is third-person plural, so ir is 'van'."},{"p":"Traduce: 'She is going to write a letter.'","a":"Ella va a escribir una carta","w":["Ella va escribir una carta","Ella va a escribo una carta","Ella van a escribir una carta"],"h":"'va' + a + infinitivo.","e":"'Ella va a escribir' keeps ir conjugated and the second verb in the infinitive."},{"p":"Usted ___ a trabajar el lunes.","a":"va","w":["vas","van","voy"],"h":"'Usted' usa tercera persona.","e":"'Usted' is formal and uses the third-person singular 'va'."},{"p":"Vosotros ___ a cantar en el concierto.","a":"vais","w":["van","vas","va"],"h":"Forma de 'vosotros'.","e":"In Spain, 'vosotros' conjugates ir as 'vais'."},{"p":"Traduce: 'They are going to buy a car.'","a":"Van a comprar un coche","w":["Van comprar un coche","Va a comprar un coche","Van a compran un coche"],"h":"Plural + a + infinitivo.","e":"'They' is 'van', linked by 'a' to the infinitive 'comprar'."},{"p":"¿Qué palabra falta? 'Yo voy ___ leer un libro.'","a":"a","w":["de","en","que"],"h":"Conector obligatorio.","e":"Ir + a + infinitive always needs the preposition 'a' between the verbs."},{"p":"Mañana ___ (yo) a visitar a mi abuela.","a":"voy","w":["va","vas","vamos"],"h":"Primera persona singular.","e":"'Yo' uses 'voy' to express a plan with ir + a + infinitive."}],"sp.9.imperfect":[{"p":"Cuando era niño, yo ___ (jugar) todos los días.","a":"jugaba","w":["jugué","juego","jugaría"],"h":"Acción habitual pasada, -ar.","e":"Regular -ar verbs form the imperfect with -aba endings, used for habitual past actions."},{"p":"Ella ___ (comer) mucho de pequeña.","a":"comía","w":["comió","come","comería"],"h":"Verbo -er, terminación -ía.","e":"Regular -er verbs take -ía in the imperfect to describe repeated past actions."},{"p":"Nosotros ___ (vivir) en Madrid.","a":"vivíamos","w":["vivimos","vivían","vivieron"],"h":"-ir, 'nosotros'.","e":"For 'nosotros', -ir verbs form the imperfect as -íamos, here 'vivíamos'."},{"p":"De pequeño, yo ___ (ser) muy alto.","a":"era","w":["fui","soy","sería"],"h":"'Ser' es irregular.","e":"Ser is irregular in the imperfect: yo era, describing states in the past."},{"p":"Ellos ___ (ir) a la escuela en autobús.","a":"iban","w":["fueron","van","irían"],"h":"'Ir' es irregular.","e":"Ir is irregular in the imperfect: ellos iban, used for habitual past actions."},{"p":"Nosotros ___ (ver) la tele cada noche.","a":"veíamos","w":["vimos","veían","vemos"],"h":"'Ver' irregular, 'nosotros'.","e":"Ver keeps the e: nosotros veíamos in the imperfect."},{"p":"Tú ___ (hablar) con tu amigo a menudo.","a":"hablabas","w":["hablaste","hablas","hablarías"],"h":"-ar, 'tú'.","e":"Regular -ar verbs use -abas for 'tú' in the imperfect."},{"p":"Yo ___ (tener) diez años entonces.","a":"tenía","w":["tuve","tengo","tendría"],"h":"La edad en el pasado.","e":"The imperfect expresses age in the past: yo tenía diez años."},{"p":"___ las tres de la tarde.","a":"Eran","w":["Fueron","Son","Serían"],"h":"La hora en el pasado.","e":"Time in the past uses the imperfect of ser: 'Eran las tres'."},{"p":"De niña, mi madre ___ (ser) muy tímida.","a":"era","w":["fue","es","sería"],"h":"Descripción en el pasado.","e":"Ser in the imperfect (era) describes characteristics in the past."},{"p":"Traduce: 'We used to travel every summer.'","a":"Viajábamos cada verano","w":["Viajamos cada verano","Viajaremos cada verano","Viajaríamos cada verano"],"h":"'Used to' = imperfecto.","e":"'Used to' habitual actions are expressed with the imperfect, here 'viajábamos'."},{"p":"Los niños ___ (correr) en el parque.","a":"corrían","w":["corrieron","corren","correrían"],"h":"-er, acción repetida.","e":"Regular -er verbs take -ían for 'ellos' in the imperfect."},{"p":"Yo siempre ___ (ir) al cine los sábados.","a":"iba","w":["fui","voy","iría"],"h":"'Siempre' sugiere hábito.","e":"Habitual past actions use the imperfect; ir is irregular: yo iba."},{"p":"Ustedes ___ (escribir) cartas.","a":"escribían","w":["escribieron","escriben","escribirían"],"h":"-ir, tercera persona plural.","e":"Regular -ir verbs use -ían for ustedes/ellos in the imperfect."},{"p":"¿Cuál expresa una acción habitual del pasado?","a":"Todos los días caminaba a la escuela.","w":["Todos los días caminé a la escuela.","Todos los días camino a la escuela.","Todos los días caminaría a la escuela."],"h":"Rutina repetida = imperfecto.","e":"Repeated, habitual past actions require the imperfect (caminaba), not the preterite."},{"p":"Hacía frío y ___ (llover).","a":"llovía","w":["llovió","llueve","llovería"],"h":"Descripción del clima pasado.","e":"The imperfect describes ongoing background conditions like weather: 'llovía'."}],"sp.9.porpara":[{"p":"Gracias ___ tu ayuda.","a":"por","w":["para","pora","de"],"h":"Expresa el motivo.","e":"'Por' expresses the reason or cause, as in thanking for something."},{"p":"Este regalo es ___ ti.","a":"para","w":["por","pora","a"],"h":"El destinatario.","e":"'Para' marks the recipient of something."},{"p":"Estudio ___ ser médico.","a":"para","w":["por","pora","de"],"h":"El objetivo o meta.","e":"'Para' expresses purpose or goal (in order to)."},{"p":"Caminamos ___ el parque.","a":"por","w":["para","pora","en"],"h":"Movimiento a través de.","e":"'Por' indicates movement through or along a place."},{"p":"Trabajé ___ ocho horas.","a":"por","w":["para","pora","en"],"h":"Duración de tiempo.","e":"'Por' expresses duration of time."},{"p":"La tarea es ___ el lunes.","a":"para","w":["por","pora","en"],"h":"Fecha límite.","e":"'Para' marks a deadline or point in time by which something is due."},{"p":"Pagué veinte dólares ___ el libro.","a":"por","w":["para","pora","de"],"h":"Intercambio.","e":"'Por' expresses exchange, such as paying an amount for something."},{"p":"Salimos ___ Madrid mañana.","a":"para","w":["por","pora","a"],"h":"Destino final.","e":"'Para' indicates the destination toward which one is heading."},{"p":"¿Cuál es correcta? (propósito)","a":"Estudio para aprender.","w":["Estudio por aprender.","Estudio pora aprender.","Estudio a aprender."],"h":"Propósito = para.","e":"Purpose (in order to) is expressed with 'para'."},{"p":"Compré flores ___ mi madre.","a":"para","w":["por","pora","a"],"h":"El destinatario del regalo.","e":"'Para' marks the person who receives something."},{"p":"Estoy nervioso ___ el examen.","a":"por","w":["para","pora","de"],"h":"Causa del sentimiento.","e":"'Por' expresses the cause or reason for a feeling."},{"p":"Traduce: 'This gift is for you.'","a":"Este regalo es para ti","w":["Este regalo es por ti","Este regalo es para tú","Este regalo es por tú"],"h":"Destinatario + pronombre 'ti'.","e":"'Para' marks the recipient, and after a preposition the pronoun is 'ti'."},{"p":"Corrimos ___ la calle.","a":"por","w":["para","pora","en"],"h":"A lo largo de / a través de.","e":"'Por' indicates movement through or along a location."},{"p":"Necesito el informe ___ el viernes.","a":"para","w":["por","pora","en"],"h":"Plazo de entrega.","e":"'Para' expresses a deadline by which something is needed."},{"p":"¿Cuál muestra causa o motivo?","a":"Lo hago por amor.","w":["Lo hago para amor.","Lo hago pora amor.","Lo hago de amor."],"h":"Motivo/emoción = por.","e":"'Por' expresses the underlying cause or motivation of an action."},{"p":"Voy a la tienda ___ pan.","a":"por","w":["para","pora","de"],"h":"En busca de algo.","e":"'Por' is used to mean 'in search of' when going to get something."}],"sp.10.commands":[{"p":"___ más despacio, por favor. (hablar, tú afirmativo)","a":"Habla","w":["Hablas","Hable","No hables"],"h":"Mandato tú = 3ª persona presente.","e":"The affirmative tú command of regular -ar verbs matches the present él/ella form: 'habla'."},{"p":"___ las verduras. (comer, tú afirmativo)","a":"Come","w":["Comes","Coma","No comas"],"h":"Igual a él/ella en presente.","e":"Affirmative tú commands of -er verbs use the él/ella present form: 'come'."},{"p":"___ tu nombre aquí. (escribir, tú afirmativo)","a":"Escribe","w":["Escribes","Escriba","No escribas"],"h":"Forma afirmativa de 'tú'.","e":"The affirmative tú command of -ir verbs is the él/ella present form: 'escribe'."},{"p":"No ___ tan rápido. (hablar, tú negativo)","a":"hables","w":["hablas","habla","hable"],"h":"Negativo tú usa subjuntivo.","e":"Negative tú commands use the present subjunctive: 'no hables'."},{"p":"No ___ eso. (comer, tú negativo)","a":"comas","w":["comes","come","coma"],"h":"Subjuntivo con 'no'.","e":"Negative tú commands of -er verbs use the subjunctive: 'no comas'."},{"p":"___ con el gerente. (hablar, usted)","a":"Hable","w":["Habla","Hablas","Hables"],"h":"Mandato formal = subjuntivo.","e":"Formal usted commands use the present subjunctive form: 'hable'."},{"p":"___ la tarea. (hacer, tú irregular)","a":"Haz","w":["Hace","Haga","Haces"],"h":"Irregular de 'hacer'.","e":"The irregular affirmative tú command of hacer is 'haz'."},{"p":"___ aquí ahora mismo. (venir, tú irregular)","a":"Ven","w":["Viene","Venga","Vienes"],"h":"Irregular de 'venir'.","e":"The irregular affirmative tú command of venir is 'ven'."},{"p":"___ la verdad. (decir, tú irregular)","a":"Di","w":["Dice","Diga","Dices"],"h":"Irregular de 'decir'.","e":"The irregular affirmative tú command of decir is 'di'."},{"p":"___ bueno con tu hermano. (ser, tú irregular)","a":"Sé","w":["Se","Sea","Eres"],"h":"Lleva acento.","e":"The irregular tú command of ser is 'sé', written with an accent."},{"p":"___ de la casa. (salir, tú irregular)","a":"Sal","w":["Sale","Salga","Sales"],"h":"Irregular de 'salir'.","e":"The irregular affirmative tú command of salir is 'sal'."},{"p":"___ paciencia. (tener, tú irregular)","a":"Ten","w":["Tiene","Tenga","Tienes"],"h":"Irregular de 'tener'.","e":"The irregular affirmative tú command of tener is 'ten'."},{"p":"___ al mercado. (ir, tú irregular)","a":"Ve","w":["Va","Vaya","Vas"],"h":"Irregular de 'ir'.","e":"The irregular affirmative tú command of ir is 've'."},{"p":"___ la mesa. (poner, tú irregular)","a":"Pon","w":["Pone","Ponga","Pones"],"h":"Irregular de 'poner'.","e":"The irregular affirmative tú command of poner is 'pon'."},{"p":"¿Cuál es el mandato negativo de 'tú' correcto?","a":"No corras.","w":["No corres.","No corre.","No corra."],"h":"Negativo tú = subjuntivo.","e":"Negative tú commands use the tú subjunctive ending: 'no corras'."},{"p":"Traduce: 'Eat! (informal)'","a":"¡Come!","w":["¡Comes!","¡Coma!","¡Comer!"],"h":"Mandato afirmativo tú.","e":"The informal affirmative command 'Eat!' is 'Come!' using the él/ella present form."}],"sp.11.futcond":[{"p":"Yo ___ (hablar) con él mañana.","a":"hablaré","w":["hablará","hablaría","hablo"],"h":"Futuro de 'yo': -é.","e":"The simple future adds -é to the infinitive for 'yo': 'hablaré'."},{"p":"Tú ___ (comer) más tarde.","a":"comerás","w":["comerá","comerías","comes"],"h":"Futuro de 'tú': -ás.","e":"The future of 'tú' adds -ás to the infinitive: 'comerás'."},{"p":"Nosotros ___ (vivir) aquí el año que viene.","a":"viviremos","w":["viviríamos","vivirán","vivimos"],"h":"Futuro de 'nosotros': -emos.","e":"The future 'nosotros' ending is -emos: 'viviremos'."},{"p":"Ellos ___ (viajar) a Perú.","a":"viajarán","w":["viajaran","viajarían","viajan"],"h":"Futuro lleva acento en la 'á'.","e":"The future 'ellos' ending is -án with an accent, distinguishing 'viajarán' from the subjunctive 'viajaran'."},{"p":"Yo ___ (hablar) con él si pudiera.","a":"hablaría","w":["hablaré","hablaba","hablará"],"h":"Condicional: -ía.","e":"The conditional adds -ía to the infinitive to mean 'would': 'hablaría'."},{"p":"Tú ___ (comer) si tuvieras hambre.","a":"comerías","w":["comerás","comías","comería"],"h":"Condicional de 'tú': -ías.","e":"The conditional 'tú' ending is -ías: 'comerías' (you would eat)."},{"p":"Yo ___ (tener) tiempo mañana.","a":"tendré","w":["teneré","tendría","tengo"],"h":"Raíz irregular: tendr-.","e":"Tener has the irregular future stem 'tendr-': 'tendré'."},{"p":"Ella ___ (hacer) la tarea esta noche.","a":"hará","w":["hacerá","haría","hace"],"h":"Raíz irregular: har-.","e":"Hacer uses the irregular future stem 'har-': 'hará'."},{"p":"Yo ___ (poder) ayudarte.","a":"podría","w":["poderría","podré","puedo"],"h":"Condicional, raíz podr-.","e":"Poder uses the irregular stem 'podr-'; the conditional is 'podría' (I would be able)."},{"p":"Nosotros ___ (salir) pronto.","a":"saldremos","w":["saliremos","saldríamos","salimos"],"h":"Raíz irregular: saldr-.","e":"Salir has the irregular future stem 'saldr-': 'saldremos'."},{"p":"Ellos ___ (venir) a la fiesta.","a":"vendrán","w":["venirán","vendrían","vienen"],"h":"Raíz irregular: vendr-.","e":"Venir uses the irregular future stem 'vendr-': 'vendrán'."},{"p":"Yo ___ (decir) la verdad.","a":"diría","w":["deciría","diré","digo"],"h":"Condicional, raíz dir-.","e":"Decir has the irregular stem 'dir-'; the conditional is 'diría' (I would say)."},{"p":"Traduce: 'I will travel.'","a":"Viajaré","w":["Viajaría","Viajaba","Viajo"],"h":"'Will' = futuro.","e":"'Will travel' is the simple future: 'viajaré'."},{"p":"Traduce: 'She would eat.'","a":"Ella comería","w":["Ella comerá","Ella comía","Ella come"],"h":"'Would' = condicional.","e":"'Would eat' is the conditional: 'comería'."},{"p":"¿Cuál expresa 'would' (condicional)?","a":"Iría al cine.","w":["Iré al cine.","Iba al cine.","Voy al cine."],"h":"'Would' = -ía.","e":"The conditional 'iría' means 'would go', unlike the future 'iré' (will go)."},{"p":"Usted ___ (poner) la mesa.","a":"pondrá","w":["ponerá","pondría","pone"],"h":"Futuro, raíz pondr-.","e":"Poner uses the irregular future stem 'pondr-': 'pondrá'."}],"sp.11.perfect":[{"p":"Yo ___ comido ya.","a":"he","w":["ha","has","hemos"],"h":"Auxiliar 'haber' para 'yo'.","e":"The present perfect uses haber; 'yo' takes 'he' before the participle."},{"p":"Ella ___ hablado con el profesor.","a":"ha","w":["he","has","han"],"h":"'Haber' para él/ella.","e":"For 'ella', the auxiliary haber is 'ha'."},{"p":"Nosotros ___ vivido aquí diez años.","a":"hemos","w":["han","ha","he"],"h":"'Haber' para 'nosotros'.","e":"For 'nosotros', the auxiliary haber is 'hemos'."},{"p":"Participio de 'hablar': he ___.","a":"hablado","w":["hablando","hablido","habló"],"h":"-ar → -ado.","e":"Regular -ar verbs form the past participle with -ado: 'hablado'."},{"p":"Participio de 'comer': he ___.","a":"comido","w":["comiendo","comado","comí"],"h":"-er → -ido.","e":"Regular -er verbs form the past participle with -ido: 'comido'."},{"p":"Participio irregular de 'hacer': he ___.","a":"hecho","w":["hacido","hacho","hice"],"h":"Irregular.","e":"Hacer has the irregular past participle 'hecho'."},{"p":"Participio irregular de 'decir': he ___.","a":"dicho","w":["decido","dicido","dije"],"h":"Irregular.","e":"Decir has the irregular past participle 'dicho'."},{"p":"Participio irregular de 'ver': he ___.","a":"visto","w":["veído","vido","vi"],"h":"Irregular.","e":"Ver has the irregular past participle 'visto'."},{"p":"Participio irregular de 'escribir': he ___.","a":"escrito","w":["escribido","escribto","escribí"],"h":"Irregular.","e":"Escribir has the irregular past participle 'escrito'."},{"p":"Participio irregular de 'poner': he ___.","a":"puesto","w":["ponido","ponto","puse"],"h":"Irregular.","e":"Poner has the irregular past participle 'puesto'."},{"p":"Participio irregular de 'volver': he ___.","a":"vuelto","w":["volvido","volto","volví"],"h":"Irregular.","e":"Volver has the irregular past participle 'vuelto'."},{"p":"Participio irregular de 'abrir': he ___.","a":"abierto","w":["abrido","abrito","abrí"],"h":"Irregular.","e":"Abrir has the irregular past participle 'abierto'."},{"p":"Traduce: 'I have eaten.'","a":"He comido","w":["He comer","He comiendo","Ha comido"],"h":"'Haber' + participio.","e":"The present perfect combines 'he' with the participle 'comido'."},{"p":"Traduce: 'They have seen the movie.'","a":"Han visto la película","w":["Han veído la película","Ha visto la película","Han ver la película"],"h":"'han' + participio irregular.","e":"'They have seen' is 'han visto', using the irregular participle of ver."},{"p":"¿ ___ (tú) terminado la tarea?","a":"Has","w":["Ha","He","Han"],"h":"'Haber' para 'tú'.","e":"For 'tú', the auxiliary haber is 'has'."},{"p":"¿Cuál es correcta?","a":"Hemos vuelto.","w":["Hemos volvido.","Habemos vuelto.","Hemos volver."],"h":"'hemos' + participio irregular.","e":"The present perfect of volver is 'hemos vuelto', using the irregular participle."}],"sp.12.subjunctive2":[{"p":"Espero que tú ___ (hablar) español.","a":"hables","w":["hablas","hablar","hablabas"],"h":"'Espero que' pide subjuntivo.","e":"Expressions of wish like 'espero que' trigger the subjunctive: 'hables'."},{"p":"Dudo que él ___ (venir) hoy.","a":"venga","w":["viene","vendrá","vino"],"h":"La duda pide subjuntivo.","e":"Doubt ('dudo que') triggers the subjunctive; venir becomes 'venga'."},{"p":"Es importante que nosotros ___ (estudiar).","a":"estudiemos","w":["estudiamos","estudiar","estudiaremos"],"h":"Expresión impersonal + subjuntivo.","e":"Impersonal expressions like 'es importante que' require the subjunctive: 'estudiemos'."},{"p":"Ojalá que ___ (llover) mañana.","a":"llueva","w":["llueve","lloverá","llovía"],"h":"'Ojalá que' + subjuntivo.","e":"'Ojalá que' expresses a wish and always takes the subjunctive: 'llueva'."},{"p":"Quiero que ella ___ (comer) algo.","a":"coma","w":["come","comer","comerá"],"h":"Deseo con dos cláusulas.","e":"A wish with a change of subject uses 'que' + subjunctive: 'coma'."},{"p":"Me alegro de que ustedes ___ (estar) aquí.","a":"estén","w":["están","estar","estarán"],"h":"Emoción + subjuntivo.","e":"Emotion ('me alegro de que') triggers the subjunctive; estar becomes 'estén'."},{"p":"Subjuntivo de 'hablar' (yo): que yo ___.","a":"hable","w":["hablo","hablé","hablaré"],"h":"-ar → -e.","e":"Regular -ar verbs form the present subjunctive with -e endings: 'hable'."},{"p":"Subjuntivo de 'comer' (tú): que tú ___.","a":"comas","w":["comes","comiste","comerás"],"h":"-er → -as.","e":"Regular -er verbs form the subjunctive with -a endings: 'comas'."},{"p":"Subjuntivo de 'vivir' (nosotros): que nosotros ___.","a":"vivamos","w":["vivimos","viviremos","vivíamos"],"h":"-ir → -amos.","e":"Regular -ir verbs form the subjunctive with -a endings: 'vivamos'."},{"p":"¿Cuál frase requiere subjuntivo?","a":"Es necesario que estudies.","w":["Es verdad que estudias.","Sé que estudias.","Es obvio que estudias."],"h":"Necesidad vs certeza.","e":"Impersonal expressions of necessity trigger the subjunctive, while certainty uses the indicative."},{"p":"Traduce: 'I hope you win.'","a":"Espero que ganes","w":["Espero que ganas","Espero que ganar","Espero que ganarás"],"h":"Deseo + que + subjuntivo.","e":"'Espero que' plus a change of subject requires the subjunctive 'ganes'."},{"p":"No creo que ___ (ser) verdad.","a":"sea","w":["es","será","era"],"h":"Duda/negación de creencia.","e":"'No creo que' expresses doubt and triggers the subjunctive: 'sea'."},{"p":"Es triste que ellos no ___ (poder) venir.","a":"puedan","w":["pueden","podrán","podían"],"h":"Emoción impersonal + subjuntivo.","e":"Emotional impersonal expressions ('es triste que') require the subjunctive: 'puedan'."},{"p":"Te recomiendo que ___ (leer) este libro.","a":"leas","w":["lees","leer","leerás"],"h":"Recomendación + subjuntivo.","e":"Verbs of influence like 'recomendar que' trigger the subjunctive: 'leas'."},{"p":"¿Cuál es correcta después de 'dudo que'?","a":"Dudo que tenga razón.","w":["Dudo que tiene razón.","Dudo que tendrá razón.","Dudo que tenía razón."],"h":"Duda = subjuntivo.","e":"'Dudo que' expresses doubt, so the following verb must be subjunctive: 'tenga'."},{"p":"Prohíben que los estudiantes ___ (usar) el móvil.","a":"usen","w":["usan","usar","usarán"],"h":"Verbo de voluntad + subjuntivo.","e":"Verbs of prohibition ('prohibir que') require the subjunctive: 'usen'."}],"sp.12.idioms":[{"p":"¿Qué significa 'tener ganas de'?","a":"to feel like (doing something)","w":["to be angry","to be afraid","to be in a hurry"],"h":"Deseo de hacer algo.","e":"'Tener ganas de' means to feel like doing something."},{"p":"¿Qué significa 'echar de menos'?","a":"to miss (someone)","w":["to throw away","to have less","to need something"],"h":"Sentir la ausencia.","e":"'Echar de menos' means to miss someone or something."},{"p":"¿Qué significa 'tener prisa'?","a":"to be in a hurry","w":["to be tired","to lend money","to be right"],"h":"Poco tiempo.","e":"'Tener prisa' means to be in a hurry."},{"p":"¿Qué significa 'valer la pena'?","a":"to be worth it","w":["to feel pain","to be worthless","to cost a lot"],"h":"Merecer el esfuerzo.","e":"'Valer la pena' means to be worth the effort."},{"p":"¿Qué significa 'dar igual'?","a":"to not matter","w":["to give equally","to be the same size","to agree"],"h":"Indiferencia.","e":"'Dar igual' means that something does not matter or makes no difference."},{"p":"¿Qué significa 'tomar el pelo'?","a":"to tease / pull someone's leg","w":["to comb one's hair","to take a nap","to grab someone's hair"],"h":"Bromear con alguien.","e":"'Tomar el pelo' means to tease someone or pull their leg."},{"p":"¿Qué significa 'estar de acuerdo'?","a":"to agree","w":["to be in tune","to remember","to be awake"],"h":"Misma opinión.","e":"'Estar de acuerdo' means to be in agreement with someone."},{"p":"¿Qué significa 'hacer falta'?","a":"to be necessary / lacking","w":["to make a mistake","to miss a person","to fail an exam"],"h":"Necesitar algo.","e":"'Hacer falta' means to be needed or necessary."},{"p":"Tengo ___ de comer pizza.","a":"ganas","w":["prisa","falta","pelo"],"h":"Sentir deseo.","e":"'Tener ganas de' means to feel like doing something."},{"p":"___ de menos a mi familia.","a":"Echo","w":["Tengo","Hago","Doy"],"h":"Extrañar.","e":"The expression 'echar de menos' uses the verb echar: 'echo de menos'."},{"p":"Corre, tenemos ___.","a":"prisa","w":["ganas","falta","razón"],"h":"Poco tiempo.","e":"'Tener prisa' means to be in a hurry."},{"p":"Ese viaje vale la ___.","a":"pena","w":["falta","prisa","cuenta"],"h":"Merece el esfuerzo.","e":"'Valer la pena' means to be worth it."},{"p":"Traduce: 'It doesn't matter to me.'","a":"Me da igual","w":["Me da igualdad","Yo doy igual","Me hace igual"],"h":"Modismo de indiferencia.","e":"'Me da igual' is the idiom for 'it doesn't matter to me'."},{"p":"No me engañes, ¿me estás tomando el ___?","a":"pelo","w":["brazo","pie","codo"],"h":"Bromear.","e":"'Tomar el pelo' means to pull someone's leg or tease them."},{"p":"Estoy de ___ contigo.","a":"acuerdo","w":["acuerdas","cuerda","recuerdo"],"h":"Misma opinión.","e":"'Estar de acuerdo' means to agree with someone."},{"p":"Me ___ falta más tiempo para terminar.","a":"hace","w":["tengo","doy","echo"],"h":"Necesitar.","e":"'Hacer falta' uses the verb hacer to mean something is needed: 'me hace falta'."}],"sp.2.ropa":[{"p":"¿Qué es 'camisa' en inglés?","a":"Shirt","w":["Shoe","Hat","Sock"],"h":"You wear it on your upper body.","e":"'Camisa' means shirt."},{"p":"¿Cómo se dice 'pants' en español?","a":"Pantalones","w":["Zapatos","Sombrero","Falda"],"h":"They cover both of your legs.","e":"'Pants' is 'pantalones' in Spanish."},{"p":"¿Qué es 'zapatos' en inglés?","a":"Shoes","w":["Socks","Gloves","Belt"],"h":"They go on your feet.","e":"'Zapatos' means shoes."},{"p":"¿Cómo se dice 'hat' en español?","a":"Sombrero","w":["Camisa","Falda","Calcetines"],"h":"It goes on your head.","e":"'Hat' is 'sombrero'."},{"p":"¿Qué es 'falda' en inglés?","a":"Skirt","w":["Dress","Jacket","Scarf"],"h":"It is often worn instead of pants.","e":"'Falda' means skirt."},{"p":"¿Cuál de estas palabras es ropa?","a":"Vestido","w":["Perro","Mesa","Árbol"],"h":"One of them is something you wear.","e":"'Vestido' (dress) is clothing."},{"p":"¿Cómo se dice 'socks' en español?","a":"Calcetines","w":["Zapatos","Guantes","Botas"],"h":"They go under your shoes.","e":"'Socks' is 'calcetines'."},{"p":"¿Qué es 'chaqueta' en inglés?","a":"Jacket","w":["Shirt","Shoe","Hat"],"h":"You wear it when it is cold.","e":"'Chaqueta' means jacket."},{"p":"Completa: Me pongo los ____ en los pies.","a":"zapatos","w":["guantes","sombreros","abrigos"],"h":"Think about what covers your feet.","e":"Shoes (zapatos) go on your feet."},{"p":"¿Cómo se dice 'dress' en español?","a":"Vestido","w":["Pantalones","Camisa","Cinturón"],"h":"It is a one-piece outfit.","e":"'Dress' is 'vestido'."},{"p":"¿Qué es 'guantes' en inglés?","a":"Gloves","w":["Socks","Boots","Belts"],"h":"They keep your hands warm.","e":"'Guantes' means gloves."},{"p":"¿Cuál de estas palabras NO es ropa?","a":"Gato","w":["Camisa","Falda","Zapatos"],"h":"Three of them are things you wear.","e":"'Gato' (cat) is an animal, not clothing."},{"p":"¿Cómo se dice 'coat' en español?","a":"Abrigo","w":["Calcetines","Vestido","Gorra"],"h":"A warm outer layer for winter.","e":"'Coat' is 'abrigo'."},{"p":"¿Qué es 'gorra' en inglés?","a":"Cap","w":["Shoe","Sock","Skirt"],"h":"A soft hat with a visor.","e":"'Gorra' means cap."},{"p":"Completa: En invierno llevo un ____ para el frío.","a":"abrigo","w":["vestido","calcetín","zapato"],"h":"Something warm for cold weather.","e":"A coat (abrigo) keeps you warm in winter."},{"p":"¿Cómo se dice 'boots' en español?","a":"Botas","w":["Guantes","Camisas","Faldas"],"h":"Tall shoes for rain or snow.","e":"'Boots' is 'botas'."}],"sp.3.cuerpo":[{"p":"¿Qué es 'cabeza' en inglés?","a":"Head","w":["Hand","Foot","Leg"],"h":"It sits on top of your body.","e":"'Cabeza' means head."},{"p":"¿Cómo se dice 'arm' en español?","a":"Brazo","w":["Pierna","Mano","Pie"],"h":"It connects to your hand.","e":"'Arm' is 'brazo'."},{"p":"¿Qué es 'mano' en inglés?","a":"Hand","w":["Foot","Ear","Nose"],"h":"It has five fingers.","e":"'Mano' means hand."},{"p":"¿Cómo se dice 'leg' en español?","a":"Pierna","w":["Brazo","Cabeza","Ojo"],"h":"You use it to walk.","e":"'Leg' is 'pierna'."},{"p":"¿Qué es 'ojos' en inglés?","a":"Eyes","w":["Ears","Hands","Feet"],"h":"You use them to see.","e":"'Ojos' means eyes."},{"p":"¿Cuál de estas palabras es parte del cuerpo?","a":"Nariz","w":["Silla","Libro","Casa"],"h":"One of them is on your face.","e":"'Nariz' (nose) is a body part."},{"p":"¿Cómo se dice 'mouth' en español?","a":"Boca","w":["Nariz","Oreja","Ojo"],"h":"You use it to eat and talk.","e":"'Mouth' is 'boca'."},{"p":"¿Qué es 'pie' en inglés?","a":"Foot","w":["Hand","Head","Arm"],"h":"It is at the end of your leg.","e":"'Pie' means foot."},{"p":"Completa: Escucho la música con las ____.","a":"orejas","w":["manos","piernas","narices"],"h":"Think about what you hear with.","e":"You listen with your ears (orejas)."},{"p":"¿Cómo se dice 'hair' en español?","a":"Pelo","w":["Boca","Diente","Cuello"],"h":"It grows on your head.","e":"'Hair' is 'pelo'."},{"p":"¿Qué es 'dientes' en inglés?","a":"Teeth","w":["Toes","Fingers","Knees"],"h":"You use them to chew food.","e":"'Dientes' means teeth."},{"p":"¿Cuál de estas palabras NO es parte del cuerpo?","a":"Ventana","w":["Brazo","Pierna","Cabeza"],"h":"Three of them are on your body.","e":"'Ventana' (window) is not a body part."},{"p":"¿Cómo se dice 'neck' en español?","a":"Cuello","w":["Hombro","Codo","Rodilla"],"h":"It is between your head and shoulders.","e":"'Neck' is 'cuello'."},{"p":"Completa: Veo el mundo con los ____.","a":"ojos","w":["pies","dedos","dientes"],"h":"Think about what you see with.","e":"You see with your eyes (ojos)."},{"p":"¿Qué es 'dedos' en inglés?","a":"Fingers","w":["Elbows","Knees","Shoulders"],"h":"You have five on each hand.","e":"'Dedos' means fingers."},{"p":"¿Cómo se dice 'shoulder' en español?","a":"Hombro","w":["Cuello","Rodilla","Codo"],"h":"Your arm connects to your body here.","e":"'Shoulder' is 'hombro'."}],"sp.6.lugares":[{"p":"¿Qué es 'biblioteca' en inglés?","a":"Library","w":["Bookstore","School","Museum"],"h":"A place to borrow books for free.","e":"'Biblioteca' means library."},{"p":"¿Cómo se dice 'pharmacy' en español?","a":"Farmacia","w":["Panadería","Biblioteca","Estación"],"h":"Where you buy medicine.","e":"'Pharmacy' is 'farmacia'."},{"p":"¿Qué es 'mercado' en inglés?","a":"Market","w":["Bank","Park","Church"],"h":"Where you buy fresh food.","e":"'Mercado' means market."},{"p":"¿Cómo se dice 'bank' en español?","a":"Banco","w":["Museo","Parque","Cine"],"h":"Where you keep and withdraw money.","e":"'Bank' is 'banco'."},{"p":"¿Qué es 'iglesia' en inglés?","a":"Church","w":["School","Store","Station"],"h":"A place of worship.","e":"'Iglesia' means church."},{"p":"Completa: Voy al ____ para ver una película.","a":"cine","w":["banco","mercado","hospital"],"h":"Where movies are shown on a big screen.","e":"You watch films at the cinema (cine)."},{"p":"¿Cómo se dice 'post office' en español?","a":"Correo","w":["Escuela","Farmacia","Parque"],"h":"Where you send letters and packages.","e":"'Post office' is 'correo'."},{"p":"¿Qué es 'panadería' en inglés?","a":"Bakery","w":["Butcher shop","Grocery store","Restaurant"],"h":"Where bread is baked and sold.","e":"'Panadería' means bakery."},{"p":"¿Cuál de estos lugares es donde estudias?","a":"Escuela","w":["Piscina","Estadio","Aeropuerto"],"h":"Students go here to learn.","e":"'Escuela' (school) is where you study."},{"p":"¿Cómo se dice 'museum' en español?","a":"Museo","w":["Teatro","Mercado","Correo"],"h":"Where art and history are displayed.","e":"'Museum' is 'museo'."},{"p":"¿Qué es 'estación de tren' en inglés?","a":"Train station","w":["Airport","Bus stop","Harbor"],"h":"Where trains arrive and depart.","e":"'Estación de tren' means train station."},{"p":"Completa: Compro pan fresco en la ____.","a":"panadería","w":["biblioteca","gasolinera","comisaría"],"h":"The place that bakes bread.","e":"You buy fresh bread at the bakery (panadería)."},{"p":"¿Cómo se dice 'park' en español?","a":"Parque","w":["Plaza","Calle","Puente"],"h":"A green space to play and relax.","e":"'Park' is 'parque'."},{"p":"¿Qué es 'ayuntamiento' en inglés?","a":"City hall","w":["Courthouse","Police station","Fire station"],"h":"Where the local government works.","e":"'Ayuntamiento' means city hall."},{"p":"¿Cuál de estas palabras NO es un lugar de la ciudad?","a":"Cuchara","w":["Biblioteca","Estadio","Farmacia"],"h":"Three are places; one is a kitchen item.","e":"'Cuchara' (spoon) is not a place."},{"p":"¿Cómo se dice 'gas station' en español?","a":"Gasolinera","w":["Comisaría","Peluquería","Zapatería"],"h":"Where cars fill up with fuel.","e":"'Gas station' is 'gasolinera'."}],"e.4.grammar":[{"p":"What part of speech is 'quickly' in: 'She ran quickly.'?","a":"Adverb","w":["Adjective","Noun","Verb"],"h":"It describes how the action was done.","e":"'Quickly' describes the verb 'ran', so it is an adverb."},{"p":"What part of speech is 'happy' in: 'The happy dog barked.'?","a":"Adjective","w":["Adverb","Noun","Pronoun"],"h":"It describes the dog.","e":"'Happy' describes the noun 'dog', so it is an adjective."},{"p":"What part of speech is 'jump' in: 'The children jump on the bed.'?","a":"Verb","w":["Noun","Adjective","Preposition"],"h":"It is the action word in the sentence.","e":"'Jump' shows action, so it is a verb."},{"p":"What part of speech is 'city' in: 'They visited the city.'?","a":"Noun","w":["Verb","Adverb","Conjunction"],"h":"It names a place.","e":"'City' names a place, so it is a noun."},{"p":"What part of speech is 'she' in: 'She likes apples.'?","a":"Pronoun","w":["Noun","Verb","Adjective"],"h":"It takes the place of a name.","e":"'She' replaces a noun, so it is a pronoun."},{"p":"What part of speech is 'under' in: 'The cat hid under the table.'?","a":"Preposition","w":["Adverb","Conjunction","Verb"],"h":"It shows where the cat is.","e":"'Under' shows position, so it is a preposition."},{"p":"What part of speech is 'and' in: 'I have a cat and a dog.'?","a":"Conjunction","w":["Preposition","Pronoun","Adverb"],"h":"It joins two words together.","e":"'And' connects words, so it is a conjunction."},{"p":"Which sentence is correct?","a":"The dogs run fast.","w":["The dogs runs fast.","The dog run fast.","The dogs running fast."],"h":"Match the verb to a plural subject.","e":"The plural subject 'dogs' takes the verb 'run'."},{"p":"Which sentence is correct?","a":"She walks to school every day.","w":["She walk to school every day.","She walking to school every day.","She to school walks every day."],"h":"A singular subject needs the -s verb form in the present.","e":"'She' takes 'walks' in the present tense."},{"p":"What is the plural of 'child'?","a":"Children","w":["Childs","Childes","Childern"],"h":"It is an irregular plural.","e":"The plural of 'child' is 'children'."},{"p":"What is the plural of 'mouse'?","a":"Mice","w":["Mouses","Mouse","Mices"],"h":"It is an irregular plural.","e":"The plural of 'mouse' is 'mice'."},{"p":"Which sentence is in the past tense?","a":"We played outside yesterday.","w":["We play outside today.","We will play outside soon.","We are playing outside now."],"h":"Look for an action that already happened.","e":"'Played' is the past tense of 'play'."},{"p":"Which word is a proper noun?","a":"London","w":["city","river","country"],"h":"It names one specific place and is capitalized.","e":"'London' names a specific city, so it is a proper noun."},{"p":"What part of speech is 'loudly' in: 'He sang loudly.'?","a":"Adverb","w":["Adjective","Noun","Verb"],"h":"It tells how he sang.","e":"'Loudly' describes the verb 'sang', so it is an adverb."},{"p":"Which sentence correctly shows a future action?","a":"I will finish my homework tonight.","w":["I finished my homework tonight.","I finish my homework last night.","I finishing my homework tonight."],"h":"The future needs a helping word.","e":"'Will finish' shows a future action."},{"p":"Which sentence has correct subject-verb agreement?","a":"The team is ready to play.","w":["The team are ready to play.","The team be ready to play.","The team am ready to play."],"h":"'Team' acts as one single group here.","e":"'Team' is singular, so it takes 'is'."}],"e.4.genres":[{"p":"Which genre tells a made-up story that could really happen?","a":"Realistic fiction","w":["Fantasy","Biography","Poetry"],"h":"Invented, but believable in real life.","e":"Realistic fiction is made up but could happen in real life."},{"p":"Which genre is a true story of a person's life written by someone else?","a":"Biography","w":["Autobiography","Fantasy","Fable"],"h":"'Bio' means life; it is written by another person.","e":"A biography is a true account of a person's life written by another author."},{"p":"A short story with talking animals that teaches a lesson is a...?","a":"Fable","w":["Myth","Biography","Poem"],"h":"Animals act like people and there is a moral.","e":"A fable uses animal characters to teach a moral lesson."},{"p":"Which genre uses rhythm, and sometimes rhyme, arranged in lines and stanzas?","a":"Poetry","w":["Drama","Informational text","Fable"],"h":"It is written in lines and stanzas.","e":"Poetry uses rhythm and lines, often with rhyme."},{"p":"A story with dragons, magic, and impossible events is...?","a":"Fantasy","w":["Realistic fiction","Biography","Informational text"],"h":"It includes things that cannot really happen.","e":"Fantasy contains magic and impossible events."},{"p":"Which genre is written to be performed by actors on a stage?","a":"Drama","w":["Poetry","Fable","Myth"],"h":"It has a script with dialogue and stage directions.","e":"Drama (a play) is meant to be acted out on a stage."},{"p":"An old story that explains nature, often with gods, is a...?","a":"Myth","w":["Biography","Realistic fiction","Informational text"],"h":"It often features gods and explains the natural world.","e":"A myth explains natural events, often involving gods."},{"p":"Which text gives real facts to teach about a topic?","a":"Informational text","w":["Fantasy","Fable","Poetry"],"h":"Its main purpose is to inform with facts.","e":"Informational text presents facts to teach about a topic."},{"p":"A traditional story passed down by word of mouth is a...?","a":"Folktale","w":["Biography","Informational text","Autobiography"],"h":"It is passed down through generations by telling.","e":"A folktale is a traditional story handed down orally."},{"p":"Which of these is nonfiction?","a":"A book about how volcanoes erupt","w":["A story about a talking dragon","A poem about the moon","A fable about a clever fox"],"h":"Nonfiction is based on real facts.","e":"A book explaining real volcanoes is nonfiction."},{"p":"Which of these is fiction?","a":"A story about a boy who flies to Mars in a dream","w":["A guide to caring for dogs","A biography of a president","An encyclopedia entry on rocks"],"h":"Fiction comes from the author's imagination.","e":"An imagined story about flying to Mars is fiction."},{"p":"A true life story written by that same person is a(n)...?","a":"Autobiography","w":["Biography","Fable","Myth"],"h":"'Auto' means self.","e":"An autobiography is a life story written by the person themselves."},{"p":"Which genre would explain the steps to build a birdhouse?","a":"Informational text","w":["Poetry","Fantasy","Folktale"],"h":"It gives facts and clear directions.","e":"Step-by-step instructions are a form of informational text."},{"p":"A poem does NOT usually need which of these?","a":"Chapters","w":["Lines","Rhythm","Stanzas"],"h":"Think about how poems are organized.","e":"Poems use lines and stanzas, not chapters."},{"p":"Which genre features a hero with superpowers battling a made-up monster?","a":"Fantasy","w":["Biography","Informational text","Realistic fiction"],"h":"Superpowers and monsters are not real.","e":"Superpowers and monsters make this fantasy."},{"p":"Cinderella, retold for generations with a magical helper, is best called a...?","a":"Folktale","w":["Biography","Informational text","Autobiography"],"h":"A traditional story retold over time.","e":"Cinderella is a classic folktale passed down through generations."}],"e.10.tonemood":[{"p":"In literary analysis, what does 'tone' most precisely refer to?","a":"The author's attitude toward the subject","w":["The reader's emotional response to the text","The rhythm and meter of the sentences","The physical setting of the story"],"h":"Consider who is doing the feeling: the writer or the reader.","e":"Tone is the writer's attitude toward the subject, revealed through word choice and style."},{"p":"In literary analysis, what does 'mood' most precisely refer to?","a":"The emotional atmosphere a reader feels","w":["The author's opinion of the topic","The number of syllables in each line","The moral lesson of the story"],"h":"Think about the feeling created in the audience, not the writer.","e":"Mood is the emotional atmosphere the text creates in the reader."},{"p":"What mood does this excerpt create? 'The old clock ticked on, indifferent to the empty chairs and the dust settling over what once was a home.'","a":"Melancholic","w":["Jubilant","Suspenseful","Whimsical"],"h":"Notice the emptiness, dust, and sense of loss.","e":"Images of emptiness and decay evoke a sorrowful, melancholic mood."},{"p":"A 'somber' tone is best described as:","a":"Grave and gloomy","w":["Light and playful","Angry and bitter","Hopeful and bright"],"h":"Associate the word with seriousness and darkness.","e":"Somber means serious, dark, and gloomy in feeling."},{"p":"A 'sardonic' tone is best defined as:","a":"Mockingly scornful","w":["Warmly affectionate","Deeply sorrowful","Calmly neutral"],"h":"It combines mockery with a bitter or scornful edge.","e":"Sardonic describes grimly mocking or scornful expression."},{"p":"What is the tone of this line? 'Oh, wonderful, another Monday and another chance to watch the coffee machine break just as the meeting starts.'","a":"Sardonic","w":["Reverent","Nostalgic","Serene"],"h":"The praise is clearly not sincere.","e":"The mock-praise about misfortune signals a sardonic, sarcastic tone."},{"p":"A 'nostalgic' tone conveys:","a":"A wistful longing for the past","w":["Fear of the future","Anger at injustice","Pure joy in the present moment"],"h":"Think of a sentimental look backward in time.","e":"Nostalgia is a wistful, sentimental longing for the past."},{"p":"What mood does this excerpt create? 'Sunlight poured through the windows, and laughter echoed as the children raced across the blooming meadow.'","a":"Joyful","w":["Ominous","Grief-stricken","Tense"],"h":"Notice the light, laughter, and blossoming imagery.","e":"Warm, lively images of light and laughter create a joyful mood."},{"p":"Which word most clearly signals an ominous mood?","a":"Foreboding","w":["Cheerful","Playful","Tranquil"],"h":"Look for the word that hints at coming danger.","e":"Foreboding suggests a threatening sense of something bad approaching."},{"p":"A writer's biting, sarcastic word choice most directly shapes the text's:","a":"Tone","w":["Mood","Rhyme scheme","Plot structure"],"h":"Word choice reveals the author's own attitude.","e":"Word choice expresses the author's attitude, which is tone."},{"p":"A 'reverent' tone conveys:","a":"Deep respect and awe","w":["Casual indifference","Bitter contempt","Nervous fear"],"h":"Think of how one speaks in a sacred place.","e":"Reverent means showing deep respect, honor, and awe."},{"p":"What is the tone toward the setting here? 'We bowed our heads in the vast cathedral, voices hushed beneath the ancient, soaring arches.'","a":"Reverent","w":["Dismissive","Mocking","Frivolous"],"h":"Notice the bowed heads and hushed voices.","e":"The hushed, humble description conveys a reverent tone of awe."},{"p":"'Wry' humor is best described as:","a":"Dryly amused and clever","w":["Loud and slapstick","Cruel and cutting","Sappy and sentimental"],"h":"Think understated cleverness, not broad comedy.","e":"Wry humor is dry, subtle, and cleverly amused."},{"p":"What mood does this excerpt create? 'The fog crept low over the graveyard, and somewhere a gate groaned on rusted hinges.'","a":"Eerie","w":["Uplifting","Comic","Peaceful"],"h":"Consider the creeping fog and the groaning gate.","e":"The graveyard, fog, and groaning gate build an eerie, unsettling mood."},{"p":"Which statement best distinguishes tone from mood?","a":"Tone is the author's attitude; mood is the feeling created in the reader","w":["Tone is the plot; mood is the theme","Tone is the setting; mood is the main character","Tone and mood are identical terms"],"h":"One belongs to the writer, the other to the audience.","e":"Tone reflects the author's attitude; mood is the reader's felt atmosphere."},{"p":"What is the tone of this line? 'Though the war had taken much, she smiled, certain that dawn would come again.'","a":"Hopeful","w":["Despairing","Sarcastic","Indifferent"],"h":"Focus on her smile and her certainty about the future.","e":"Confidence that dawn will return signals a hopeful tone."}],"e.10.poetry":[{"p":"A traditional sonnet contains how many lines?","a":"14","w":["12","10","16"],"h":"It is a fixed form ending with a couplet or sestet.","e":"A sonnet is a 14-line poem, typically in iambic pentameter."},{"p":"A haiku traditionally follows which syllable pattern across its three lines?","a":"5-7-5","w":["7-5-7","5-5-5","3-5-3"],"h":"The middle line is the longest.","e":"A traditional haiku has 5, 7, and 5 syllables in its three lines."},{"p":"Which device appears in this line? 'The wind whispered secrets through the trees.'","a":"Personification","w":["Simile","Hyperbole","Onomatopoeia"],"h":"A nonhuman thing is given a human ability.","e":"Giving the wind the human ability to whisper is personification."},{"p":"Which device appears in this line? 'Her smile was as bright as the morning sun.'","a":"Simile","w":["Metaphor","Personification","Alliteration"],"h":"Look for a comparison using 'like' or 'as'.","e":"The comparison using 'as' makes this a simile."},{"p":"Which device appears in this line? 'Life is a broken-winged bird that cannot fly.'","a":"Metaphor","w":["Simile","Hyperbole","Assonance"],"h":"Two unlike things are equated without 'like' or 'as'.","e":"Directly equating life with a bird is a metaphor."},{"p":"Which device appears in this line? 'Peter Piper picked a peck of pickled peppers.'","a":"Alliteration","w":["Assonance","End rhyme","Personification"],"h":"Listen to the repeated initial consonant sound.","e":"The repeated initial 'p' sound is alliteration."},{"p":"The repetition of vowel sounds within nearby words is called:","a":"Assonance","w":["Alliteration","Consonance","Enjambment"],"h":"Focus on repeated vowel, not consonant, sounds.","e":"Assonance is the repetition of vowel sounds in nearby words."},{"p":"Which device appears here? 'I have told you a million times to clean your room.'","a":"Hyperbole","w":["Understatement","Metaphor","Imagery"],"h":"The claim is a deliberate, obvious exaggeration.","e":"The exaggerated 'a million times' is hyperbole."},{"p":"Free verse is poetry that:","a":"Has no regular meter or rhyme scheme","w":["Always rhymes in couplets","Must be exactly 14 lines","Uses only iambic pentameter"],"h":"The word 'free' points to its lack of fixed rules.","e":"Free verse follows no set meter or rhyme scheme."},{"p":"Enjambment is best defined as:","a":"Continuing a sentence past the end of a line without a pause","w":["A full pause at the end of a line","The repetition of consonant sounds","A comparison using 'like' or 'as'"],"h":"It concerns how a line breaks in the middle of a thought.","e":"Enjambment carries a phrase over a line break without end punctuation."},{"p":"A four-line stanza rhyming lines one with two and three with four uses which rhyme scheme?","a":"AABB","w":["ABAB","ABBA","ABCB"],"h":"Adjacent lines share the same end sound in pairs.","e":"Paired adjacent rhymes give the scheme AABB."},{"p":"A metrical foot of one unstressed syllable followed by one stressed syllable is called:","a":"An iamb","w":["A trochee","An anapest","A dactyl"],"h":"It is the foot used in iambic pentameter.","e":"An iamb is an unstressed syllable followed by a stressed one."},{"p":"Which device appears in this line? 'The stars danced playfully in the night sky.'","a":"Personification","w":["Hyperbole","Simile","Alliteration"],"h":"Stars are given a human action.","e":"Giving stars the human ability to dance is personification."},{"p":"Vivid, descriptive language that appeals to the five senses is called:","a":"Imagery","w":["Symbolism","Meter","Allusion"],"h":"Think of language that helps you see, hear, or feel a scene.","e":"Imagery is sensory language that appeals to the reader's senses."},{"p":"A ballad is best described as:","a":"A narrative poem, often in quatrains, that tells a story","w":["A 17-syllable nature poem","A 14-line love poem","An unrhymed dramatic monologue"],"h":"It is a story-telling form often set to song.","e":"A ballad is a narrative poem, traditionally in quatrains, that tells a story."},{"p":"When a poet uses a dove to represent peace, this is an example of:","a":"Symbolism","w":["Personification","Hyperbole","Assonance"],"h":"One concrete object stands in for a larger idea.","e":"Using a concrete object to represent an abstract idea is symbolism."}],"e.12.synthesis":[{"p":"Synthesis differs from summary primarily because synthesis:","a":"Combines ideas from multiple sources to form a new understanding","w":["Restates one source in fewer words","Copies quotations without commentary","Lists sources in alphabetical order"],"h":"One draws on many sources; the other condenses just one.","e":"Synthesis integrates multiple sources to build a new, unified understanding."},{"p":"Three independent articles each report that a new policy reduced traffic deaths. Their agreement is an example of:","a":"Corroboration","w":["Contradiction","Refutation","Plagiarism"],"h":"Separate sources confirming the same claim reinforce it.","e":"When independent sources confirm the same claim, that is corroboration."},{"p":"Two credible sources reach opposite conclusions about a drug's safety. This relationship is best called:","a":"Contradiction","w":["Corroboration","Synthesis","Summary"],"h":"The sources disagree with each other.","e":"Sources reaching opposing conclusions are in contradiction."},{"p":"When evaluating a source's credibility, which factor matters MOST?","a":"The author's expertise and the evidence provided","w":["The length of the article","The number of images included","Whether it appears first in search results"],"h":"Focus on authority and support, not surface features.","e":"Credibility rests chiefly on the author's expertise and the evidence given."},{"p":"A 'common claim' across several sources is one that:","a":"Multiple sources independently assert","w":["Only a single source makes","Contradicts all the other sources","Appears only in a title"],"h":"It is the point where separate sources overlap.","e":"A common claim is an assertion that multiple sources share independently."},{"p":"A student weaves quotations from four historians into one original argument about a war's causes. This is best described as:","a":"Synthesis","w":["Summary","Paraphrase","Direct citation"],"h":"Multiple sources are combined into a new argument.","e":"Blending several sources into a new argument is synthesis."},{"p":"A peer-reviewed journal article is generally more credible than a personal blog because:","a":"It has undergone expert evaluation before publication","w":["It is longer","It is easier to read","It is available for free"],"h":"Consider what vetting process each undergoes.","e":"Peer review means experts vetted the work before publication, raising credibility."},{"p":"Corroborating evidence is valuable because it:","a":"Strengthens a claim by showing multiple sources agree","w":["Proves the claim is false","Removes the need for any sources","Summarizes a single text"],"h":"Think about what agreement among sources accomplishes.","e":"Corroboration strengthens a claim by demonstrating independent agreement."},{"p":"Source A is a 2024 empirical study; Source B is a 1985 opinion column. They disagree on current climate data. Which is likely more reliable, and why?","a":"Source A, because it is recent, evidence-based research","w":["Source B, because older sources are always better","Neither, because all sources are equal","Source B, because opinions are never biased"],"h":"Weigh recency and type of evidence for a data question.","e":"For current data, recent empirical research generally outweighs an old opinion piece."},{"p":"Effective integration of evidence into an essay requires a writer to:","a":"Introduce, quote, and explain how the evidence supports the point","w":["Paste the quotation with no context","Rely on only one source throughout","Avoid citing anyone by name"],"h":"Evidence needs framing before and interpretation after.","e":"Strong integration introduces, presents, and explains the evidence's relevance."},{"p":"When two equally credible sources contradict each other, a strong synthesis essay should:","a":"Acknowledge the tension and weigh the evidence","w":["Ignore one source entirely","Declare both sources worthless","Copy both without comment"],"h":"Disagreement should be addressed, not hidden.","e":"Good synthesis acknowledges conflicting sources and evaluates their evidence."},{"p":"A 'cherry-picked' source is one that:","a":"Is selected only because it supports a predetermined conclusion","w":["Is the most recent source available","Has been peer reviewed","Comes from a public library"],"h":"Think about biased selection to fit an argument.","e":"Cherry-picking chooses only sources that confirm a desired conclusion."},{"p":"A blog cites no data, while a government report cites tracked statistics. The report is more credible mainly because of its:","a":"Verifiable evidence","w":["Attractive layout","Casual tone","Shorter length"],"h":"Compare what each source uses to back its claims.","e":"The report's verifiable, tracked statistics make it more credible."},{"p":"The primary goal of synthesizing sources is to:","a":"Build a coherent, evidence-based argument from multiple perspectives","w":["Prove you have read many books","Fill a required page count","Repeat each source one after another"],"h":"The aim is a unified argument, not a source list.","e":"Synthesis aims to build one coherent, evidence-based argument from many perspectives."},{"p":"Which sentence demonstrates synthesis rather than summary?","a":"While Lee stresses economics and Ortiz highlights culture, together they suggest the causes were intertwined.","w":["Lee argues that the cause was economic.","Ortiz wrote an article about culture.","There were two articles about the topic."],"h":"Look for the option that connects sources into a new insight.","e":"Only the option that links two sources into a combined insight is true synthesis."},{"p":"Recognizing that a source may be biased should lead a researcher to:","a":"Corroborate its claims with independent sources","w":["Accept its claims without question","Discard all evidence on the topic","Cite only that single source"],"h":"Bias calls for checking claims elsewhere, not blind trust or total rejection.","e":"Potential bias means a researcher should verify claims against independent sources."}],"e.12.rhetanalysis":[{"p":"A rhetorical appeal to the audience's emotions is called:","a":"Pathos","w":["Ethos","Logos","Kairos"],"h":"Its root relates to feeling and suffering.","e":"Pathos is the appeal to the audience's emotions."},{"p":"A rhetorical appeal based on the speaker's credibility and character is called:","a":"Ethos","w":["Pathos","Logos","Anaphora"],"h":"Its root relates to character and ethics.","e":"Ethos is the appeal grounded in the speaker's credibility and character."},{"p":"A rhetorical appeal to logic, reasoning, and evidence is called:","a":"Logos","w":["Ethos","Pathos","Allusion"],"h":"Its root relates to word, reason, and logic.","e":"Logos is the appeal to logic, reason, and evidence."},{"p":"Which device appears here? 'We shall fight on the beaches, we shall fight on the landing grounds, we shall fight in the fields.'","a":"Anaphora","w":["Antithesis","Allusion","Hyperbole"],"h":"Notice the repeated opening phrase of each clause.","e":"Repeating 'we shall fight' at the start of clauses is anaphora."},{"p":"Which device appears here? 'It was the best of times, it was the worst of times.'","a":"Antithesis","w":["Anaphora","Alliteration","Simile"],"h":"Look for opposing ideas in balanced structure.","e":"Pairing contrasting ideas in balanced form is antithesis."},{"p":"Which device appears here? 'Are we simply going to stand by and do nothing?'","a":"Rhetorical question","w":["Allusion","Concession","Parallelism"],"h":"The speaker asks something without expecting a reply.","e":"A question posed for effect, not an answer, is a rhetorical question."},{"p":"Which appeal is used here? 'As a physician of thirty years, I assure you this treatment is safe.'","a":"Ethos","w":["Pathos","Logos","Kairos"],"h":"The speaker leans on personal authority and experience.","e":"Citing one's professional credibility is an appeal to ethos."},{"p":"Which appeal is used here? 'Studies show that 90 percent of patients recovered fully within one week.'","a":"Logos","w":["Ethos","Pathos","Anaphora"],"h":"The line relies on data and statistics.","e":"Using statistics and evidence is an appeal to logos."},{"p":"Which appeal is used here? 'Think of the children who go to bed hungry tonight, frightened and alone.'","a":"Pathos","w":["Logos","Ethos","Antithesis"],"h":"The line is designed to stir the audience's feelings.","e":"Evoking sympathy and emotion is an appeal to pathos."},{"p":"Anaphora is the repetition of a word or phrase at the:","a":"Beginning of successive clauses","w":["End of successive clauses","Middle of a single sentence","End of an entire poem"],"h":"Think about where the repetition consistently occurs.","e":"Anaphora repeats a word or phrase at the start of successive clauses."},{"p":"Antithesis is a rhetorical device that:","a":"Places contrasting ideas in balanced, parallel structure","w":["Repeats the first word of each line","References a famous work or event","Asks a question not meant to be answered"],"h":"The key is contrast expressed through balance.","e":"Antithesis sets contrasting ideas against each other in parallel structure."},{"p":"When a writer briefly admits a valid point of the opposing side, this technique is called:","a":"Concession","w":["Anaphora","Allusion","Juxtaposition"],"h":"The writer grants ground before countering it.","e":"Acknowledging an opposing point is a concession."},{"p":"Which device appears here? 'Like David facing Goliath, our small team took on the industry giant.'","a":"Allusion","w":["Antithesis","Anaphora","Concession"],"h":"The line references a well-known story.","e":"Referencing the biblical David and Goliath is an allusion."},{"p":"Parallelism as a rhetorical device refers to:","a":"Using similar grammatical structures for related ideas","w":["Comparing two unlike things directly","Overstating a claim for effect","Addressing the reader directly"],"h":"Think about matching grammatical patterns.","e":"Parallelism expresses related ideas using matching grammatical structures."},{"p":"Placing two contrasting things side by side to highlight their differences is called:","a":"Juxtaposition","w":["Parallelism","Anaphora","Ethos"],"h":"The emphasis is on positioning contrasts next to each other.","e":"Setting contrasting elements side by side is juxtaposition."},{"p":"Identifying an author's purpose in rhetorical analysis means determining whether the author aims to:","a":"Persuade, inform, or entertain","w":["Use as many sources as possible","Reach a required text length","Choose an attractive font"],"h":"Purpose is about the author's overall intent.","e":"An author's purpose is the intent to persuade, inform, or entertain the audience."}],"sp.1.juguetes":[{"p":"How do you say 'ball' (a toy you kick) in Spanish?","a":"la pelota","w":["la muñeca","el globo","el tren"],"h":"You bounce it and kick it.","e":"'La pelota' means ball."},{"p":"How do you say 'doll' in Spanish?","a":"la muñeca","w":["la pelota","el osito","la canica"],"h":"A toy shaped like a person.","e":"'La muñeca' means doll."},{"p":"How do you say 'teddy bear' in Spanish?","a":"el osito","w":["el gato","el perro","el tren"],"h":"A soft, cuddly bear.","e":"'El osito' means teddy bear."},{"p":"How do you say 'toy car' in Spanish?","a":"el carro","w":["la cometa","el tambor","la muñeca"],"h":"It has four wheels and you push it.","e":"'El carro' means car."},{"p":"How do you say 'train' in Spanish?","a":"el tren","w":["el globo","la pelota","el osito"],"h":"It runs on tracks.","e":"'El tren' means train."},{"p":"How do you say 'kite' in Spanish?","a":"la cometa","w":["el trompo","la canica","el robot"],"h":"You fly it in the wind.","e":"'La cometa' means kite."},{"p":"How do you say 'balloon' in Spanish?","a":"el globo","w":["la cuerda","el tambor","el tren"],"h":"You fill it with air and it floats.","e":"'El globo' means balloon."},{"p":"How do you say 'drum' in Spanish?","a":"el tambor","w":["la muñeca","el carro","la pelota"],"h":"You hit it to make a sound.","e":"'El tambor' means drum."},{"p":"How do you say 'blocks' in Spanish?","a":"los bloques","w":["las canicas","los globos","los trenes"],"h":"You stack them to build towers.","e":"'Los bloques' means blocks."},{"p":"How do you say 'jump rope' in Spanish?","a":"la cuerda","w":["la cometa","la pelota","la muñeca"],"h":"You jump over it.","e":"'La cuerda' means jump rope."},{"p":"How do you say 'spinning top' in Spanish?","a":"el trompo","w":["el robot","el osito","el globo"],"h":"It spins on a point.","e":"'El trompo' means spinning top."},{"p":"How do you say 'marble' in Spanish?","a":"la canica","w":["el tambor","el tren","la cometa"],"h":"A tiny glass ball.","e":"'La canica' means marble."},{"p":"How do you say 'robot' in Spanish?","a":"el robot","w":["la muñeca","el osito","la pelota"],"h":"A toy machine shaped like a person.","e":"'El robot' means robot."},{"p":"How do you say 'bicycle' in Spanish?","a":"la bicicleta","w":["el carro","el tren","el globo"],"h":"Two wheels and pedals.","e":"'La bicicleta' means bicycle."},{"p":"How do you say 'puzzle' in Spanish?","a":"el rompecabezas","w":["el tambor","la canica","la cometa"],"h":"You put the pieces together.","e":"'El rompecabezas' means puzzle."},{"p":"How do you say 'I want to play' in Spanish?","a":"Quiero jugar","w":["Quiero comer","Quiero dormir","Tengo hambre"],"h":"'Jugar' means to play.","e":"'Quiero jugar' means I want to play."}],"sp.2.casa":[{"p":"How do you say 'kitchen' in Spanish?","a":"la cocina","w":["el baño","la sala","el jardín"],"h":"The room where you cook.","e":"'La cocina' means kitchen."},{"p":"How do you say 'bedroom' in Spanish?","a":"el dormitorio","w":["el comedor","el garaje","la cocina"],"h":"The room where you sleep.","e":"'El dormitorio' means bedroom."},{"p":"How do you say 'bathroom' in Spanish?","a":"el baño","w":["la sala","la cocina","el jardín"],"h":"The room with a shower.","e":"'El baño' means bathroom."},{"p":"How do you say 'living room' in Spanish?","a":"la sala","w":["el baño","el comedor","la cocina"],"h":"The room with the sofa and TV.","e":"'La sala' means living room."},{"p":"How do you say 'dining room' in Spanish?","a":"el comedor","w":["el dormitorio","el garaje","el baño"],"h":"The room where you eat meals.","e":"'El comedor' means dining room."},{"p":"How do you say 'garden' or 'yard' in Spanish?","a":"el jardín","w":["la sala","la cocina","el comedor"],"h":"The outdoor area with plants.","e":"'El jardín' means garden."},{"p":"How do you say 'garage' in Spanish?","a":"el garaje","w":["el baño","la sala","el jardín"],"h":"Where the car is parked.","e":"'El garaje' means garage."},{"p":"How do you say 'bed' in Spanish?","a":"la cama","w":["la mesa","la silla","la puerta"],"h":"You sleep on it.","e":"'La cama' means bed."},{"p":"How do you say 'table' in Spanish?","a":"la mesa","w":["la cama","el sofá","la ventana"],"h":"You eat and write on it.","e":"'La mesa' means table."},{"p":"How do you say 'chair' in Spanish?","a":"la silla","w":["la cama","la puerta","la lámpara"],"h":"You sit on it.","e":"'La silla' means chair."},{"p":"How do you say 'sofa' in Spanish?","a":"el sofá","w":["la mesa","la cama","la ventana"],"h":"A long, soft seat.","e":"'El sofá' means sofa."},{"p":"How do you say 'door' in Spanish?","a":"la puerta","w":["la ventana","la silla","la mesa"],"h":"You open it to enter a room.","e":"'La puerta' means door."},{"p":"How do you say 'window' in Spanish?","a":"la ventana","w":["la puerta","la lámpara","el sofá"],"h":"You look outside through it.","e":"'La ventana' means window."},{"p":"How do you say 'lamp' in Spanish?","a":"la lámpara","w":["la mesa","la cama","la puerta"],"h":"It gives light.","e":"'La lámpara' means lamp."},{"p":"How do you say 'refrigerator' in Spanish?","a":"el refrigerador","w":["la lámpara","la silla","la ventana"],"h":"It keeps food cold.","e":"'El refrigerador' means refrigerator."},{"p":"How do you say 'My house is big' in Spanish?","a":"Mi casa es grande","w":["Mi casa es pequeña","Mi perro es grande","Tengo una casa"],"h":"'grande' means big.","e":"'Mi casa es grande' means my house is big."}],"sp.3.hora":[{"p":"How do you ask 'What time is it?' in Spanish?","a":"¿Qué hora es?","w":["¿Cómo estás?","¿Cuántos años tienes?","¿Dónde está?"],"h":"You ask this to learn the time.","e":"'¿Qué hora es?' asks the time."},{"p":"How do you say 'It's one o'clock' in Spanish?","a":"Es la una","w":["Son las una","Es las uno","Son la una"],"h":"One o'clock uses singular 'es la'.","e":"One o'clock is 'Es la una'."},{"p":"How do you say 'It's two o'clock' in Spanish?","a":"Son las dos","w":["Es la dos","Son la dos","Es las dos"],"h":"Two or more hours use 'son las'.","e":"'Son las dos' is 2:00."},{"p":"How do you say 'It's four o'clock' in Spanish?","a":"Son las cuatro","w":["Es la cuatro","Son la cuatro","Es las cuatro"],"h":"Use 'son las' for hours after one.","e":"'Son las cuatro' is 4:00."},{"p":"How do you say 'It's 3:15' in Spanish?","a":"Son las tres y cuarto","w":["Son las tres y media","Son las cuatro y cuarto","Son las tres menos cuarto"],"h":"'cuarto' means a quarter (15 min).","e":"'y cuarto' adds fifteen minutes."},{"p":"How do you say 'It's 3:30' in Spanish?","a":"Son las tres y media","w":["Son las tres y cuarto","Son las tres y treinta y cinco","Son las cuatro y media"],"h":"'media' means half.","e":"'y media' means half past."},{"p":"How do you say 'It's 3:45' in Spanish?","a":"Son las cuatro menos cuarto","w":["Son las tres y cuarto","Son las cuatro y cuarto","Son las tres menos media"],"h":"Fifteen minutes before four.","e":"'menos cuarto' means quarter to."},{"p":"How do you say 'It's 5:10' in Spanish?","a":"Son las cinco y diez","w":["Son las cinco menos diez","Son las diez y cinco","Son las seis y diez"],"h":"Add the minutes with 'y'.","e":"'y diez' adds ten minutes."},{"p":"How do you say 'noon' in Spanish?","a":"el mediodía","w":["la medianoche","la mañana","la tarde"],"h":"12:00 in the daytime.","e":"'El mediodía' means noon."},{"p":"How do you say 'midnight' in Spanish?","a":"la medianoche","w":["el mediodía","la noche","la tarde"],"h":"12:00 at night.","e":"'La medianoche' means midnight."},{"p":"How do you say 'in the morning' (A.M.) in Spanish?","a":"de la mañana","w":["de la tarde","de la noche","del mediodía"],"h":"Used for morning hours.","e":"'de la mañana' means in the morning."},{"p":"How do you say 'in the afternoon' in Spanish?","a":"de la tarde","w":["de la mañana","de la noche","de la medianoche"],"h":"Used for early P.M. hours.","e":"'de la tarde' means in the afternoon."},{"p":"How do you say 'at night' in Spanish?","a":"de la noche","w":["de la mañana","de la tarde","del mediodía"],"h":"Used for late P.M. hours.","e":"'de la noche' means at night."},{"p":"How do you ask 'At what time?' in Spanish?","a":"¿A qué hora?","w":["¿Qué hora es?","¿Cuánto tiempo?","¿Cuándo hora?"],"h":"You ask this about when something happens.","e":"'¿A qué hora?' asks at what time."},{"p":"How do you say 'It's 1:30' in Spanish?","a":"Es la una y media","w":["Son la una y media","Es las una y media","Es la una y cuarto"],"h":"1:30 still uses singular 'es la'.","e":"'Es la una y media' is 1:30."},{"p":"How do you say 'It's 6:50' in Spanish?","a":"Son las siete menos diez","w":["Son las seis y diez","Son las siete y diez","Son las seis menos diez"],"h":"Ten minutes before seven.","e":"'siete menos diez' means 6:50."}],"sp.4.escuela":[{"p":"How do you say 'book' in Spanish?","a":"el libro","w":["el cuaderno","el lápiz","la mochila"],"h":"You read it.","e":"'El libro' means book."},{"p":"How do you say 'pencil' in Spanish?","a":"el lápiz","w":["el bolígrafo","la regla","la goma"],"h":"You write with it and can erase.","e":"'El lápiz' means pencil."},{"p":"How do you say 'pen' in Spanish?","a":"el bolígrafo","w":["el lápiz","el marcador","la tiza"],"h":"You write with ink.","e":"'El bolígrafo' means pen."},{"p":"How do you say 'notebook' in Spanish?","a":"el cuaderno","w":["el libro","el papel","la mochila"],"h":"You write notes in it.","e":"'El cuaderno' means notebook."},{"p":"How do you say 'backpack' in Spanish?","a":"la mochila","w":["la regla","la goma","el pupitre"],"h":"You carry books on your back.","e":"'La mochila' means backpack."},{"p":"How do you say 'eraser' in Spanish?","a":"la goma","w":["la regla","el lápiz","las tijeras"],"h":"It removes pencil marks.","e":"'La goma' means eraser."},{"p":"How do you say 'ruler' in Spanish?","a":"la regla","w":["la goma","las tijeras","el papel"],"h":"You measure straight lines with it.","e":"'La regla' means ruler."},{"p":"How do you say 'scissors' in Spanish?","a":"las tijeras","w":["el pegamento","la regla","la goma"],"h":"You cut paper with them.","e":"'Las tijeras' means scissors."},{"p":"How do you say 'desk' (a student's) in Spanish?","a":"el pupitre","w":["la pizarra","la mochila","la silla"],"h":"A student's table at school.","e":"'El pupitre' means school desk."},{"p":"How do you say 'chalkboard' in Spanish?","a":"la pizarra","w":["el pupitre","el cuaderno","el papel"],"h":"The teacher writes on it at the front.","e":"'La pizarra' means chalkboard."},{"p":"How do you say 'teacher' (female) in Spanish?","a":"la maestra","w":["la estudiante","la mochila","la regla"],"h":"The person who teaches the class.","e":"'La maestra' means teacher."},{"p":"How do you say 'paper' in Spanish?","a":"el papel","w":["el libro","el lápiz","la goma"],"h":"You write on this thin sheet.","e":"'El papel' means paper."},{"p":"How do you say 'glue' in Spanish?","a":"el pegamento","w":["las tijeras","la regla","el marcador"],"h":"It sticks things together.","e":"'El pegamento' means glue."},{"p":"How do you say 'marker' in Spanish?","a":"el marcador","w":["el lápiz","la goma","la regla"],"h":"A thick colored pen.","e":"'El marcador' means marker."},{"p":"How do you say 'calculator' in Spanish?","a":"la calculadora","w":["el cuaderno","la regla","la mochila"],"h":"It helps you do math.","e":"'La calculadora' means calculator."},{"p":"How do you say 'I need a pencil' in Spanish?","a":"Necesito un lápiz","w":["Tengo un libro","Quiero un cuaderno","Necesito una regla"],"h":"'Necesito' means I need.","e":"'Necesito un lápiz' means I need a pencil."}],"sp.6.stemchange":[{"p":"Complete: Yo ___ un helado. (querer)","a":"quiero","w":["quero","quiere","queremos"],"h":"e changes to ie for 'yo'.","e":"'Querer' becomes 'quiero' for yo."},{"p":"Complete: Tú ___ correr rápido. (poder)","a":"puedes","w":["podes","puede","poder"],"h":"o changes to ue.","e":"'Poder' becomes 'puedes' for tú."},{"p":"Complete: Ella ___ ocho horas. (dormir)","a":"duerme","w":["dorme","duermes","dormo"],"h":"o changes to ue.","e":"'Dormir' becomes 'duerme' for ella."},{"p":"Complete: Nosotros ___ pizza. (pedir)","a":"pedimos","w":["pidimos","pedemos","pido"],"h":"The nosotros form keeps the original stem.","e":"Nosotros does not change: 'pedimos'."},{"p":"Complete: Yo ___ en mi familia. (pensar)","a":"pienso","w":["penso","piensa","pensamos"],"h":"e changes to ie.","e":"'Pensar' becomes 'pienso' for yo."},{"p":"Complete: La clase ___ a las ocho. (empezar)","a":"empieza","w":["empeza","empiezo","empezamos"],"h":"e changes to ie.","e":"'Empezar' becomes 'empieza'."},{"p":"Complete: Ellos ___ a casa. (volver)","a":"vuelven","w":["volven","vuelve","vuelvo"],"h":"o changes to ue.","e":"'Volver' becomes 'vuelven' for ellos."},{"p":"Complete: Los niños ___ al fútbol. (jugar)","a":"juegan","w":["jugan","juega","juego"],"h":"u changes to ue.","e":"'Jugar' becomes 'juegan' for ellos."},{"p":"Complete: Yo no ___ la lección. (entender)","a":"entiendo","w":["entendo","entiende","entiendes"],"h":"e changes to ie.","e":"'Entender' becomes 'entiendo' for yo."},{"p":"Complete: Nosotros ___ el café. (preferir)","a":"preferimos","w":["prefierimos","preferemos","prefiero"],"h":"Nosotros keeps the original stem.","e":"Nosotros form is 'preferimos'."},{"p":"Complete: El mesero ___ la comida. (servir)","a":"sirve","w":["serve","sirvo","serves"],"h":"e changes to i.","e":"'Servir' becomes 'sirve'."},{"p":"Complete: Tú ___ hasta diez. (contar)","a":"cuentas","w":["contas","cuenta","cuento"],"h":"o changes to ue.","e":"'Contar' becomes 'cuentas' for tú."},{"p":"Complete: Yo siempre ___ mis llaves. (perder)","a":"pierdo","w":["perdo","pierde","pierdes"],"h":"e changes to ie.","e":"'Perder' becomes 'pierdo' for yo."},{"p":"Complete: Ella ___ el libro. (encontrar)","a":"encuentra","w":["encontra","encuentro","encuentras"],"h":"o changes to ue.","e":"'Encontrar' becomes 'encuentra'."},{"p":"Complete: Yo ___ la palabra. (repetir)","a":"repito","w":["repeto","repite","repites"],"h":"e changes to i.","e":"'Repetir' becomes 'repito' for yo."},{"p":"Complete: La tienda ___ a las nueve. (cerrar)","a":"cierra","w":["cerra","cierro","cierras"],"h":"e changes to ie.","e":"'Cerrar' becomes 'cierra'."}],"sp.7.progressive":[{"p":"To form the present progressive, you use a form of 'estar' plus what?","a":"the gerund (-ando/-iendo)","w":["the infinitive","the past participle","the subjunctive"],"h":"estar plus a special -ndo form.","e":"Present progressive is estar plus the gerund."},{"p":"What is the gerund of 'hablar'?","a":"hablando","w":["hablado","hablendo","hablan"],"h":"-ar verbs take -ando.","e":"'Hablar' becomes 'hablando'."},{"p":"What is the gerund of 'comer'?","a":"comiendo","w":["comando","comido","comendo"],"h":"-er verbs take -iendo.","e":"'Comer' becomes 'comiendo'."},{"p":"What is the gerund of 'vivir'?","a":"viviendo","w":["vivando","vivido","viviando"],"h":"-ir verbs take -iendo.","e":"'Vivir' becomes 'viviendo'."},{"p":"How do you say 'I am studying' in Spanish?","a":"Estoy estudiando","w":["Estoy estudiar","Soy estudiando","Estoy estudiado"],"h":"Use estoy plus the gerund.","e":"'Estoy estudiando' means I am studying."},{"p":"How do you say 'She is eating' in Spanish?","a":"Ella está comiendo","w":["Ella es comiendo","Ella está comer","Ella está comido"],"h":"está plus the gerund.","e":"'Está comiendo' means is eating."},{"p":"What is the gerund of 'leer'?","a":"leyendo","w":["leiendo","leendo","leído"],"h":"-er after a vowel becomes -yendo.","e":"'Leer' becomes 'leyendo'."},{"p":"What is the gerund of 'dormir'?","a":"durmiendo","w":["dormiendo","dormando","dormido"],"h":"o changes to u in the stem.","e":"'Dormir' becomes 'durmiendo'."},{"p":"How do you say 'We are working' in Spanish?","a":"Estamos trabajando","w":["Estamos trabajar","Somos trabajando","Estamos trabajado"],"h":"estamos plus the gerund.","e":"'Estamos trabajando' means we are working."},{"p":"What is the gerund of 'pedir'?","a":"pidiendo","w":["pediendo","pidando","pedido"],"h":"e changes to i in the stem.","e":"'Pedir' becomes 'pidiendo'."},{"p":"How do you say 'They are running' in Spanish?","a":"Ellos están corriendo","w":["Ellos son corriendo","Ellos están correr","Ellos están corrido"],"h":"están plus the gerund.","e":"'Están corriendo' means they are running."},{"p":"What is the gerund of 'decir'?","a":"diciendo","w":["deciendo","dicando","dicho"],"h":"e changes to i in the stem.","e":"'Decir' becomes 'diciendo'."},{"p":"How do you ask 'What are you doing?' in Spanish?","a":"¿Qué estás haciendo?","w":["¿Qué estás hacer?","¿Qué eres haciendo?","¿Qué estás hecho?"],"h":"estás plus the gerund of hacer.","e":"'¿Qué estás haciendo?' means what are you doing?"},{"p":"What is the gerund of 'escribir'?","a":"escribiendo","w":["escribando","escrito","escribendo"],"h":"-ir verbs take -iendo.","e":"'Escribir' becomes 'escribiendo'."},{"p":"Which verb is used with the gerund to form the present progressive?","a":"estar","w":["ser","tener","ir"],"h":"It is not 'ser'.","e":"The present progressive uses 'estar', not 'ser'."},{"p":"How do you say 'I am not sleeping' in Spanish?","a":"No estoy durmiendo","w":["No soy durmiendo","No estoy dormir","No estoy dormido"],"h":"no plus estoy plus the gerund.","e":"'No estoy durmiendo' means I am not sleeping."}],"sp.8.negatives":[{"p":"How do you say 'something' in Spanish?","a":"algo","w":["nada","alguien","nunca"],"h":"The opposite of 'nada'.","e":"'Algo' means something."},{"p":"How do you say 'nothing' in Spanish?","a":"nada","w":["algo","nadie","nunca"],"h":"The opposite of 'algo'.","e":"'Nada' means nothing."},{"p":"How do you say 'someone' in Spanish?","a":"alguien","w":["nadie","algo","alguno"],"h":"It refers to a person.","e":"'Alguien' means someone."},{"p":"How do you say 'no one' in Spanish?","a":"nadie","w":["alguien","nada","ninguno"],"h":"The opposite of 'alguien'.","e":"'Nadie' means no one."},{"p":"How do you say 'always' in Spanish?","a":"siempre","w":["nunca","también","a veces"],"h":"The opposite of 'nunca'.","e":"'Siempre' means always."},{"p":"How do you say 'never' in Spanish?","a":"nunca","w":["siempre","tampoco","a veces"],"h":"The opposite of 'siempre'.","e":"'Nunca' means never."},{"p":"How do you say 'also / too' in Spanish?","a":"también","w":["tampoco","siempre","además"],"h":"Used to agree with a positive statement.","e":"'También' means also."},{"p":"How do you say 'neither / me neither' in Spanish?","a":"tampoco","w":["también","nunca","nada"],"h":"The negative counterpart of 'también'.","e":"'Tampoco' means neither."},{"p":"How do you say 'I don't want anything' in Spanish?","a":"No quiero nada","w":["No quiero algo","Quiero nada","No quiero nadie"],"h":"Spanish uses a double negative: no plus nada.","e":"'No quiero nada' means I don't want anything."},{"p":"How do you say 'No one is here' in Spanish?","a":"Nadie está aquí","w":["Alguien está aquí","No nadie está aquí","Nada está aquí"],"h":"When 'nadie' comes first, no extra 'no' is needed.","e":"'Nadie está aquí' means no one is here."},{"p":"How do you say 'I never eat meat' in Spanish?","a":"Nunca como carne","w":["Siempre como carne","No como siempre carne","Como nunca carne"],"h":"'nunca' can go before the verb.","e":"'Nunca como carne' means I never eat meat."},{"p":"How do you say 'Me neither' in Spanish?","a":"Yo tampoco","w":["Yo también","Yo nunca","Yo nada"],"h":"You are agreeing with a negative statement.","e":"'Yo tampoco' means me neither."},{"p":"How do you say 'I don't have any book' in Spanish?","a":"No tengo ningún libro","w":["No tengo alguno libro","No tengo ningunos libros","Tengo ningún libro"],"h":"'ningún' goes before a masculine singular noun.","e":"'No tengo ningún libro' means I have no book."},{"p":"Which Spanish pair means 'neither... nor...'?","a":"ni... ni...","w":["o... o...","y... y...","ni... o..."],"h":"The negative pair of options.","e":"'Ni... ni...' means neither... nor."},{"p":"Which Spanish pair means 'either... or...'?","a":"o... o...","w":["ni... ni...","y... y...","o... ni..."],"h":"The positive pair of choices.","e":"'O... o...' means either... or."},{"p":"In the sentence 'No veo a nadie', how many negative words are correctly used together?","a":"two (no and nadie)","w":["one","three","none"],"h":"Spanish allows a double negative.","e":"'No' and 'nadie' together is correct in Spanish."}],"sp.9.relatives":[{"p":"Which relative pronoun is the general word for 'that / which / who'?","a":"que","w":["quien","cuyo","donde"],"h":"It is the most common relative pronoun.","e":"'Que' is the default relative pronoun."},{"p":"Complete: El hombre ___ habla es mi tío. (who)","a":"que","w":["quien","lo que","cuyo"],"h":"Right after a noun, use the default relative.","e":"'El hombre que habla' uses 'que'."},{"p":"After a preposition referring to a person, which relative pronoun is used?","a":"quien","w":["que","lo que","cuyo"],"h":"Think 'con ___' or 'de ___' for people.","e":"'La chica con quien hablo' uses 'quien'."},{"p":"Which relative pronoun means 'whose' (possession)?","a":"cuyo","w":["que","quien","donde"],"h":"It agrees with the thing possessed.","e":"'Cuyo' means whose."},{"p":"Complete: El libro ___ leo es bueno. (that)","a":"que","w":["quien","cuyo","lo que"],"h":"Books are things, so use the default relative.","e":"'que' refers back to the book."},{"p":"Complete: El lugar ___ vivo es tranquilo. (where)","a":"donde","w":["que","quien","cuyo"],"h":"It refers to a location.","e":"'donde' means where."},{"p":"Which phrase means 'what / that which' when there is no specific noun?","a":"lo que","w":["que","quien","cuyo"],"h":"It refers to a whole idea, not a noun.","e":"'Lo que' means what / that which."},{"p":"Complete: Lo ___ dices es verdad. (what)","a":"que","w":["quien","cual","cuyo"],"h":"'lo ___' forms 'that which'.","e":"'Lo que dices' means what you say."},{"p":"Complete: La mujer ___ vive aquí es doctora. (who)","a":"que","w":["cuyo","lo que","donde"],"h":"Use the default relative right after the noun.","e":"'La mujer que vive aquí' uses 'que'."},{"p":"Complete: El autor, ___ libro leí, es famoso. (whose)","a":"cuyo","w":["que","quien","donde"],"h":"It shows the author owns the book.","e":"'cuyo libro' means whose book."},{"p":"Complete: Ese es el hombre de ___ hablé. (whom)","a":"quien","w":["que","cuyo","lo que"],"h":"After 'de', people take this pronoun.","e":"'de quien hablé' means about whom I spoke."},{"p":"Complete: No entiendo ___ quieres. (what)","a":"lo que","w":["que","quien","cuyo"],"h":"It refers to an unnamed idea.","e":"'lo que quieres' means what you want."},{"p":"The pronoun 'cuyo' must agree in gender and number with what?","a":"the noun it precedes (the thing owned)","w":["the owner","the verb","nothing"],"h":"It behaves like an adjective.","e":"'cuya casa' agrees with the feminine 'casa'."},{"p":"Complete: La ciudad ___ nací es pequeña. (where)","a":"donde","w":["que","cuyo","quien"],"h":"It refers to the city as a place.","e":"'donde nací' means where I was born."},{"p":"Complete: Las personas ___ conozco son amables. (whom / that)","a":"que","w":["cuyo","donde","lo que"],"h":"The default relative works even for known people.","e":"'que conozco' means whom I know."},{"p":"Complete: Todo ___ brilla no es oro. (that which)","a":"lo que","w":["que","quien","cuyo"],"h":"It refers to a general idea, 'all that'.","e":"'todo lo que brilla' means all that glitters."}],"sp.10.narracion":[{"p":"Which past tense describes a completed, one-time action?","a":"the preterite","w":["the imperfect","the present","the future"],"h":"Think 'done and finished'.","e":"The preterite tells completed past actions."},{"p":"Which past tense describes ongoing or habitual past actions?","a":"the imperfect","w":["the preterite","the conditional","the present"],"h":"Think 'used to' or 'was doing'.","e":"The imperfect gives background and habits."},{"p":"Complete: Ayer ___ al cine con Ana. (ir, completed action)","a":"fui","w":["iba","voy","iré"],"h":"'ayer' signals a finished action.","e":"'Ayer fui' uses the preterite."},{"p":"Complete: Todos los días ___ a la escuela. (caminar, habitual)","a":"caminaba","w":["caminé","camino","caminaré"],"h":"'todos los días' signals a habit.","e":"Habitual actions use the imperfect 'caminaba'."},{"p":"Complete: Mientras yo leía, mi hermano ___. (dormir, ongoing)","a":"dormía","w":["durmió","duerme","dormirá"],"h":"Two ongoing actions use the imperfect.","e":"'mientras' often signals the imperfect."},{"p":"Complete: De repente, ___ un ruido fuerte. (oír, sudden)","a":"oí","w":["oía","oigo","oiré"],"h":"'de repente' signals a sudden completed action.","e":"A sudden action uses the preterite 'oí'."},{"p":"Describing weather in the past, like 'it was raining', usually uses which tense?","a":"the imperfect","w":["the preterite","the present","the future"],"h":"It is background description.","e":"'Llovía' sets the scene in the imperfect."},{"p":"In 'The phone rang while we were eating', which verb is in the preterite?","a":"rang (sonó)","w":["were eating","both verbs","neither verb"],"h":"The interrupting action is the preterite.","e":"'Sonó' interrupts the ongoing 'comíamos'."},{"p":"Telling time in the past, like 'it was three o'clock', uses which tense?","a":"the imperfect","w":["the preterite","the conditional","the present"],"h":"It describes a state.","e":"'Eran las tres' uses the imperfect."},{"p":"Complete: Cuando era niño, ___ mucho en el parque. (jugar, used to)","a":"jugaba","w":["jugué","juego","jugaré"],"h":"'used to' signals the imperfect.","e":"'jugaba' means I used to play."},{"p":"Complete: Anoche ellos ___ una película. (ver, completed)","a":"vieron","w":["veían","ven","verán"],"h":"'anoche' means last night, a finished time.","e":"'vieron' is the preterite."},{"p":"Which word signals the imperfect: 'siempre' or 'anoche'?","a":"siempre","w":["anoche","ayer","de repente"],"h":"'always' implies repetition.","e":"'siempre' cues the habitual imperfect."},{"p":"Complete: Yo ___ la tarea cuando me llamaste. (hacer, in progress)","a":"hacía","w":["hice","hago","haré"],"h":"An action in progress when interrupted uses the imperfect.","e":"'hacía' means I was doing."},{"p":"Stating age in the past, like 'she was ten years old', uses which tense?","a":"the imperfect","w":["the preterite","the future","the present"],"h":"It describes an ongoing state.","e":"'Tenía diez años' uses the imperfect."},{"p":"Complete: El año pasado nosotros ___ a España. (viajar, completed)","a":"viajamos","w":["viajábamos","viajaremos","viajemos"],"h":"'el año pasado' points to one finished trip.","e":"Here 'viajamos' is preterite (last year)."},{"p":"A story's background details (setting, feelings, weather) are usually told in the...","a":"imperfect","w":["preterite","present","future"],"h":"Scene-setting versus main events.","e":"Background uses the imperfect; events use the preterite."}],"sp.11.pasiva":[{"p":"The construction in 'Se habla español aquí' is called the...","a":"passive / impersonal se","w":["reflexive se","direct object","subjunctive"],"h":"No specific person is named as the doer.","e":"'Se habla' means Spanish is spoken (passive se)."},{"p":"How do you say 'Houses are sold here' in Spanish?","a":"Se venden casas aquí","w":["Se vende casas aquí","Casas venden aquí","Se vendan casas aquí"],"h":"The verb agrees with the plural 'casas'.","e":"A plural subject takes 'se venden'."},{"p":"How do you say 'One book is sold' in Spanish?","a":"Se vende un libro","w":["Se venden un libro","Se vendo un libro","Un libro se venden"],"h":"A singular subject takes a singular verb.","e":"'Se vende un libro' is singular."},{"p":"In 'La carta fue escrita por Ana', which word means 'by'?","a":"por","w":["para","de","con"],"h":"It introduces the doer of the action.","e":"'por' introduces who did the action."},{"p":"How do you say 'The house was built in 1990' in Spanish?","a":"La casa fue construida en 1990","w":["La casa es construida en 1990","La casa fue construido en 1990","La casa fue construyó en 1990"],"h":"Use fue plus a participle that agrees with 'casa'.","e":"'fue construida' is feminine to match 'casa'."},{"p":"In the 'ser plus past participle' passive, the participle agrees with the...","a":"subject","w":["verb ser","agent","object"],"h":"It behaves like an adjective.","e":"The participle matches the subject's gender and number."},{"p":"How do you say 'It is said that...' in Spanish?","a":"Se dice que...","w":["Es dicho que...","Se dicen que...","Dice que se..."],"h":"Impersonal se with a singular verb.","e":"'Se dice que' means it is said that."},{"p":"How do you say 'The books were written by the author' in Spanish?","a":"Los libros fueron escritos por el autor","w":["Los libros fueron escrito por el autor","Los libros son escritos de el autor","Los libros fue escritos por el autor"],"h":"Plural subject takes fueron plus 'escritos'.","e":"Agreement gives 'fueron escritos'."},{"p":"The passive 'se' is most common when the doer is...","a":"unknown or unimportant","w":["a specific named person","always plural","in the future"],"h":"The focus is the action, not who did it.","e":"Passive se hides the agent."},{"p":"What does 'Se prohíbe fumar' mean?","a":"Smoking is prohibited","w":["I prohibit smoking","We smoke","Smoking prohibits"],"h":"It is an impersonal rule or sign.","e":"'Se prohíbe' means it is prohibited."},{"p":"How do you say 'Cars are repaired here' in Spanish?","a":"Se reparan carros aquí","w":["Se repara carros aquí","Carros se repara","Se reparen carros aquí"],"h":"Plural 'carros' takes 'se reparan'.","e":"Plural agreement gives 'se reparan'."},{"p":"How do you ask 'How does one get to the station?' in Spanish?","a":"¿Cómo se llega a la estación?","w":["¿Cómo llegas a la estación por se?","¿Cómo se llegan a la estación?","¿Cómo es llegado a la estación?"],"h":"Impersonal se with a singular verb.","e":"'¿Cómo se llega?' means how does one get there?"},{"p":"How do you say 'The window was broken' in Spanish (ser passive)?","a":"La ventana fue rota","w":["La ventana fue roto","La ventana es rompida","La ventana fue rompió"],"h":"The participle of 'romper' is irregular.","e":"'rota' is the past participle of 'romper'."},{"p":"Which is more natural in everyday Spanish for 'Spanish is spoken here'?","a":"Se habla español","w":["Español es hablado","Español fue hablado","Es hablado español"],"h":"Passive se is preferred over the ser passive.","e":"Spanish favors 'se habla' over the ser passive."},{"p":"How do you say 'The doors were opened by the guard' in Spanish?","a":"Las puertas fueron abiertas por el guardia","w":["Las puertas fueron abierto por el guardia","Las puertas fue abiertas por el guardia","Las puertas son abrieron por el guardia"],"h":"Use fueron plus 'abiertas' (feminine plural).","e":"Full agreement gives 'fueron abiertas'."},{"p":"In 'Se me perdió el libro', the 'se' adds a sense of...","a":"an accidental / unintentional action","w":["a deliberate action","a future action","a command"],"h":"It means 'it got lost on me'.","e":"The no-fault se shows the action was accidental."}],"sp.12.debate":[{"p":"How do you say 'In my opinion' in Spanish?","a":"En mi opinión","w":["Por ejemplo","Sin embargo","Por lo tanto"],"h":"It introduces your own view.","e":"'En mi opinión' means in my opinion."},{"p":"How do you say 'I agree' in Spanish?","a":"Estoy de acuerdo","w":["No estoy de acuerdo","Estoy cansado","Tengo razón"],"h":"You are expressing agreement.","e":"'Estoy de acuerdo' means I agree."},{"p":"How do you say 'I disagree' in Spanish?","a":"No estoy de acuerdo","w":["Estoy de acuerdo","Estoy de vacaciones","No tengo idea"],"h":"It is the negative of agreeing.","e":"'No estoy de acuerdo' means I disagree."},{"p":"How do you say 'However' in Spanish?","a":"Sin embargo","w":["Por lo tanto","Además","Por ejemplo"],"h":"It signals a contrast.","e":"'Sin embargo' means however."},{"p":"How do you say 'Therefore' in Spanish?","a":"Por lo tanto","w":["Sin embargo","Por ejemplo","Por un lado"],"h":"It introduces a conclusion.","e":"'Por lo tanto' means therefore."},{"p":"How do you say 'Furthermore / Also' in Spanish?","a":"Además","w":["Sin embargo","Por lo tanto","En resumen"],"h":"It adds another point.","e":"'Además' means furthermore."},{"p":"How do you say 'For example' in Spanish?","a":"Por ejemplo","w":["Por lo tanto","Sin embargo","En mi opinión"],"h":"It introduces an example.","e":"'Por ejemplo' means for example."},{"p":"How do you say 'On the other hand' in Spanish?","a":"Por otro lado","w":["Por un lado","Por lo tanto","Sin duda"],"h":"It presents the opposing side.","e":"'Por otro lado' means on the other hand."},{"p":"How do you say 'On one hand' in Spanish?","a":"Por un lado","w":["Por otro lado","Sin embargo","Además"],"h":"It introduces the first side.","e":"'Por un lado' means on one hand."},{"p":"How do you say 'In summary' in Spanish?","a":"En resumen","w":["Por ejemplo","Sin embargo","Además"],"h":"It is used in a conclusion.","e":"'En resumen' means in summary."},{"p":"How do you say 'Without a doubt' in Spanish?","a":"Sin duda","w":["Tal vez","Quizás","Sin embargo"],"h":"It expresses certainty.","e":"'Sin duda' means without a doubt."},{"p":"How do you say 'From my point of view' in Spanish?","a":"Desde mi punto de vista","w":["En mi casa","Por lo tanto","Por ejemplo"],"h":"It is another way to give an opinion.","e":"'Desde mi punto de vista' means from my point of view."},{"p":"How do you say 'It is important that we act' in Spanish?","a":"Es importante que actuemos","w":["Es importante que actuamos","Es importante actuar nosotros","Es importante que actuar"],"h":"'es importante que' triggers the subjunctive.","e":"'actuemos' is subjunctive after 'es importante que'."},{"p":"How do you say 'Nevertheless' in Spanish (formal)?","a":"No obstante","w":["Por lo tanto","Además","Por ejemplo"],"h":"A formal way to say 'however'.","e":"'No obstante' means nevertheless."},{"p":"How do you say 'I think that...' in Spanish?","a":"Creo que...","w":["Creo de...","Pienso de que...","Me creo que..."],"h":"'creer que' is followed by the indicative.","e":"'Creo que' introduces an opinion."},{"p":"How do you say 'To conclude' in Spanish?","a":"Para concluir","w":["Para empezar","Por ejemplo","Sin embargo"],"h":"It signals the closing statement.","e":"'Para concluir' means to conclude."}]};
